 15→function routeForRole(role: Role) {
 16→  if (role === 'STUDENT') return '/student';
 17→  if (role === 'PROFESSOR') return '/instructor';
 18→  if (role === 'TA') return '/unsupported-role';
 19→  return '/admin';
 20→}
 21→
 22→function extractErrorMessage(error: unknown) {
 23→  if (!(error instanceof Error)) {
 24→    return 'Could not start EduAI sign-in';
 25→  }
 26→
 27→  try {
 28→    const parsed = JSON.parse(error.message);
 29→    if (typeof parsed?.message === 'string' && parsed.message.trim()) {
 30→      return parsed.message;
 31→    }
 32→    if (typeof parsed?.error === 'string' && parsed.error.trim()) {
 33→      return parsed.error;
 34→    }
 35→  } catch {
 36→    // Fall back to the raw message when the backend returns plain text.
 37→  }
 38→
 39→  return error.message || 'Could not start EduAI sign-in';
 40→}
