 42→export default function Home() {
 43→  const navigate = useNavigate();
 44→  const { user, isInitializing } = useLocalUser();
 45→  const [loading, setLoading] = useState(false);
 46→  const [error, setError] = useState('');
 47→
 48→  useEffect(() => {
 49→    if (!user) return;
 50→    navigate(routeForRole(user.role), { replace: true });
 51→  }, [navigate, user]);
 52→
 53→  useEffect(() => {
 54→    if (typeof window === 'undefined') return;
 55→    const params = new URLSearchParams(window.location.search);
 56→    if (params.get('authError') === 'eduai_sign_in_failed') {
 57→      setError('EduAI sign-in did not complete. Please try again.');
 58→    }
 59→  }, []);
 60→
 61→  const onSignIn = async () => {
 62→    setLoading(true);
 63→    setError('');
 64→
 65→    try {
 66→      await signInWithEduAi();
 67→    } catch (err) {
 68→      setError(extractErrorMessage(err));
 69→      setLoading(false);
 70→      return;
 71→    } finally {
 72→      // Full-page redirect keeps this from usually running, but it protects the button on failure.
 73→      setLoading(false);
 74→    }
 75→  };
 76→
 77→  if (isInitializing || user) {
 78→    return (
 79→      <main className="relative min-h-dvh overflow-hidden bg-background">
 80→        <div className="absolute inset-0 dots-pattern" />
 81→        <div className="relative container mx-auto flex min-h-dvh items-center justify-center px-6 py-12">
 82→          <div className="card-editorial flex w-full max-w-md items-center justify-center gap-3 p-8 text-sm text-muted-foreground">
 83→            <svg className="h-4 w-4 animate-spin" fill="none" viewBox="0 0 24 24">
 84→              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
 85→              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
 86→            </svg>
 87→            Redirecting to your workspace...
 88→          </div>
 89→        </div>
 90→      </main>
