 93→
 94→  return (
 95→    <main className="relative min-h-dvh overflow-hidden bg-background">
 96→      <div className="absolute inset-0 dots-pattern" />
 97→      <div className="absolute top-0 right-0 h-[600px] w-[600px] rounded-full bg-primary/5 blur-3xl -translate-y-1/2 translate-x-1/2" />
 98→      <div className="absolute bottom-0 left-0 h-[400px] w-[400px] rounded-full bg-accent/10 blur-3xl translate-y-1/2 -translate-x-1/2" />
