 15→// Theme script runs before React hydration to prevent flash
 16→// Sets dark class on <html> based on localStorage or system preference
 17→const themeScript = `(function(){
 18→  try {
 19→    var stored = localStorage.getItem("theme");
 20→    if (stored === "dark") {
 21→      document.documentElement.classList.add("dark");
 22→      return;
 23→    }
 24→    if (stored === "light") {
 25→      document.documentElement.classList.remove("dark");
 26→      return;
 27→    }
 28→  } catch (e) {}
 29→  if (window.matchMedia && window.matchMedia("(prefers-color-scheme: dark)").matches) {
 30→    document.documentElement.classList.add("dark");
 31→  }
 32→})();`;
