100→export function ErrorBoundary({ error }: Route.ErrorBoundaryProps) {
101→  let message = "Oops!";
102→  let details = "An unexpected error occurred.";
103→  let stack: string | undefined;
104→
105→  if (isRouteErrorResponse(error)) {
106→    message = error.status === 404 ? "404" : "Error";
107→    details =
108→      error.status === 404
109→        ? "The requested page could not be found."
110→        : error.statusText || details;
111→  } else if (import.meta.env.DEV && error && error instanceof Error) {
112→    details = error.message;
113→    stack = error.stack;
114→  }
115→
116→  return (
117→    <main className="pt-16 p-4 container mx-auto">
118→      <h1>{message}</h1>
119→      <p>{details}</p>
120→      {stack && (
121→        <pre className="w-full p-4 overflow-x-auto">
122→          <code>{stack}</code>
123→        </pre>
124→      )}
125→    </main>
126→  );
127→}
