 15→export const API_BASE = import.meta.env.VITE_API_URL || "http://localhost:4000";
 16→
 17→async function http(path: string, init?: RequestInit) {
 18→  const headers: Record<string, string> = {
 19→    "Content-Type": "application/json",
 20→  };
 21→
 22→  const res = await fetch(`${API_BASE}${path}`, {
 23→    ...init,
 24→    credentials: "include",
 25→    headers: {
 26→      ...headers,
 27→      ...(init?.headers || {}),
 28→    },
 29→  });
 30→
 31→  if (!res.ok) {
 32→    if (res.status === 401 || res.status === 403) {
 33→      // Only redirect if we are NOT already at the root
 34→      if (window.location.pathname !== "/") {
 35→        window.location.href = "/";
 36→      }
 37→      throw new Error("Authentication required");
 38→    }
 39→    const text = await res.text();
 40→    throw new Error(text || `Request failed: ${res.status}`);
 41→  }
 42→  return res.json();
 43→}
