 36→export function TourProvider({ children }: { children: React.ReactNode }) {
 37→  const location = useLocation();
 38→  const navigate = useNavigate();
 39→  const [activeTourId, setActiveTourId] = useState<AppTourId | null>(null);
 40→  const driverRef = useRef<Driver | null>(null);
 41→  const sessionRef = useRef<ActiveTourSession | null>(null);
 42→  const renderTokenRef = useRef(0);
 43→  const suppressDestroyedRef = useRef(false);
 44→
 45→  const clearTourState = useCallback(() => {
 46→    renderTokenRef.current += 1;
 47→    sessionRef.current = null;
 48→    setActiveTourId(null);
 49→  }, []);
 50→
 51→  const destroyDriver = useCallback((suppressOnDestroyed = false) => {
 52→    if (suppressOnDestroyed) {
 53→      suppressDestroyedRef.current = true;
 54→    }
 55→
 56→    driverRef.current?.destroy();
 57→  }, []);
 58→
 59→  const ensureDriver = useCallback(async () => {
 60→    if (driverRef.current) return driverRef.current;
 61→
 62→    const { driver } = await import('driver.js');
 63→    driverRef.current = driver({
 64→      animate: true,
 65→      allowClose: true,
 66→      overlayClickBehavior: () => {
 67→        stopTour();
 68→      },
 69→      overlayOpacity: 0.62,
 70→      overlayColor: 'rgb(20 14 10)',
 71→      smoothScroll: true,
 72→      stagePadding: 12,
 73→      stageRadius: 20,
 74→      popoverOffset: 18,
 75→      showProgress: true,
 76→      allowKeyboardControl: true,
 77→      popoverClass: 'driver-popover-aitutor',
 78→      onDestroyStarted: () => {
 79→        if (suppressDestroyedRef.current) return;
 80→        clearTourState();
 81→      },
 82→      onDestroyed: () => {
 83→        if (suppressDestroyedRef.current) {
 84→          suppressDestroyedRef.current = false;
 85→          return;
 86→        }
 87→
 88→        clearTourState();
 89→      },
 90→    });
 91→
 92→    return driverRef.current;
 93→  }, [clearTourState]);
 94→
 95→  const stopTour = useCallback(() => {
 96→    clearTourState();
 97→    destroyDriver(true);
 98→  }, [clearTourState, destroyDriver]);
 99→
100→  const completeTour = useCallback((tour: AppTourDefinition) => {
101→    markTourCompleted(tour);
102→    stopTour();
103→  }, [stopTour]);
104→
105→  const showStep = useCallback(async () => {
106→    const session = sessionRef.current;
107→    if (!session) return;
108→
109→    const { step, route, hasPrevious, hasNext } = getStepMeta(session);
110→    if (!route) {
111→      const nextIndex = moveSessionAfterMissingTarget(session);
112→      if (nextIndex == null) {
113→        completeTour(session.tour);
114→        return;
115→      }
116→      void showStep();
117→      return;
118→    }
119→
120→    session.context.currentPath = location.pathname;
121→
122→    if (route !== location.pathname) {
123→      destroyDriver(true);
124→      session.pendingRoute = route;
125→      navigate(route);
126→      return;
127→    }
128→
129→    const token = ++renderTokenRef.current;
130→
131→    try {
132→      const element = await waitForElement(step.target);
133→      if (renderTokenRef.current !== token || sessionRef.current !== session) return;
134→
135→      const projectedSession: ActiveTourSession = {
136→        ...session,
137→        context: { ...session.context },
138→      };
139→      storeStepSelection(projectedSession, element);
140→      const projectedHasNext = findStepIndex(
141→        projectedSession,
142→        projectedSession.stepIndex + 1,
143→        1,
144→      ) != null;
145→
146→      const driver = await ensureDriver();
147→      if (renderTokenRef.current !== token || sessionRef.current !== session) return;
148→
149→      destroyDriver(true);
150→
151→      driver.highlight({
152→        element,
153→        disableActiveInteraction: true,
154→        popover: {
155→          title: step.title,
156→          description: step.description,
157→          side: step.side ?? 'bottom',
158→          align: step.align ?? 'center',
159→          showButtons: [
160→            ...(hasPrevious ? (['previous'] as const) : []),
161→            'next',
162→            'close',
163→          ],
164→          progressText: `${session.stepIndex + 1} of ${session.tour.steps.length}`,
165→          nextBtnText: projectedHasNext ? 'Continue' : 'Finish',
166→          prevBtnText: 'Back',
167→          doneBtnText: 'Finish',
168→          onPopoverRender: applyPopoverTheme,
169→          onCloseClick: () => stopTour(),
170→          onPrevClick: () => {
171→            const currentSession = sessionRef.current;
172→            if (!currentSession) return;
173→            const previousIndex = moveSession(currentSession, -1);
174→            if (previousIndex == null) return;
175→            void showStep();
176→          },
177→          onNextClick: () => {
178→            const currentSession = sessionRef.current;
179→            if (!currentSession) return;
180→
181→            storeStepSelection(
182→              currentSession,
183→              driver.getActiveElement() ?? document.querySelector(step.target),
184→            );
185→
186→            const nextIndex = moveSession(currentSession, 1);
187→            if (nextIndex == null) {
188→              completeTour(currentSession.tour);
189→              return;
190→            }
191→            void showStep();
192→          },
193→        },
194→      });
195→    } catch {
196→      const currentSession = sessionRef.current;
197→      if (!currentSession) return;
198→      const nextIndex = moveSessionAfterMissingTarget(currentSession);
199→      if (nextIndex == null) {
200→        completeTour(currentSession.tour);
201→        return;
202→      }
203→      void showStep();
204→    }
205→  }, [completeTour, ensureDriver, location.pathname, navigate, stopTour]);
206→
207→  const startTour = useCallback((tourId: AppTourId) => {
208→    const tour = tourDefinitions[tourId];
209→    sessionRef.current = createTourSession(tour, location.pathname);
210→    setActiveTourId(tourId);
211→    destroyDriver(true);
212→    void showStep();
213→  }, [destroyDriver, location.pathname, showStep]);
214→
215→  const suggestedTourId = useMemo<AppTourId | null>(() => {
216→    if (!location.pathname.startsWith('/student')) return null;
217→    return isLessonRoute(location.pathname) ? 'student-lesson-help' : 'student-journey';
218→  }, [location.pathname]);
219→
220→  const startSuggestedTour = useCallback(() => {
221→    if (!suggestedTourId) return;
222→    startTour(suggestedTourId);
223→  }, [startTour, suggestedTourId]);
224→
225→  useEffect(() => {
226→    const session = sessionRef.current;
227→    if (!session) return;
228→
229→    session.context.currentPath = location.pathname;
230→
231→    if (session.pendingRoute === location.pathname) {
232→      session.pendingRoute = null;
233→      void showStep();
234→    }
235→  }, [location.pathname, showStep]);
236→
237→  useEffect(() => () => {
238→    destroyDriver(true);
239→  }, [destroyDriver]);
240→
241→  const value = useMemo<TourContextValue>(() => ({
242→    activeTourId,
243→    isRunning: activeTourId != null,
244→    suggestedTourId,
245→    startTour,
246→    startSuggestedTour,
247→    stopTour,
248→  }), [activeTourId, startSuggestedTour, startTour, stopTour, suggestedTourId]);
249→
250→  return (
251→    <AppTourContext.Provider value={value}>
252→      {children}
253→    </AppTourContext.Provider>
254→  );
255→}
256→
257→export function useAppTour() {
258→  const context = useContext(AppTourContext);
259→  if (!context) {
260→    throw new Error('useAppTour must be used within a TourProvider');
261→  }
262→  return context;
263→}
