 34→      try {
 35→        const parsed = JSON.parse(error.message);
 36→        if (parsed && typeof parsed === 'object' && typeof parsed.error === 'string') {
 37→          return parsed.error;
 38→        }
 39→      } catch {
 40→        // Ignore JSON parse failures
 41→      }
 42→      return error.message;
