 1→import { createContext, useContext, useEffect, useMemo, useState } from "react";
 2→import api from "~/lib/api";
 3→import type { User } from "~/lib/types";
 4→
 5→export type AuthUser = Pick<User, "id" | "name" | "role">;
 6→
 7→type AuthContextValue = {
 8→  user: AuthUser | null;
 9→  isInitializing: boolean;
10→  saveAuth: (userData: AuthUser) => void;
11→  logout: () => Promise<void>;
12→  setUser: (user: AuthUser | null) => void;
13→};
14→
15→const AuthContext = createContext<AuthContextValue | undefined>(undefined);
16→
17→type AuthProviderProps = {
18→  initialUser: AuthUser | null;
19→  children: React.ReactNode;
20→};
21→
22→export function AuthProvider({ initialUser, children }: AuthProviderProps) {
23→  const [user, setUser] = useState<AuthUser | null>(initialUser);
24→  const [isInitializing, setIsInitializing] = useState(!initialUser);
25→
26→  useEffect(() => {
27→    if (initialUser) {
28→      setIsInitializing(false);
29→      return;
30→    }
31→
32→    let cancelled = false;
33→
34→    api
35→      .me()
36→      .then((data) => {
37→        if (cancelled) return;
38→        const nextUser = data?.user ?? null;
39→        if (nextUser) {
40→          setUser({ id: nextUser.id, name: nextUser.name, role: nextUser.role });
41→        } else {
42→          setUser(null);
43→        }
44→      })
45→      .catch(() => {
46→        if (cancelled) return;
47→        setUser(null);
48→      })
49→      .finally(() => {
50→        if (cancelled) return;
51→        setIsInitializing(false);
52→      });
53→
54→    return () => {
55→      cancelled = true;
56→    };
57→  }, [initialUser]);
58→
59→  const saveAuth = (userData: AuthUser) => {
60→    setUser(userData);
61→  };
62→
63→  const logout = async () => {
64→    try {
65→      await api.logout();
66→    } catch (error) {
67→      console.error("Failed to log out", error);
68→    }
69→    setUser(null);
70→  };
71→
72→  const value = useMemo<AuthContextValue>(
73→    () => ({
74→      user,
75→      isInitializing,
76→      saveAuth,
77→      logout,
78→      setUser,
79→    }),
80→    [isInitializing, user],
81→  );
82→
83→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
84→}
85→
86→export function useLocalUser() {
87→  const context = useContext(AuthContext);
88→  if (!context) {
89→    throw new Error("useLocalUser must be used within an AuthProvider");
90→  }
91→  return context;
92→}
