111→  --chart-4: oklch(0.65 0.15 60);
112→  --chart-5: oklch(0.50 0.10 300);
113→  
114→  --sidebar: oklch(0.96 0.01 75);
115→  --sidebar-foreground: oklch(0.18 0.02 45);
116→  --sidebar-primary: oklch(0.52 0.14 35);
117→  --sidebar-primary-foreground: oklch(0.98 0.005 80);
118→  --sidebar-accent: oklch(0.92 0.02 75);
119→  --sidebar-accent-foreground: oklch(0.35 0.03 45);
120→  --sidebar-border: oklch(0.88 0.02 70);
121→  --sidebar-ring: oklch(0.52 0.14 35);
122→}
123→
124→.dark {
125→  /* Dark theme - Deep charcoal & copper */
126→  --background: oklch(0.14 0.01 45);
127→  --foreground: oklch(0.92 0.01 75);
128→  --card: oklch(0.18 0.01 45);
129→  --card-foreground: oklch(0.92 0.01 75);
130→  --popover: oklch(0.18 0.01 45);
131→  --popover-foreground: oklch(0.92 0.01 75);
132→  
133→  /* Primary - Warm copper */
134→  --primary: oklch(0.70 0.14 50);
135→  --primary-foreground: oklch(0.14 0.01 45);
136→  
137→  /* Secondary - Slate */
138→  --secondary: oklch(0.24 0.01 45);
139→  --secondary-foreground: oklch(0.88 0.01 75);
140→  
141→  /* Muted */
142→  --muted: oklch(0.22 0.01 45);
143→  --muted-foreground: oklch(0.60 0.01 75);
144→  
145→  /* Accent - Muted sage */
146→  --accent: oklch(0.28 0.03 150);
147→  --accent-foreground: oklch(0.85 0.04 150);
148→  
149→  --destructive: oklch(0.65 0.20 25);
150→  --border: oklch(0.26 0.01 45);
151→  --input: oklch(0.22 0.01 45);
152→  --ring: oklch(0.70 0.14 50);
153→  
154→  --chart-1: oklch(0.70 0.14 50);
155→  --chart-2: oklch(0.65 0.10 150);
156→  --chart-3: oklch(0.70 0.12 250);
157→  --chart-4: oklch(0.75 0.12 60);
158→  --chart-5: oklch(0.65 0.12 300);
159→  
160→  --sidebar: oklch(0.16 0.01 45);
161→  --sidebar-foreground: oklch(0.92 0.01 75);
162→  --sidebar-primary: oklch(0.70 0.14 50);
163→  --sidebar-primary-foreground: oklch(0.14 0.01 45);
164→  --sidebar-accent: oklch(0.22 0.01 45);
165→  --sidebar-accent-foreground: oklch(0.88 0.01 75);
166→  --sidebar-border: oklch(0.26 0.01 45);
167→  --sidebar-ring: oklch(0.70 0.14 50);
168→}
169→
170→/* ========================================
171→   CUSTOM COLOR PALETTE UTILITIES
172→   ======================================== */
173→
174→@theme inline {
175→  /* Surface colors */
176→  --color-surface-cream: oklch(0.98 0.005 80);
177→  --color-surface-warm: oklch(0.96 0.01 75);
178→  
179→  /* Ink (text) colors */
180→  --color-ink-50: oklch(0.98 0.005 80);
181→  --color-ink-100: oklch(0.95 0.008 75);
182→  --color-ink-200: oklch(0.88 0.02 70);
183→  --color-ink-300: oklch(0.75 0.02 60);
184→  --color-ink-400: oklch(0.60 0.02 50);
185→  --color-ink-500: oklch(0.50 0.02 45);
186→  --color-ink-600: oklch(0.40 0.02 45);
187→  --color-ink-700: oklch(0.30 0.02 45);
188→  --color-ink-800: oklch(0.22 0.015 45);
189→  --color-ink-900: oklch(0.18 0.02 45);
190→  --color-ink-950: oklch(0.14 0.01 45);
191→  
192→  /* Terracotta (primary warm) */
193→  --color-terracotta-50: oklch(0.97 0.02 40);
194→  --color-terracotta-100: oklch(0.93 0.04 38);
195→  --color-terracotta-200: oklch(0.87 0.07 36);
196→  --color-terracotta-300: oklch(0.78 0.10 35);
197→  --color-terracotta-400: oklch(0.68 0.13 34);
198→  --color-terracotta-500: oklch(0.58 0.14 35);
199→  --color-terracotta-600: oklch(0.52 0.14 35);
200→  --color-terracotta-700: oklch(0.45 0.12 35);
201→  --color-terracotta-800: oklch(0.38 0.10 35);
202→  --color-terracotta-900: oklch(0.30 0.08 35);
203→  --color-terracotta-950: oklch(0.22 0.06 35);
204→  
205→  /* Sage (accent green) */
206→  --color-sage-50: oklch(0.97 0.02 150);
207→  --color-sage-100: oklch(0.94 0.03 150);
208→  --color-sage-200: oklch(0.88 0.05 150);
209→  --color-sage-300: oklch(0.78 0.07 150);
210→  --color-sage-400: oklch(0.65 0.09 150);
211→  --color-sage-500: oklch(0.55 0.10 150);
212→  --color-sage-600: oklch(0.48 0.09 150);
213→  --color-sage-700: oklch(0.40 0.08 150);
214→  --color-sage-800: oklch(0.32 0.06 150);
215→  --color-sage-900: oklch(0.25 0.05 150);
216→  --color-sage-950: oklch(0.18 0.04 150);
217→}
218→
219→/* ========================================
220→   BASE LAYER
221→   ======================================== */
222→
223→@layer base {
224→  * {
225→    @apply border-border outline-ring/50;
226→  }
227→  
228→  body {
229→    @apply bg-background text-foreground;
230→    font-feature-settings: "ss01", "ss02", "cv01";
231→  }
232→  
233→  /* Display typography */
234→  h1, h2, h3 {
235→    font-family: var(--font-display);
236→    @apply tracking-tight;
237→  }
238→  
239→  /* Smooth focus states */
240→  :focus-visible {
241→    @apply outline-none ring-2 ring-ring ring-offset-2 ring-offset-background;
242→    transition: box-shadow 0.15s ease;
243→  }
244→}
245→
246→/* ========================================
247→   CUSTOM COMPONENTS
248→   ======================================== */
249→
250→@layer components {
251→  /* Editorial card with subtle texture */
252→  .card-editorial {
253→    @apply relative overflow-hidden rounded-2xl border border-border bg-card;
254→    background-image: 
255→      radial-gradient(circle at 100% 0%, oklch(0.52 0.14 35 / 0.03) 0%, transparent 50%),
256→      linear-gradient(135deg, transparent 0%, oklch(0.92 0.02 75 / 0.5) 100%);
257→  }
258→  
259→  .dark .card-editorial {
260→    background-image: 
261→      radial-gradient(circle at 100% 0%, oklch(0.70 0.14 50 / 0.05) 0%, transparent 50%),
262→      linear-gradient(135deg, transparent 0%, oklch(0.18 0.01 45 / 0.5) 100%);
263→  }
264→  
265→  /* Glass morphism panel */
266→  .panel-glass {
267→    @apply backdrop-blur-xl bg-card/70 border border-border/50 shadow-xl;
268→    background-image: linear-gradient(
269→      135deg,
270→      oklch(1 0 0 / 0.1) 0%,
271→      oklch(1 0 0 / 0.05) 100%
272→    );
273→  }
274→  
275→  .dark .panel-glass {
276→    background-image: linear-gradient(
277→      135deg,
278→      oklch(1 0 0 / 0.03) 0%,
279→      oklch(1 0 0 / 0.01) 100%
280→    );
281→  }
282→  
283→  /* Prominent button with glow */
284→  .btn-primary {
285→    @apply relative inline-flex items-center justify-center gap-2 px-5 py-2.5;
286→    @apply font-semibold text-primary-foreground bg-primary rounded-xl;
287→    @apply shadow-lg shadow-primary/20;
288→    @apply transition-all duration-300;
289→    @apply hover:shadow-xl hover:shadow-primary/30 hover:-translate-y-0.5;
290→    @apply active:translate-y-0 active:shadow-md;
291→    @apply disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:translate-y-0;
292→  }
293→  
294→  .btn-primary::before {
295→    content: '';
296→    @apply absolute inset-0 rounded-xl opacity-0 transition-opacity duration-300;
297→    background: linear-gradient(135deg, oklch(1 0 0 / 0.15) 0%, transparent 50%);
298→  }
299→  
300→  .btn-primary:hover::before {
301→    @apply opacity-100;
302→  }
303→  
304→  /* Secondary button */
305→  .btn-secondary {
306→    @apply inline-flex items-center justify-center gap-2 px-5 py-2.5;
307→    @apply font-medium text-foreground bg-secondary rounded-xl;
308→    @apply border border-border;
309→    @apply transition-all duration-200;
310→    @apply hover:bg-muted hover:border-foreground/20;
311→    @apply active:scale-[0.98];
312→  }
313→  
314→  /* Ghost button */
315→  .btn-ghost {
316→    @apply inline-flex items-center justify-center gap-2 px-4 py-2;
317→    @apply font-medium text-muted-foreground rounded-lg;
318→    @apply transition-all duration-200;
319→    @apply hover:text-foreground hover:bg-muted;
320→    @apply active:scale-[0.98];
321→  }
322→  
323→  /* Input field */
324→  .input-field {
325→    @apply w-full px-4 py-3 rounded-xl;
326→    @apply bg-background border-2 border-border;
327→    @apply text-foreground placeholder:text-muted-foreground;
328→    @apply transition-all duration-200;
329→    @apply focus:border-primary focus:ring-0;
330→  }
331→  
332→  /* Tag/badge */
333→  .tag {
334→    @apply inline-flex items-center px-2.5 py-0.5 rounded-full;
335→    @apply text-xs font-semibold tracking-wide uppercase;
336→    @apply bg-secondary text-secondary-foreground;
337→  }
338→  
339→  .tag-primary {
340→    @apply bg-primary/10 text-primary;
341→  }
342→  
343→  .tag-accent {
344→    @apply bg-accent text-accent-foreground;
345→  }
346→
347→  .driver-active .driver-overlay {
348→    background:
349→      radial-gradient(circle at top, oklch(0.70 0.14 50 / 0.05), transparent 32%),
350→      linear-gradient(180deg, oklch(0.08 0.01 45 / 0.46), oklch(0.08 0.01 45 / 0.68));
351→  }
352→
353→  .driver-active-element {
354→    position: relative;
355→    z-index: 1000001;
356→    filter: brightness(1.08) saturate(1.04);
357→    box-shadow: 0 18px 38px oklch(0.02 0.01 45 / 0.28);
358→  }
359→
360→  .driver-popover.driver-popover-aitutor {
361→    @apply max-w-[22rem] rounded-3xl border border-border bg-card p-5 text-card-foreground shadow-2xl;
362→    font-family: var(--font-sans);
363→    box-shadow:
364→      0 24px 80px oklch(0.18 0.02 45 / 0.24),
365→      0 6px 24px oklch(0.18 0.02 45 / 0.12);
366→    background-image:
367→      radial-gradient(circle at top right, oklch(0.52 0.14 35 / 0.08), transparent 45%),
368→      linear-gradient(135deg, transparent 0%, oklch(0.92 0.02 75 / 0.45) 100%);
369→  }
370→
371→  .dark .driver-popover.driver-popover-aitutor {
372→    background-image:
373→      radial-gradient(circle at top right, oklch(0.70 0.14 50 / 0.12), transparent 45%),
374→      linear-gradient(135deg, transparent 0%, oklch(0.24 0.01 45 / 0.7) 100%);
375→  }
376→
377→  .driver-popover-aitutor .driver-popover-title {
378→    @apply pr-8 text-xl leading-tight;
379→    font-family: var(--font-display);
380→    font-weight: 700;
381→    color: var(--primary);
382→  }
383→
384→  .dark .driver-popover-aitutor .driver-popover-title {
385→    color: var(--primary);
386→  }
387→
388→  .driver-popover-aitutor .driver-popover-description {
389→    @apply mt-2 text-sm leading-6 text-muted-foreground;
390→    font-family: var(--font-sans);
391→  }
392→
393→  .driver-popover-aitutor .driver-popover-footer {
394→    @apply mt-[15px];
395→  }
396→
397→  .driver-popover-aitutor .driver-popover-progress-text {
398→    @apply text-xs font-medium uppercase tracking-[0.18em] text-muted-foreground;
399→  }
400→
401→  .driver-popover-aitutor .driver-popover-close-btn {
402→    @apply flex h-8 w-8 items-center justify-center rounded-full text-muted-foreground transition-colors;
403→  }
404→
405→  .driver-popover-aitutor .driver-popover-close-btn:hover,
406→  .driver-popover-aitutor .driver-popover-close-btn:focus-visible {
407→    @apply bg-secondary text-foreground;
408→  }
409→
410→  .driver-popover-aitutor .driver-popover-arrow {
411→    border-width: 8px;
412→  }
413→
414→  .driver-popover-aitutor .driver-popover-arrow-side-top,
415→  .driver-popover-aitutor .driver-popover-arrow-side-bottom,
416→  .driver-popover-aitutor .driver-popover-arrow-side-left,
417→  .driver-popover-aitutor .driver-popover-arrow-side-right {
418→    border-color: var(--card);
419→  }
420→
421→  .driver-popover-aitutor .driver-popover-arrow-side-left {
422→    border-right-color: transparent;
423→    border-bottom-color: transparent;
424→    border-top-color: transparent;
425→  }
426→
427→  .driver-popover-aitutor .driver-popover-arrow-side-right {
428→    border-left-color: transparent;
429→    border-bottom-color: transparent;
430→    border-top-color: transparent;
431→  }
432→
433→  .driver-popover-aitutor .driver-popover-arrow-side-top {
434→    border-right-color: transparent;
435→    border-bottom-color: transparent;
436→    border-left-color: transparent;
437→  }
438→
439→  .driver-popover-aitutor .driver-popover-arrow-side-bottom {
440→    border-left-color: transparent;
441→    border-top-color: transparent;
442→    border-right-color: transparent;
443→  }
444→
445→  .driver-tour-button {
446→    @apply inline-flex items-center justify-center rounded-xl border px-3 py-2 text-sm font-semibold transition-colors;
447→    font-family: var(--font-sans);
448→  }
449→
450→  .driver-tour-button-secondary {
451→    @apply border-border bg-card text-foreground hover:bg-secondary;
452→  }
453→
454→  .driver-tour-button-primary {
455→    @apply border-transparent bg-primary text-primary-foreground hover:opacity-95;
456→  }
457→}
458→
459→/* ========================================
460→   CUSTOM UTILITIES
461→   ======================================== */
462→
463→@layer utilities {
464→  /* Typography utilities */
465→  .font-display {
466→    font-family: var(--font-display);
467→  }
468→  
469→  .font-mono {
470→    font-family: var(--font-mono);
471→  }
472→  
473→  /* Gradient text */
474→  .text-gradient {
475→    @apply bg-clip-text text-transparent;
476→    background-image: linear-gradient(135deg, var(--primary), oklch(0.65 0.15 60));
477→  }
478→  
479→  .dark .text-gradient {
480→    background-image: linear-gradient(135deg, oklch(0.75 0.12 50), oklch(0.70 0.14 80));
481→  }
482→  
483→  /* Noise texture overlay */
484→  .noise::before {
485→    content: '';
486→    @apply absolute inset-0 pointer-events-none opacity-[0.015];
487→    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
488→  }
489→  
490→  .dark .noise::before {
491→    @apply opacity-[0.03];
492→  }
493→  
494→  /* Decorative dot pattern */
495→  .dots-pattern {
496→    background-image: radial-gradient(circle, oklch(0.52 0.14 35 / 0.1) 1px, transparent 1px);
497→    background-size: 24px 24px;
498→  }
499→  
500→  .dark .dots-pattern {
501→    background-image: radial-gradient(circle, oklch(0.70 0.14 50 / 0.1) 1px, transparent 1px);
502→  }
503→  
504→  /* Grid lines background */
505→  .grid-lines {
506→    background-image: 
507→      linear-gradient(to right, oklch(0 0 0 / 0.03) 1px, transparent 1px),
508→      linear-gradient(to bottom, oklch(0 0 0 / 0.03) 1px, transparent 1px);
509→    background-size: 48px 48px;
510→  }
511→  
512→  .dark .grid-lines {
513→    background-image: 
514→      linear-gradient(to right, oklch(1 0 0 / 0.03) 1px, transparent 1px),
515→      linear-gradient(to bottom, oklch(1 0 0 / 0.03) 1px, transparent 1px);
516→  }
517→  
518→  /* Glow effect */
519→  .glow {
520→    @apply relative;
521→  }
522→  
523→  .glow::after {
524→    content: '';
525→    @apply absolute -inset-1 rounded-[inherit] opacity-0 blur-xl transition-opacity duration-500;
526→    background: linear-gradient(135deg, var(--primary), oklch(0.65 0.12 150));
527→    z-index: -1;
528→  }
529→  
530→  .glow:hover::after {
531→    @apply opacity-20;
532→  }
533→}
534→
535→/* ========================================
536→   ANIMATIONS
537→   ======================================== */
538→
539→@keyframes fade-in {
540→  from { opacity: 0; }
541→  to { opacity: 1; }
542→}
543→
544→@keyframes fade-up {
545→  from { 
546→    opacity: 0; 
547→    transform: translateY(16px);
548→  }
549→  to { 
550→    opacity: 1; 
551→    transform: translateY(0);
552→  }
553→}
554→
555→@keyframes fade-down {
556→  from { 
557→    opacity: 0; 
558→    transform: translateY(-16px);
559→  }
560→  to { 
561→    opacity: 1; 
562→    transform: translateY(0);
563→  }
564→}
565→
566→@keyframes scale-in {
567→  from { 
568→    opacity: 0; 
569→    transform: scale(0.95);
570→  }
571→  to { 
572→    opacity: 1; 
573→    transform: scale(1);
574→  }
575→}
576→
577→@keyframes slide-in-right {
578→  from { 
579→    opacity: 0; 
580→    transform: translateX(24px);
581→  }
582→  to { 
583→    opacity: 1; 
584→    transform: translateX(0);
585→  }
586→}
587→
588→@keyframes float {
589→  0%, 100% { transform: translateY(0); }
590→  50% { transform: translateY(-8px); }
591→}
592→
593→@keyframes pulse-soft {
594→  0%, 100% { opacity: 1; }
595→  50% { opacity: 0.7; }
596→}
597→
598→@keyframes shimmer {
599→  0% { background-position: -200% 0; }
600→  100% { background-position: 200% 0; }
601→}
602→
603→@layer utilities {
604→  .animate-fade-in {
605→    opacity: 0;
606→    animation: fade-in 0.4s var(--ease-out-expo) forwards;
607→  }
608→  
609→  .animate-fade-up {
610→    opacity: 0;
611→    transform: translateY(16px);
612→    animation: fade-up 0.5s var(--ease-out-expo) forwards;
613→  }
614→  
615→  .animate-fade-down {
616→    opacity: 0;
617→    transform: translateY(-16px);
618→    animation: fade-down 0.5s var(--ease-out-expo) forwards;
619→  }
620→  
621→  .animate-scale-in {
622→    opacity: 0;
623→    transform: scale(0.95);
624→    animation: scale-in 0.4s var(--ease-out-expo) forwards;
625→  }
626→  
627→  .animate-slide-in-right {
628→    opacity: 0;
629→    transform: translateX(24px);
630→    animation: slide-in-right 0.5s var(--ease-out-expo) forwards;
631→  }
632→  
633→  .animate-float {
634→    animation: float 3s ease-in-out infinite;
635→  }
636→  
637→  .animate-pulse-soft {
638→    animation: pulse-soft 2s ease-in-out infinite;
639→  }
640→  
641→  .animate-shimmer {
642→    background: linear-gradient(
643→      90deg,
644→      transparent 0%,
645→      oklch(1 0 0 / 0.1) 50%,
646→      transparent 100%
647→    );
648→    background-size: 200% 100%;
649→    animation: shimmer 2s linear infinite;
650→  }
651→  
652→  /* Stagger delays */
653→  .delay-75 { animation-delay: 75ms; }
654→  .delay-150 { animation-delay: 150ms; }
655→  .delay-200 { animation-delay: 200ms; }
656→  .delay-300 { animation-delay: 300ms; }
657→  .delay-400 { animation-delay: 400ms; }
658→  .delay-500 { animation-delay: 500ms; }
659→}
660→
661→/* ========================================
662→   SCROLLBAR STYLING
663→   ======================================== */
664→
665→::-webkit-scrollbar {
666→  @apply w-2 h-2;
667→}
668→
669→::-webkit-scrollbar-track {
670→  @apply bg-transparent;
671→}
672→
673→::-webkit-scrollbar-thumb {
674→  @apply bg-border rounded-full;
675→  @apply hover:bg-muted-foreground/30;
676→}
677→
678→/* Firefox */
679→* {
680→  scrollbar-width: thin;
681→  scrollbar-color: var(--border) transparent;
682→}
683→
684→/* ========================================
685→   SELECTION
686→   ======================================== */
687→
688→::selection {
689→  @apply bg-primary/20 text-foreground;
690→}
