123→                        className={`flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-medium cursor-default ${
124→                          eduAiStatus === 'loading' 
125→                            ? 'bg-muted text-muted-foreground' 
126→                            : eduAiStatus === 'connected'
127→                            ? 'bg-green-500/15 text-green-600 dark:text-green-400'
128→                            : 'bg-red-500/15 text-red-600 dark:text-red-400'
129→                        }`}
130→                      >
131→                        <span className={`h-1.5 w-1.5 rounded-full ${
132→                          eduAiStatus === 'loading'
133→                            ? 'bg-muted-foreground animate-pulse'
134→                            : eduAiStatus === 'connected'
135→                            ? 'bg-green-500'
136→                            : 'bg-red-500'
137→                        }`} />
138→                        <span className="hidden sm:inline">EduAI</span>
139→                      </div>
140→                    </TooltipTrigger>
141→                    <TooltipContent>
142→                      {eduAiStatus === 'loading' 
143→                        ? 'Checking EduAI connection...' 
144→                        : eduAiStatus === 'connected'
145→                        ? 'EduAI is connected'
146→                        : 'EduAI is not connected'}
147→                    </TooltipContent>
148→                  </Tooltip>
149→
150→                  {/* User badge */}
151→                  <div className="hidden md:flex items-center gap-2">
152→                    <div className="flex h-8 w-8 items-center justify-center rounded-full bg-secondary text-xs font-semibold uppercase text-secondary-foreground">
153→                      {user.name?.charAt(0) || 'U'}
154→                    </div>
155→                    <div className="flex flex-col">
156→                      <span className="text-sm font-medium text-foreground leading-tight">
157→                        {user.name}
158→                      </span>
159→                      <span className="text-[10px] font-medium uppercase tracking-wider text-muted-foreground">
160→                        {user.role}
161→                      </span>
162→                    </div>
163→                  </div>
164→                  
165→                  {/* Logout button */}
166→                  <button
167→                    onClick={handleLogout}
168→                    className="btn-ghost text-sm text-muted-foreground hover:text-destructive"
169→                    title="Sign out"
170→                  >
171→                    <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
172→                      <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 9V5.25A2.25 2.25 0 0013.5 3h-6a2.25 2.25 0 00-2.25 2.25v13.5A2.25 2.25 0 007.5 21h6a2.25 2.25 0 002.25-2.25V15m3 0l3-3m0 0l-3-3m3 3H9" />
173→                    </svg>
174→                    <span className="hidden sm:inline">Sign out</span>
175→                  </button>
176→                </div>
177→              )}
178→            </nav>
179→          </div>
180→        </div>
181→      </div>
182→    </header>
183→  );
184→}
