 2→
 3→interface ProgressBarProps {
 4→  completed: number;
 5→  total: number;
 6→  size?: 'sm' | 'md' | 'lg';
 7→  showLabel?: boolean;
 8→  className?: string;
 9→}
10→
11→export function ProgressBar({
12→  completed,
13→  total,
14→  size = 'md',
15→  showLabel = true,
16→  className = '',
17→}: ProgressBarProps) {
18→  const percentage = total > 0 ? Math.round((completed / total) * 100) : 0;
19→  const isComplete = percentage === 100;
20→
21→  const heights = {
22→    sm: 'h-1.5',
23→    md: 'h-2.5',
24→    lg: 'h-3.5',
25→  };
26→
27→  return (
28→    <div className={`space-y-2 ${className}`}>
29→      {showLabel && (
30→        <div className="flex justify-between items-center text-xs">
31→          <span className="text-muted-foreground font-medium">
32→            {completed} of {total} completed
33→          </span>
34→          <span className="font-bold tabular-nums text-foreground">
35→            {percentage}%
36→          </span>
37→        </div>
38→      )}
39→      <div
40→        className={`relative w-full bg-secondary rounded-full overflow-hidden ${heights[size]}`}
41→      >
42→        {/* Track glow on completion */}
43→        {isComplete && (
44→          <div className="absolute inset-0 bg-primary/30 animate-pulse-soft" />
45→        )}
46→        
47→        {/* Progress fill */}
48→        <div
49→          className="h-full rounded-full transition-all duration-700 ease-out relative bg-primary"
50→          style={{ width: `${percentage}%` }}
51→        >
52→          {/* Shimmer effect for in-progress */}
53→          {!isComplete && percentage > 0 && percentage < 100 && (
54→            <div className="absolute inset-0 animate-shimmer" />
55→          )}
56→        </div>
57→      </div>
58→    </div>
59→  );
60→}
61→
62→export function ProgressBarFromData({
63→  progress,
64→  size,
65→  showLabel,
66→  className,
67→}: {
68→  progress?: Progress;
69→  size?: 'sm' | 'md' | 'lg';
70→  showLabel?: boolean;
71→  className?: string;
72→}) {
73→  if (!progress) {
74→    return null;
75→  }
76→
77→  return (
78→    <ProgressBar
79→      completed={progress.completed}
80→      total={progress.total}
81→      size={size}
82→      showLabel={showLabel}
83→      className={className}
84→    />
85→  );
86→}
