 52→export async function clientLoader({ params }: Route.ClientLoaderArgs) {
 53→  await requireClientUser('STUDENT');
 54→  const lessonId = Number(params.lessonId);
 55→  if (!Number.isFinite(lessonId)) {
 56→    throw new Response('Invalid lesson id', { status: 400 });
 57→  }
 58→
 59→  const [lesson, activities] = await Promise.all([
 60→    api.lessonById(lessonId) as Promise<Lesson>,
 61→    api.activitiesForLesson(lessonId) as Promise<Activity[]>,
 62→  ]);
 63→
 64→  let module: ModuleDetail | null = null;
 65→  let course: Course | null = null;
 66→  if (lesson.moduleId) {
 67→    module = (await api.moduleById(lesson.moduleId)) as ModuleDetail;
 68→    if (module?.courseOfferingId) {
 69→      course = (await api.courseById(module.courseOfferingId)) as Course;
 70→    }
 71→  }
 72→
 73→  return { course, module, lesson, activities };
 74→}
