302→                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
303→              </svg>
304→              <p className="text-sm text-muted-foreground">Loading courses...</p>
305→            </div>
306→          </div>
307→        ) : oCourses.length === 0 ? (
308→          <div className="animate-fade-up delay-150">
309→            <div className="card-editorial p-12 text-center max-w-lg mx-auto">
310→              <div className="w-16 h-16 mx-auto mb-6 rounded-2xl bg-secondary flex items-center justify-center">
311→                <svg className="w-8 h-8 text-muted-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
312→                  <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m0 12.75h7.5m-7.5 3H12M10.5 2.25H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
313→                </svg>
314→              </div>
315→              <h2 className="font-display text-xl font-bold text-foreground mb-2">
316→                No courses yet
317→              </h2>
318→              <p className="text-muted-foreground text-sm">
319→                Import one from EduAI to get started with your teaching materials.
320→              </p>
321→            </div>
322→          </div>
323→        ) : (
324→          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
325→            {oCourses.map((c, index) => (
326→              <div
327→                key={c.id}
328→                role="button"
329→                tabIndex={0}
330→                onClick={() => navigate(`/instructor/courses/${c.id}`)}
331→                onKeyDown={(event) => {
332→                  if (event.key === 'Enter' || event.key === ' ') {
333→                    event.preventDefault();
334→                    navigate(`/instructor/courses/${c.id}`);
335→                  }
336→                }}
337→                className="group card-editorial p-6 cursor-pointer transition-all duration-300 hover:shadow-xl hover:-translate-y-1 glow flex flex-col animate-fade-up focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
338→                style={{ animationDelay: `${150 + index * 50}ms` }}
339→              >
340→                {/* Header */}
341→                <div className="flex items-start justify-between gap-3 mb-4">
342→                  <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center text-primary transition-colors group-hover:bg-primary group-hover:text-primary-foreground">
343→                    <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
344→                      <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m0 12.75h7.5m-7.5 3H12M10.5 2.25H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
345→                    </svg>
346→                  </div>
347→                  
348→                  {c.externalSource === 'EDUAI' && (
349→                    <span className="tag tag-primary">
350→                      EduAI
351→                    </span>
352→                  )}
353→                </div>
354→                
355→                {/* Course info */}
356→                <div className="flex-1 mb-4">
357→                  <h3 className="font-display text-lg font-bold text-foreground mb-1 group-hover:text-primary transition-colors line-clamp-2">
358→                    {c.title}
359→                  </h3>
360→                  {c.description && (
361→                    <p className="text-sm text-muted-foreground line-clamp-2">
362→                      {c.description}
363→                    </p>
364→                  )}
365→                </div>
366→                
367→                {/* Footer */}
368→                <div className="pt-4 border-t border-border flex items-center justify-between">
369→                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
370→                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
371→                      <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
372→                    </svg>
373→                    <span className="group-hover:text-foreground transition-colors">View course</span>
374→                  </div>
375→                  
376→                  <div
377→                    onClick={(event) => event.stopPropagation()}
378→                    onKeyDown={(event) => event.stopPropagation()}
379→                  >
380→                    <PublishStatusButton
381→                      isPublished={c.isPublished}
382→                      pending={publishingId === c.id}
383→                      onClick={() => {
384→                        if (publishingId === c.id) return;
385→                        togglePublish(c.id, c.isPublished);
386→                      }}
387→                    />
388→                  </div>
389→                </div>
390→              </div>
391→            ))}
392→          </div>
393→        )}
394→      </div>
395→    </div>
396→  );
397→}
