 34→export default function InstructorCourseModules({ loaderData }: Route.ComponentProps) {
 35→  const navigate = useNavigate();
 36→  const { courseId } = useParams();
 37→  const numericCourseId = courseId ? Number(courseId) : null;
 38→  const { course, modules: initialModules } = loaderData;
