 44→  const [selectedSourceCourseId, setSelectedSourceCourseId] = useState<number | null>(null);
 45→  const [sourceModules, setSourceModules] = useState<Module[]>([]);
 46→  const [loadingSourceCourses, setLoadingSourceCourses] = useState(false);
 47→  const [loadingSourceModules, setLoadingSourceModules] = useState(false);
 48→  const [selectedModuleIds, setSelectedModuleIds] = useState<Set<number>>(new Set());
 49→  const [importing, setImporting] = useState(false);
 50→  const [publishingId, setPublishingId] = useState<number | null>(null);
 51→  const modulesRequestIdRef = useRef(0);
 52→
 53→  const [oModules, addModuleOpt] = useOptimistic(
 54→    modules,
 55→    (state, patch: (items: Module[]) => Module[]) => patch(state),
 56→  );
 57→
 58→  // Adjust state during render when loader data changes
 59→  const [prevInitialModules, setPrevInitialModules] = useState(initialModules);
 60→  if (initialModules !== prevInitialModules) {
 61→    setPrevInitialModules(initialModules);
 62→    setModules(initialModules);
 63→  }
 64→
 65→  const refreshModules = async () => {
 66→    if (!numericCourseId) return;
 67→    try {
 68→      const modulesData = await api.modulesForCourse(numericCourseId);
 69→      setModules(modulesData);
 70→    } catch (error) {
 71→      console.error('Failed to refresh modules', error);
 72→    }
