 74→
 75→  const ensureSourceCoursesLoaded = () => {
 76→    if (availableCourses.length > 0) return;
 77→    setLoadingSourceCourses(true);
 78→    api
 79→      .listCourses()
 80→      .then((data: Course[]) => {
 81→        const nextCourses = numericCourseId
 82→          ? data.filter((course: Course) => course.id !== numericCourseId)
 83→          : data;
 84→        setAvailableCourses(nextCourses);
 85→      })
 86→      .catch((error) => console.error('Failed to load courses', error))
 87→      .finally(() => setLoadingSourceCourses(false));
 88→  };
 89→
 90→  const handleSourceCourseSelection = async (nextCourseId: number | null) => {
 91→    const requestId = ++modulesRequestIdRef.current;
 92→    setSelectedSourceCourseId(nextCourseId);
 93→    setSourceModules([]);
 94→    setSelectedModuleIds(new Set());
 95→
 96→    if (nextCourseId == null) {
 97→      setLoadingSourceModules(false);
 98→      return;
 99→    }
100→
101→    setLoadingSourceModules(true);
102→    try {
103→      const data = await api.modulesForCourse(nextCourseId);
104→      if (modulesRequestIdRef.current === requestId) {
105→        setSourceModules(data);
106→      }
107→    } catch (error) {
108→      if (modulesRequestIdRef.current === requestId) {
109→        console.error('Failed to load modules for course', error);
110→        setSourceModules([]);
111→      }
112→    } finally {
113→      if (modulesRequestIdRef.current === requestId) {
114→        setLoadingSourceModules(false);
115→      }
116→    }
117→  };
118→
119→  const onCreateModule = async (event: FormEvent) => {
120→    event.preventDefault();
