130→      setCreating(false);
131→    }
132→  };
133→
134→  const toggleModuleSelection = (moduleId: number) => {
135→    setSelectedModuleIds((prev) => {
136→      const next = new Set(prev);
137→      if (next.has(moduleId)) next.delete(moduleId);
138→      else next.add(moduleId);
139→      return next;
140→    });
141→  };
142→
143→  const onImport = async () => {
144→    if (!numericCourseId || selectedSourceCourseId == null || selectedModuleIds.size === 0) return;
145→    setImporting(true);
146→    try {
147→      await api.importIntoCourse(numericCourseId, {
148→        sourceCourseId: selectedSourceCourseId,
149→        moduleIds: Array.from(selectedModuleIds),
150→      });
151→      setShowImport(false);
152→      await handleSourceCourseSelection(null);
153→      await refreshModules();
