212→                  }
213→                  setShowImport((prev) => !prev);
214→                }}
215→                className="btn-secondary"
216→              >
217→                {showImport ? 'Close' : 'Import'}
218→              </button>
219→            </div>
220→          </div>
221→
222→          {showImport && (
223→            <div className="card-editorial p-5 space-y-4">
224→              <div>
225→                <label className="block text-sm font-semibold mb-1 text-foreground">Choose course to copy</label>
226→                <select
