 42→  const [title, setTitle] = useState('');
 43→  const [creating, setCreating] = useState(false);
 44→  const [showImport, setShowImport] = useState(false);
 45→  const [availableCourses, setAvailableCourses] = useState<Course[]>([]);
 46→  const [selectedSourceCourseId, setSelectedSourceCourseId] = useState<number | null>(null);
 47→  const [sourceModules, setSourceModules] = useState<Module[]>([]);
 48→  const [selectedSourceModuleId, setSelectedSourceModuleId] = useState<number | null>(null);
 49→  const [sourceLessons, setSourceLessons] = useState<Lesson[]>([]);
 50→  const [loadingSourceCourses, setLoadingSourceCourses] = useState(false);
 51→  const [loadingSourceModules, setLoadingSourceModules] = useState(false);
 52→  const [loadingSourceLessons, setLoadingSourceLessons] = useState(false);
 53→  const [selectedLessonIds, setSelectedLessonIds] = useState<Set<number>>(new Set());
 54→  const [importing, setImporting] = useState(false);
 55→  const [publishingId, setPublishingId] = useState<number | null>(null);
 56→  const sourceModulesRequestIdRef = useRef(0);
 57→  const sourceLessonsRequestIdRef = useRef(0);
