 71→  const refreshLessons = async () => {
 72→    if (!numericModuleId) return;
 73→    try {
 74→      const lessonData = await api.lessonsForModule(numericModuleId);
 75→      setLessons(lessonData);
 76→    } catch (error) {
 77→      console.error('Failed to refresh lessons', error);
 78→    }
