114→      const modulesData = await api.modulesForCourse(nextCourseId);
115→      if (sourceModulesRequestIdRef.current === courseRequestId) {
116→        setSourceModules(modulesData);
117→      }
118→    } catch (error) {
119→      if (sourceModulesRequestIdRef.current === courseRequestId) {
120→        console.error('Failed to load modules for course', error);
121→        setSourceModules([]);
122→      }
123→    } finally {
124→      if (sourceModulesRequestIdRef.current === courseRequestId) {
125→        setLoadingSourceModules(false);
126→      }
127→    }
128→  };
129→
130→  const handleSourceModuleSelection = async (nextModuleId: number | null) => {
131→    const lessonRequestId = ++sourceLessonsRequestIdRef.current;
132→
133→    setSelectedSourceModuleId(nextModuleId);
134→    setSourceLessons([]);
135→    setSelectedLessonIds(new Set());
136→
137→    if (nextModuleId == null) {
138→      setLoadingSourceLessons(false);
139→      return;
140→    }
141→
142→    setLoadingSourceLessons(true);
143→    try {
144→      const lessonData = await api.lessonsForModule(nextModuleId);
145→      if (sourceLessonsRequestIdRef.current === lessonRequestId) {
146→        setSourceLessons(lessonData);
147→      }
148→    } catch (error) {
149→      if (sourceLessonsRequestIdRef.current === lessonRequestId) {
150→        console.error('Failed to load lessons for module', error);
151→        setSourceLessons([]);
152→      }
153→    } finally {
154→      if (sourceLessonsRequestIdRef.current === lessonRequestId) {
155→        setLoadingSourceLessons(false);
156→      }
157→    }
158→  };
159→
160→  const onCreateLesson = async (event: FormEvent) => {
161→    event.preventDefault();
162→    if (!numericModuleId || !title.trim()) return;
163→    setCreating(true);
164→    try {
165→      await api.createLesson(numericModuleId, { title: title.trim() });
166→      setTitle('');
167→      refreshLessons();
168→    } catch (error) {
169→      console.error('Failed to create lesson', error);
170→    } finally {
171→      setCreating(false);
172→    }
173→  };
174→
175→  const toggleLesson = (lessonId: number) => {
176→    setSelectedLessonIds((prev) => {
177→      const next = new Set(prev);
178→      if (next.has(lessonId)) next.delete(lessonId);
179→      else next.add(lessonId);
180→      return next;
181→    });
182→  };
183→
184→  const onImportLessons = async () => {
185→    if (!module || !numericModuleId || selectedSourceModuleId == null || selectedLessonIds.size === 0)
186→      return;
187→    setImporting(true);
188→    try {
189→      await api.importIntoCourse(module.courseOfferingId, {
190→        lessonIds: Array.from(selectedLessonIds),
191→        targetModuleId: numericModuleId,
192→      });
193→      setShowImport(false);
194→      await handleSourceCourseSelection(null);
195→      refreshLessons();
196→    } catch (error) {
197→      console.error('Import lessons failed', error);
198→    } finally {
199→      setImporting(false);
200→    }
201→  };
202→
203→  const togglePublish = async (lessonId: number, currentlyPublished: boolean) => {
204→    // Optimistic update via useOptimistic
205→    addLessonOpt((items) =>
206→      items.map((l) => (l.id === lessonId ? { ...l, isPublished: !currentlyPublished } : l)),
207→    );
208→    setPublishingId(lessonId);
209→
210→    try {
211→      const updated = currentlyPublished
212→        ? await api.unpublishLesson(lessonId)
213→        : await api.publishLesson(lessonId);
214→      // Confirm with server response
215→      setLessons((prev) => prev.map((l) => (l.id === lessonId ? updated : l)));
216→    } catch (error) {
217→      console.error('Failed to toggle publish status', error);
218→      // Rollback on error to clear optimistic change
219→      setLessons((prev) =>
220→        prev.map((l) => (l.id === lessonId ? { ...l, isPublished: currentlyPublished } : l)),
221→      );
222→    } finally {
223→      setPublishingId((current) => (current === lessonId ? null : current));
224→    }
225→  };
226→
227→  return (
228→    <div className="min-h-dvh bg-background">
229→      <Nav />
230→      <div className="container mx-auto px-4 py-8 space-y-6">
231→          <Breadcrumb className="mb-6">
232→            <BreadcrumbList>
233→              <BreadcrumbItem>
234→                <BreadcrumbLink asChild>
235→                  <Link to="/instructor">Teaching</Link>
236→                </BreadcrumbLink>
237→              </BreadcrumbItem>
238→              <BreadcrumbSeparator>/</BreadcrumbSeparator>
239→              <BreadcrumbItem>
240→                {course && module ? (
241→                  <BreadcrumbLink asChild>
242→                    <Link to={`/instructor/courses/${module.courseOfferingId}`}>{course.title}</Link>
243→                  </BreadcrumbLink>
244→                ) : (
245→                  <BreadcrumbPage>Course</BreadcrumbPage>
246→                )}
247→              </BreadcrumbItem>
248→              <BreadcrumbSeparator>/</BreadcrumbSeparator>
249→              <BreadcrumbItem>
250→                <BreadcrumbPage>{module?.title || 'Module'}</BreadcrumbPage>
251→              </BreadcrumbItem>
252→            </BreadcrumbList>
253→          </Breadcrumb>
254→          <div className="flex items-center justify-between">
255→            <div>
256→              <h2 className="font-display text-2xl font-semibold text-foreground">Lessons</h2>
257→            </div>
258→            <button
259→              onClick={() => {
260→                if (!showImport) {
261→                  ensureSourceCoursesLoaded();
262→                } else {
263→                  void handleSourceCourseSelection(null);
264→                }
265→                setShowImport((prev) => !prev);
266→              }}
267→              className="btn-secondary"
268→            >
269→              {showImport ? 'Close' : 'Import Lessons'}
270→            </button>
271→          </div>
272→
273→          {showImport && (
274→            <div className="card-editorial p-5 space-y-4">
275→              <div>
276→                <label className="block text-sm font-semibold mb-1 text-foreground">Choose course</label>
277→                <select
278→                  value={selectedSourceCourseId ?? ''}
279→                  onChange={(e) => {
280→                    const nextValue = e.target.value ? Number(e.target.value) : null;
281→                    void handleSourceCourseSelection(nextValue);
282→                  }}
283→                  className="input-field"
284→                >
285→                  <option value="">Select course…</option>
286→                  {availableCourses.map((course) => (
287→                    <option key={course.id} value={course.id}>
288→                      {course.title}
289→                    </option>
290→                  ))}
291→                </select>
292→                {loadingSourceCourses && (
293→                  <p className="mt-2 text-xs text-muted-foreground">Loading courses…</p>
294→                )}
295→                {!loadingSourceCourses && availableCourses.length === 0 && (
296→                  <p className="mt-2 text-xs text-muted-foreground">
297→                    You don't have another course to copy from yet.
298→                  </p>
299→                )}
300→              </div>
301→
302→              {selectedSourceCourseId != null && (
303→                <div>
304→                  <label className="block text-sm font-semibold mb-1 text-foreground">Choose module</label>
305→                  <select
306→                    value={selectedSourceModuleId ?? ''}
307→                    onChange={(e) => {
308→                      const nextValue = e.target.value ? Number(e.target.value) : null;
309→                    void handleSourceModuleSelection(nextValue);
310→                    }}
311→                    className="input-field"
312→                  >
313→                    <option value="">Select module…</option>
314→                    {sourceModules.map((sourceModule) => (
315→                      <option key={sourceModule.id} value={sourceModule.id}>
316→                        {sourceModule.title}
317→                      </option>
318→                    ))}
319→                  </select>
320→                  {loadingSourceModules && (
321→                    <p className="mt-2 text-xs text-muted-foreground">Loading modules…</p>
322→                  )}
323→                  {!loadingSourceModules && sourceModules.length === 0 && (
324→                    <p className="mt-2 text-xs text-muted-foreground">Selected course has no modules yet.</p>
325→                  )}
326→                </div>
327→              )}
328→
329→              {selectedSourceCourseId == null ? (
330→                <p className="text-sm text-muted-foreground">Select a course to begin.</p>
331→              ) : selectedSourceModuleId == null ? (
332→                <p className="text-sm text-muted-foreground">Select a module to preview lessons.</p>
333→              ) : loadingSourceLessons ? (
334→                <p className="text-sm text-muted-foreground">Loading lessons…</p>
335→              ) : sourceLessons.length === 0 ? (
336→                <p className="text-sm text-muted-foreground">Selected module has no lessons yet.</p>
337→              ) : (
338→                <div className="space-y-3">
339→                  <div className="border border-border rounded-xl overflow-hidden">
340→                    <div className="px-4 py-2.5 text-sm font-semibold bg-secondary text-secondary-foreground">
341→                      Lessons
342→                    </div>
343→                    <div className="p-3 space-y-2 bg-card">
344→                      {sourceLessons.map((lesson) => (
345→                        <label
346→                          key={lesson.id}
347→                          className={`flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition ${
348→                            selectedLessonIds.has(lesson.id)
349→                              ? 'border-primary ring-2 ring-primary/30 bg-primary/5'
350→                              : 'border-border hover:border-primary/50'
351→                          }`}
352→                        >
353→                          <input
354→                            type="checkbox"
355→                            className="sr-only"
356→                            checked={selectedLessonIds.has(lesson.id)}
357→                            onChange={() => toggleLesson(lesson.id)}
358→                          />
359→                          <span className="text-sm text-foreground">{lesson.title}</span>
360→                        </label>
361→                      ))}
362→                    </div>
363→                  </div>
364→                  <button
365→                    onClick={onImportLessons}
366→                    disabled={importing || selectedLessonIds.size === 0}
367→                    className="btn-primary"
368→                  >
369→                    {importing ? 'Importing…' : 'Import selected lessons'}
370→                  </button>
371→                </div>
372→              )}
373→            </div>
374→          )}
375→
376→          <form onSubmit={onCreateLesson} className="flex gap-3">
377→            <input
378→              value={title}
379→              onChange={(e) => setTitle(e.target.value)}
380→              placeholder="New lesson title…"
381→              className="input-field flex-1"
382→            />
383→            <button
384→              disabled={creating || !title.trim()}
385→              className="btn-primary"
386→            >
387→              {creating ? 'Adding…' : 'Add Lesson'}
388→            </button>
389→          </form>
390→
391→          {oLessons.length === 0 ? (
392→            <div className="text-muted-foreground">No lessons yet.</div>
393→          ) : (
394→            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
395→              {oLessons.map((lesson, idx) => {
396→                const canPublish = course?.isPublished && module?.isPublished;
397→                const blocked = !lesson.isPublished && !canPublish;
398→                const parentName = !course?.isPublished
399→                  ? course?.title || 'the parent course'
400→                  : !module?.isPublished
401→                  ? module?.title || 'the parent module'
402→                  : null;
403→                const tooltipMessage = blocked && parentName
404→                  ? `${parentName} is unpublished, so you can't publish ${lesson.title}.`
405→                  : null;
406→                const busy = publishingId === lesson.id;
407→                return (
408→                  <div
409→                    key={lesson.id}
410→                    className="card-editorial p-5 hover:shadow-lg transition group cursor-pointer flex flex-col h-full animate-fade-up"
411→                    style={{ animationDelay: `${idx * 50}ms` }}
412→                    onClick={() => navigate(`/instructor/lesson/${lesson.id}`)}
413→                    role="button"
414→                    tabIndex={0}
415→                    onKeyDown={(event) => {
416→                      if (event.key === 'Enter' || event.key === ' ') {
417→                        event.preventDefault();
418→                        navigate(`/instructor/lesson/${lesson.id}`);
419→                      }
420→                    }}
421→                    >
422→                      <div className="flex items-start gap-3">
423→                        <span className="flex-shrink-0 w-8 h-8 rounded-full bg-accent text-accent-foreground flex items-center justify-center font-display font-semibold text-sm">
424→                          {idx + 1}
425→                        </span>
426→                        <div className="flex-1 min-w-0">
427→                          <div className="font-semibold text-foreground group-hover:text-primary transition-colors">{lesson.title}</div>
428→                        </div>
429→                      </div>
430→                      <div className="flex-grow"></div>
431→                    <div className="mt-4 flex justify-end">
432→                      <div onClick={(e) => e.stopPropagation()} onKeyDown={(e) => e.stopPropagation()}>
433→                        <PublishStatusButton
434→                          isPublished={lesson.isPublished}
435→                          pending={busy}
436→                          blockedReason={tooltipMessage}
437→                          onClick={() => {
438→                            if (busy || blocked) return;
439→                            togglePublish(lesson.id, lesson.isPublished);
440→                          }}
441→                        />
442→                      </div>
443→                    </div>
444→                  </div>
445→                );
446→              })}
447→            </div>
448→          )}
449→      </div>
450→      </div>
451→  );
452→}
