import { Link, useLocation, useNavigate } from 'react-router';
import { useLocalUser } from '../hooks/useLocalUser';
import { useEffect, useState } from 'react';
import { api } from '../lib/api';
import { Tooltip, TooltipContent, TooltipTrigger } from './ui/tooltip';
import TourButton from './TourButton';

export default function Nav() {
  const [eduAiStatus, setEduAiStatus] = useState<'loading' | 'connected' | 'disconnected'>('loading');
  const [profileOpen, setProfileOpen] = useState(false);
  const navigate = useNavigate();
  const loc = useLocation();
  const { user, logout } = useLocalUser();
  const isAdminUser = user?.role === 'ADMIN';

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  useEffect(() => {
    if (isAdminUser) {
      // Admins are intentionally scoped away from non-admin endpoints,
      // so skip the shared live-model probe that would otherwise 403.
      setEduAiStatus('connected');
      return;
    }

    let mounted = true;
    api.listAiModels()
      .then(() => {
        if (mounted) setEduAiStatus('connected');
      })
      .catch(() => {
        if (mounted) setEduAiStatus('disconnected');
      });
    return () => { mounted = false; };
  }, [isAdminUser]);

  // Close profile dropdown when clicking outside
  useEffect(() => {
    if (!profileOpen) return;
    const handleClick = () => setProfileOpen(false);
    document.addEventListener('click', handleClick);
    return () => document.removeEventListener('click', handleClick);
  }, [profileOpen]);

  const isStudent = loc.pathname.startsWith('/student');
  const isInstructor = loc.pathname.startsWith('/instructor');
  const isAdmin = loc.pathname.startsWith('/admin');

  return (
    <header className="sticky top-0 z-50 w-full animate-fade-down">
      {/* Editorial masthead bar */}
      <div className="border-b border-border/40 backdrop-blur-xl bg-background/80">
        <div className="mx-auto max-w-7xl px-8">
          <div className="flex h-[4.25rem] items-center justify-between">

            {/* ---- Logo ---- */}
            <Link
              to="/"
              className="group flex items-center gap-3.5 transition-opacity duration-300 hover:opacity-80"
            >
              {/* Logo mark -- three descending bars */}
              <div className="flex h-10 w-10 items-center justify-center rounded-xl border border-primary/20 bg-primary/5 transition-colors duration-300 group-hover:bg-primary/10">
                <div className="flex flex-col items-center gap-[3px]">
                  <div className="h-[3px] w-5 rounded-full bg-primary" />
                  <div className="h-[3px] w-3.5 rounded-full bg-primary/60" />
                  <div className="h-[3px] w-2 rounded-full bg-primary/30" />
                </div>
              </div>

              {/* Wordmark */}
              <span className="font-display text-[1.05rem] font-semibold tracking-[0.12em] uppercase text-foreground">
                AI Tutor
              </span>
            </Link>

            {/* ---- Center: Navigation links ---- */}
            <nav className="flex items-center gap-1">
              {isStudent && (
                <Link
                  to="/student"
                  className="group relative px-4 py-2 text-[0.8125rem] font-medium tracking-wide text-foreground/70 transition-colors duration-200 hover:text-foreground"
                >
                  <span className="flex items-center gap-2">
                    <svg className="h-4 w-4 opacity-60 transition-opacity duration-200 group-hover:opacity-100" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.75}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
                    </svg>
                    My Courses
                  </span>
                  {/* Editorial underline on hover */}
                  <span className="absolute bottom-0.5 left-4 right-4 h-px origin-left scale-x-0 bg-primary/50 transition-transform duration-300 ease-out group-hover:scale-x-100" />
                </Link>
              )}

              <TourButton />

              {isInstructor && (
                <Link
                  to="/instructor"
                  className="group relative px-4 py-2 text-[0.8125rem] font-medium tracking-wide text-foreground/70 transition-colors duration-200 hover:text-foreground"
                >
                  <span className="flex items-center gap-2">
                    <svg className="h-4 w-4 opacity-60 transition-opacity duration-200 group-hover:opacity-100" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.75}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m0 12.75h7.5m-7.5 3H12M10.5 2.25H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
                    </svg>
                    Teaching
                  </span>
                  <span className="absolute bottom-0.5 left-4 right-4 h-px origin-left scale-x-0 bg-primary/50 transition-transform duration-300 ease-out group-hover:scale-x-100" />
                </Link>
              )}

              {isAdmin && (
                <Link
                  to="/admin"
                  className="group relative px-4 py-2 text-[0.8125rem] font-medium tracking-wide text-foreground/70 transition-colors duration-200 hover:text-foreground"
                >
                  <span className="flex items-center gap-2">
                    <svg className="h-4 w-4 opacity-60 transition-opacity duration-200 group-hover:opacity-100" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.75}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 6h9.75M10.5 6a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 11-3 0M10.5 18h9.75m-9.75 0a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 11-3 0m3-6h9.75m-9.75 0a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 11-3 0" />
                    </svg>
                    Admin
                  </span>
                  <span className="absolute bottom-0.5 left-4 right-4 h-px origin-left scale-x-0 bg-primary/50 transition-transform duration-300 ease-out group-hover:scale-x-100" />
                </Link>
              )}
            </nav>

            {/* ---- Right: Status + User ---- */}
            {user && (
              <div className="flex items-center gap-5">
                {/* EduAI Status Badge */}
                <Tooltip>
                  <TooltipTrigger asChild>
                    <div
                      className={`tag flex items-center gap-2 cursor-default transition-colors duration-200 ${
                        eduAiStatus === 'loading'
                          ? 'bg-muted text-muted-foreground'
                          : eduAiStatus === 'connected'
                          ? 'tag-accent'
                          : 'bg-red-500/10 text-red-600 dark:text-red-400'
                      }`}
                    >
                      <span className={`h-1.5 w-1.5 rounded-full ${
                        eduAiStatus === 'loading'
                          ? 'bg-muted-foreground animate-pulse'
                          : eduAiStatus === 'connected'
                          ? 'bg-accent-foreground'
                          : 'bg-red-500'
                      }`} />
                      <span className="hidden sm:inline">EduAI</span>
                    </div>
                  </TooltipTrigger>
                  <TooltipContent>
                    {eduAiStatus === 'loading'
                      ? 'Checking EduAI connection...'
                      : eduAiStatus === 'connected'
                      ? 'EduAI is connected'
                      : 'EduAI is not connected'}
                  </TooltipContent>
                </Tooltip>

                {/* Thin vertical divider */}
                <div className="h-5 w-px bg-border" />

