                      <span className="text-[0.8125rem] font-medium leading-tight text-foreground">
                        {user.name}
                      </span>
                      <span className="font-mono text-[10px] uppercase tracking-widest text-muted-foreground">
                        {user.role}
                      </span>
                    </div>
                    {/* Chevron */}
