11→type PublishStatusButtonProps = {
12→  isPublished: boolean;
13→  pending?: boolean;
14→  blockedReason?: string | null;
15→  onClick?: (event: MouseEvent<HTMLButtonElement>) => void;
16→  className?: string;
17→};
18→
19→export function PublishStatusButton({
20→  isPublished,
21→  pending = false,
22→  blockedReason,
23→  onClick,
24→  className,
25→}: PublishStatusButtonProps) {
26→  const label = pending ? "Saving…" : isPublished ? "Published" : "Unpublished";
27→  const blocked = Boolean(blockedReason);
28→
29→  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
30→    if (blocked) {
31→      event.preventDefault();
32→      return;
33→    }
34→    onClick?.(event);
35→  };
36→
37→  const button = (
38→    <Button
39→      type="button"
40→      size="sm"
41→      aria-disabled={blocked}
42→      className={cn(
43→        "px-3 py-1.5 text-xs font-semibold transition",
44→        isPublished
45→          ? "bg-emerald-400 text-emerald-900 hover:bg-emerald-500 dark:bg-emerald-500/80 dark:text-white dark:hover:bg-emerald-500/70"
46→          : "bg-gray-200 text-gray-700 hover:bg-gray-300 dark:bg-gray-800 dark:text-gray-200 dark:hover:bg-gray-700",
47→        blocked && "cursor-not-allowed opacity-60 hover:bg-gray-300/80 dark:hover:bg-gray-700/80",
48→        className,
49→      )}
50→      onClick={handleClick}
51→    >
52→      {label}
53→    </Button>
54→  );
55→
56→  if (!blockedReason) {
57→    return button;
58→  }
59→
60→  return (
61→    <TooltipProvider delayDuration={150}>
62→      <Tooltip>
63→        <TooltipTrigger asChild>{button}</TooltipTrigger>
64→        <TooltipContent>{blockedReason}</TooltipContent>
65→      </Tooltip>
66→    </TooltipProvider>
