 57→export async function clientLoader({ params }: Route.ClientLoaderArgs) {
 58→  await requireClientUser('PROFESSOR');
 59→  const lessonId = Number(params.lessonId);
 60→  if (!Number.isFinite(lessonId)) {
 61→    throw new Response('Invalid lesson id', { status: 400 });
 62→  }
 63→
 64→  const [lesson, activities] = await Promise.all([
 65→    api.lessonById(lessonId) as Promise<Lesson>,
 66→    api.activitiesForLesson(lessonId) as Promise<Activity[]>,
 67→  ]);
 68→
 69→  let module: ModuleDetail | null = null;
 70→  let course: Course | null = null;
 71→  if (lesson.moduleId) {
 72→    module = (await api.moduleById(lesson.moduleId)) as ModuleDetail;
 73→    if (module.courseOfferingId) {
 74→      course = (await api.courseById(module.courseOfferingId)) as Course;
 75→    }
 76→  }
 77→
 78→  return { course, module, lesson, activities };
 79→}
