153→  };
154→
155→  const endModeUpdate = (activityId: number) => {
156→    let shouldClear = false;
157→    setUpdatingModesFor((current) => {
158→      if (current !== activityId) {
159→        return current;
160→      }
161→      shouldClear = true;
162→      return null;
163→    });
164→    if (shouldClear) {
165→      if (modeSavingTimeoutRef.current) {
