 21→  busy?: boolean;
 22→}) {
 23→  const [submitting, setSubmitting] = useState(false);
 24→  const [mappings, setMappings] = useState<Mapping[]>(() =>
 25→    missing.map((m) => ({ fromTopicId: m.id, toTopicId: '' })),
 26→  );
 27→
 28→  // Reset mapping rows when missing list changes or dialog reopens
 29→  const prevOpen = useMemo(() => open, [open]);
 30→  if (prevOpen && mappings.length !== missing.length) {
 31→    // Ensure we have one mapping per missing topic
 32→    const byFrom = new Map(mappings.map((m) => [m.fromTopicId, m.toTopicId]));
 33→    setMappings(missing.map((m) => ({ fromTopicId: m.id, toTopicId: byFrom.get(m.id) ?? '' })));
 34→  }
 35→
 36→  // Keep mappings in sync when missing changes
 37→  const missingIds = useMemo(() => new Set(missing.map((m) => m.id)), [missing]);
 38→  const mappingByFrom = useMemo(() => {
 39→    const map = new Map<number, string>();
 40→    for (const m of mappings) map.set(m.fromTopicId, m.toTopicId);
 41→    return map;
 42→  }, [mappings]);
 43→
 44→  const options = useMemo(() => topics, [topics]);
 45→
 46→  const allSelected = mappings.length > 0 && mappings.every((m) => m.toTopicId !== '');
 47→
 48→  const handleChange = (fromTopicId: number, value: string) => {
 49→    const toTopicId = value || '';
 50→    setMappings((prev) =>
 51→      prev.map((m) => (m.fromTopicId === fromTopicId ? { ...m, toTopicId } : m)),
 52→    );
 53→  };
 54→
 55→  const onSubmit = async () => {
 56→    if (!allSelected || submitting || busy) return;
 57→    setSubmitting(true);
 58→    try {
 59→      const payload = mappings
 60→        .filter((m) => m.toTopicId !== '')
 61→        .map((m) => ({ fromTopicId: m.fromTopicId, toTopicId: Number(m.toTopicId) }));
 62→      await onApply(payload);
 63→      onClose();
 64→    } finally {
 65→      setSubmitting(false);
 66→    }
 67→  };
 68→
 69→  if (!open) return null;
 70→
 71→  return (
 72→    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
 73→      <div className="w-[min(720px,95vw)] rounded-2xl bg-white dark:bg-gray-950 p-6 shadow-xl border border-gray-200 dark:border-gray-800">
 74→        <div className="text-lg font-semibold">Review topic changes</div>
 75→        <p className="mt-1 text-sm text-gray-600 dark:text-gray-300">
 76→          Some topics in this course are no longer present in EduAI. Please map them to existing topics so activities remain correctly tagged.
 77→        </p>
 78→
 79→        <div className="mt-4 space-y-3 max-h-[50vh] overflow-y-auto pr-1">
 80→          {missing.map((m) => (
 81→            <div key={m.id} className="rounded-xl border border-gray-200 dark:border-gray-800 p-3">
 82→              <div className="text-sm">
 83→                <span className="font-semibold">{m.name}</span> no longer exists. Choose a replacement topic:
 84→              </div>
 85→              <div className="mt-2">
 86→                <select
 87→                  className="w-full sm:w-80 px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-700 bg-transparent"
 88→                  value={mappingByFrom.get(m.id) ?? ''}
 89→                  onChange={(e) => handleChange(m.id, e.target.value)}
 90→                >
 91→                  <option value="">Select replacement…</option>
 92→                  {options
 93→                    .filter((t) => t.id !== m.id)
 94→                    .map((t) => (
 95→                      <option key={t.id} value={t.id}>
 96→                        {t.name}
 97→                      </option>
 98→                    ))}
 99→                </select>
100→              </div>
101→            </div>
102→          ))}
103→        </div>
104→
105→        <div className="mt-5 flex justify-end gap-2">
106→          <button
107→            type="button"
108→            onClick={onClose}
109→            className="px-4 py-2 rounded-xl border border-gray-300 dark:border-gray-700 text-sm"
110→            disabled={submitting || busy}
111→          >
112→            Cancel
113→          </button>
114→          <button
115→            type="button"
116→            onClick={onSubmit}
117→            disabled={!allSelected || submitting || busy}
118→            className="px-4 py-2 rounded-xl bg-indigo-600 text-white text-sm font-semibold disabled:opacity-50"
119→          >
120→            {submitting ? 'Applying…' : 'Apply mappings'}
121→          </button>
122→        </div>
123→      </div>
124→    </div>
125→  );
126→}
127→

