import { useMemo } from 'react';
import { Link, useNavigate } from 'react-router';
import Nav from '../components/Nav';
import { ProgressBarFromData } from '../components/ProgressBar';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import type { Course, Module } from '../lib/types';
import type { Route } from './+types/student.course';
import api from '~/lib/api';
import { requireClientUser } from '~/lib/client-auth';

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('STUDENT');
  const courseId = Number(params.courseId);
  if (!Number.isFinite(courseId)) {
    throw new Response('Invalid course id', { status: 400 });
  }

  const [course, modules] = await Promise.all([
    api.courseById(courseId) as Promise<Course>,
    api.modulesForCourse(courseId) as Promise<Module[]>,
  ]);

  return { course, modules };
}

export default function StudentCourseModules({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const { course, modules } = loaderData;
  const moduleList = useMemo(() => modules ?? [], [modules]);

  return (
    <div className="min-h-dvh bg-background">
      <Nav />

      {/* Subtle background texture */}
      <div className="fixed inset-0 -z-10 pointer-events-none">
        <div className="absolute inset-0 noise" />
        <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-primary/[0.04] rounded-full blur-[120px] -translate-y-1/3 translate-x-1/4" />
        <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-accent/[0.04] rounded-full blur-[120px] translate-y-1/3 -translate-x-1/4" />
      </div>

      <div className="max-w-4xl mx-auto px-6 sm:px-8 py-10">
        {/* Breadcrumb */}
        <Breadcrumb className="mb-10 animate-fade-in">
          <BreadcrumbList className="text-sm tracking-wide">
            <BreadcrumbItem>
              <BreadcrumbLink asChild>
                <Link to="/student" className="text-muted-foreground hover:text-foreground transition-colors duration-200">
                  My Courses
                </Link>
              </BreadcrumbLink>
            </BreadcrumbItem>
            <BreadcrumbSeparator className="text-border/60 mx-1">/</BreadcrumbSeparator>
            <BreadcrumbItem>
              <BreadcrumbPage className="font-medium text-foreground">
                {course?.title || 'Course'}
              </BreadcrumbPage>
            </BreadcrumbItem>
          </BreadcrumbList>
        </Breadcrumb>

        {/* Page header */}
        <header className="mb-14 animate-fade-up">
          <div className="mb-4">
            <span className="tag tag-primary text-[10px] tracking-[0.15em] mb-3 inline-block">
              Course
            </span>
            <h1 className="font-display text-4xl sm:text-5xl font-bold tracking-tight text-foreground leading-[1.1]">
              {course?.title || 'Course'}
            </h1>
          </div>
          {course?.description && (
            <p className="text-muted-foreground text-base leading-relaxed max-w-2xl mt-3">
              {course.description}
            </p>
          )}
          <div className="mt-6 pt-6 border-t border-border/60">
            <span className="font-mono text-sm text-muted-foreground tracking-wide">
              {String(moduleList.length).padStart(2, '0')}{' '}
              <span className="text-border mx-1">/</span>{' '}
              {moduleList.length === 1 ? 'Module' : 'Modules'}
            </span>
          </div>
        </header>

        {/* Module list */}
        {moduleList.length === 0 ? (
          <div className="animate-fade-up delay-150">
            <div className="card-editorial px-8 py-16 text-center max-w-md mx-auto">
              <div className="w-12 h-12 mx-auto mb-5 rounded-xl bg-secondary flex items-center justify-center">
                <svg className="w-6 h-6 text-muted-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 7.125C2.25 6.504 2.754 6 3.375 6h6c.621 0 1.125.504 1.125 1.125v3.75c0 .621-.504 1.125-1.125 1.125h-6a1.125 1.125 0 01-1.125-1.125v-3.75zM14.25 8.625c0-.621.504-1.125 1.125-1.125h5.25c.621 0 1.125.504 1.125 1.125v8.25c0 .621-.504 1.125-1.125 1.125h-5.25a1.125 1.125 0 01-1.125-1.125v-8.25zM3.75 16.125c0-.621.504-1.125 1.125-1.125h5.25c.621 0 1.125.504 1.125 1.125v2.25c0 .621-.504 1.125-1.125 1.125h-5.25a1.125 1.125 0 01-1.125-1.125v-2.25z" />
                </svg>
              </div>
              <h2 className="font-display text-lg font-bold text-foreground mb-2">
                No modules yet
              </h2>
              <p className="text-muted-foreground text-sm leading-relaxed">
                This course doesn't have any modules available. Check back later.
              </p>
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            {moduleList.map((module, index) => (
              <button
                key={module.id}
                onClick={() => navigate(`/student/module/${module.id}`)}
                className="group w-full text-left card-editorial transition-all duration-300 hover:shadow-lg hover:border-primary/20 glow animate-fade-up"
                style={{ animationDelay: `${100 + index * 60}ms` }}
                data-tour={index === 0 ? 'student-module-card-first' : undefined}
                data-tour-route={index === 0 ? `/student/module/${module.id}` : undefined}
              >
                <div className="flex items-center gap-5 sm:gap-6 p-5 sm:p-6">
                  {/* Module index */}
                  <div className="flex-shrink-0 w-12 h-12 rounded-xl bg-primary/[0.08] flex items-center justify-center transition-colors duration-300 group-hover:bg-primary/[0.14]">
                    <span className="font-mono text-sm font-semibold text-primary tabular-nums">
                      {String(index + 1).padStart(2, '0')}
                    </span>
                  </div>

                  {/* Module content */}
                  <div className="flex-1 min-w-0">
                    <h3 className="font-display text-lg font-bold text-foreground group-hover:text-primary transition-colors duration-200 truncate">
                      {module.title}
                    </h3>
                    {module.description && (
                      <p className="text-sm text-muted-foreground mt-0.5 line-clamp-1">
                        {module.description}
                      </p>
                    )}

                    {/* Progress */}
                    {module.progress && module.progress.total > 0 && (
                      <div className="mt-3 max-w-xs">
                        <ProgressBarFromData progress={module.progress} size="sm" showLabel />
                      </div>
                    )}
                  </div>

                  {/* Arrow indicator */}
                  <div className="flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center text-muted-foreground/40 transition-all duration-300 group-hover:text-primary group-hover:translate-x-0.5">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                    </svg>
                  </div>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

