  1→import type { FormEvent } from 'react';
  2→import { useMemo, useState } from 'react';
  3→import api from '../lib/api';
  4→import { useCourseTopicsContext } from '../hooks/useCourseTopics';
  5→interface AddActivityPanelProps {
  6→  lessonId: number;
  7→  onActivityCreated: () => void;
  8→}
  9→
 10→export default function AddActivityPanel({
 11→  lessonId,
 12→  onActivityCreated,
 13→}: AddActivityPanelProps) {
 14→  const { topics, loading: loadingTopics, error: topicsError } = useCourseTopicsContext();
 15→  const [type, setType] = useState<'MCQ' | 'SHORT_TEXT'>('MCQ');
 16→  const [question, setQuestion] = useState('');
 17→  const [choices, setChoices] = useState<string[]>(['', '', '', '']);
 18→  const [correct, setCorrect] = useState(0);
 19→  const [hasSelectedCorrect, setHasSelectedCorrect] = useState(false);
 20→  const [textAnswer, setTextAnswer] = useState('');
 21→  const [hint, setHint] = useState('');
 22→  const [busy, setBusy] = useState(false);
 23→
 24→  const [selectedMainTopicId, setSelectedMainTopicId] = useState<number | ''>('');
 25→  const [selectedSecondaryTopicIds, setSelectedSecondaryTopicIds] = useState<number[]>([]);
 26→  const [topicSelectionError, setTopicSelectionError] = useState<string | null>(null);
 27→
 28→  const [enableTeachMode, setEnableTeachMode] = useState(true);
 29→  const [enableGuideMode, setEnableGuideMode] = useState(true);
 30→
 31→  // Adjust main topic selection during render when topics change
 32→  const [prevTopics, setPrevTopics] = useState(topics);
 33→  if (topics !== prevTopics) {
 34→    setPrevTopics(topics);
 35→
 36→    if (topics.length === 0) {
 37→      if (selectedMainTopicId !== '') setSelectedMainTopicId('');
 38→      if (selectedSecondaryTopicIds.length > 0) setSelectedSecondaryTopicIds([]);
 39→    } else {
 40→      // If current selection is invalid, default to first topic
 41→      if (selectedMainTopicId === '' || !topics.some((topic) => topic.id === selectedMainTopicId)) {
 42→        setSelectedMainTopicId(topics[0].id);
 43→      }
 44→    }
 45→  }
 46→
 47→  const availableSecondaryTopics = useMemo(
 48→    () =>
 49→      topics.filter(
 50→        (topic) => topic.id !== (typeof selectedMainTopicId === 'number' ? selectedMainTopicId : -1),
 51→      ),
 52→    [topics, selectedMainTopicId],
 53→  );
 54→
 55→
 56→
 57→  const toggleSecondaryForNew = (topicId: number) => {
 58→    setSelectedSecondaryTopicIds((prev) => {
 59→      if (prev.includes(topicId)) {
 60→        return prev.filter((id) => id !== topicId);
 61→      }
 62→      return [...prev, topicId];
 63→    });
 64→  };
 65→
 66→  const handleAddActivity = async (event: FormEvent) => {
 67→    event.preventDefault();
 68→    if (!question.trim()) return;
 69→    if (selectedMainTopicId === '') {
 70→      setTopicSelectionError('Select a main topic to continue.');
 71→      return;
 72→    }
 73→
 74→    if (!enableTeachMode && !enableGuideMode) {
 75→      alert('At least one AI mode must be enabled');
 76→      return;
 77→    }
 78→
 79→    setBusy(true);
 80→    setTopicSelectionError(null);
 81→
 82→    const mainTopicId = Number(selectedMainTopicId);
 83→    const secondaryIds = selectedSecondaryTopicIds.filter((id) => id !== mainTopicId);
 84→
 85→    try {
 86→      if (type === 'MCQ') {
 87→        await api.createActivity(lessonId, {
 88→          question: question.trim(),
 89→          type,
 90→          options: { choices },
 91→          answer: { correctIndex: correct },
 92→          hints: hint.trim() ? [hint.trim()] : [],
 93→          mainTopicId,
 94→          secondaryTopicIds: secondaryIds,
 95→          enableTeachMode,
 96→          enableGuideMode,
 97→        });
 98→      } else {
 99→        await api.createActivity(lessonId, {
100→          question: question.trim(),
101→          type,
102→          answer: { text: textAnswer.trim() },
103→          hints: hint.trim() ? [hint.trim()] : [],
104→          mainTopicId,
105→          secondaryTopicIds: secondaryIds,
106→          enableTeachMode,
107→          enableGuideMode,
108→        });
109→      }
110→
111→      setQuestion('');
112→      setChoices(['', '', '', '']);
113→      setCorrect(0);
114→      setHasSelectedCorrect(false);
115→      setTextAnswer('');
116→      setHint('');
117→      setSelectedSecondaryTopicIds([]);
118→      setEnableTeachMode(true);
119→      setEnableGuideMode(true);
120→      onActivityCreated();
121→    } catch (error) {
122→      console.error('Failed to add activity', error);
123→    } finally {
124→      setBusy(false);
125→    }
126→  };
127→
128→  return (
129→    <form
130→      onSubmit={handleAddActivity}
131→      className="card-editorial p-5 space-y-4"
132→    >
133→      <div className="font-semibold text-foreground">Add Activity</div>
134→      <div className="flex gap-2 text-sm">
135→        <label
136→          className={`px-3 py-1.5 rounded-full cursor-pointer transition ${
137→            type === 'MCQ' ? 'bg-primary text-primary-foreground' : 'bg-secondary text-secondary-foreground hover:bg-muted'
138→          }`}
139→        >
140→          <input
141→            type="radio"
142→            name="type"
143→            className="sr-only"
144→            checked={type === 'MCQ'}
145→            onChange={() => setType('MCQ')}
146→          />
147→          MCQ
148→        </label>
149→        <label
150→          className={`px-3 py-1.5 rounded-full cursor-pointer transition ${
151→            type === 'SHORT_TEXT' ? 'bg-primary text-primary-foreground' : 'bg-secondary text-secondary-foreground hover:bg-muted'
152→          }`}
153→        >
154→          <input
155→            type="radio"
156→            name="type"
157→            className="sr-only"
158→            checked={type === 'SHORT_TEXT'}
159→            onChange={() => setType('SHORT_TEXT')}
160→          />
161→          Short answer
162→        </label>
163→      </div>
164→
165→      <div className="space-y-2">
166→        <label className="text-xs font-semibold text-muted-foreground">
167→          Question prompt
168→        </label>
169→        <textarea
170→          value={question}
171→          onChange={(event) => setQuestion(event.target.value)}
172→          placeholder="Write the question learners should answer…"
173→          rows={4}
174→          className="input-field"
175→        />
176→      </div>
177→
178→      {type === 'MCQ' ? (
179→        <div className="space-y-3">
180→          <div className="text-xs font-semibold text-muted-foreground">Choices</div>
181→          <div className="space-y-2">
182→            {choices.map((choice, index) => {
183→              const isSelected = correct === index && hasSelectedCorrect;
184→              return (
185→                <label
186→                  key={index}
187→                  className={`flex items-center gap-3 px-3 py-2.5 rounded-xl border cursor-pointer transition focus-within:outline-none bg-card ${
188→                    isSelected
189→                      ? 'border-primary ring-2 ring-primary/20'
190→                      : 'border-border hover:border-primary/50'
191→                  }`}
192→                >
193→                  <input
194→                    type="radio"
195→                    name="correct"
196→                    className="sr-only"
197→                    checked={correct === index}
198→                    onChange={() => {
199→                      setCorrect(index);
200→                      setHasSelectedCorrect(true);
201→                    }}
202→                  />
203→                  <span className="text-xs font-semibold text-muted-foreground w-6">{String.fromCharCode(65 + index)}.</span>
204→                  <input
205→                    value={choice}
206→                    onChange={(event) =>
207→                      setChoices((prev) => {
208→                        const next = [...prev];
209→                        next[index] = event.target.value;
210→                        return next;
211→                      })
212→                    }
213→                    placeholder="Option text"
214→                    className="flex-1 min-w-0 border-none bg-transparent focus:outline-none text-foreground placeholder:text-muted-foreground"
215→                  />
216→                </label>
217→              );
218→            })}
219→          </div>
220→        </div>
221→      ) : (
222→        <div className="space-y-2">
223→          <label className="text-xs font-semibold text-muted-foreground">
224→            Expected answer
225→          </label>
226→          <input
227→            value={textAnswer}
228→            onChange={(event) => setTextAnswer(event.target.value)}
229→            placeholder="Ideal short response…"
230→            className="input-field"
231→          />
232→        </div>
233→      )}
234→
235→      <div className="space-y-2">
236→        <label className="text-xs font-semibold text-muted-foreground">Main topic</label>
237→        <select
238→          value={selectedMainTopicId === '' ? '' : selectedMainTopicId}
239→          onChange={(event) => {
240→            const newMainTopicId = event.target.value ? Number(event.target.value) : '';
241→            setSelectedMainTopicId(newMainTopicId);
242→            // Remove new main topic from secondary topics if it was selected there
243→            if (typeof newMainTopicId === 'number') {
244→              setSelectedSecondaryTopicIds((prev) => prev.filter((id) => id !== newMainTopicId));
245→            }
246→          }}
247→          disabled={loadingTopics || topics.length === 0}
248→          className="input-field text-sm"
249→        >
250→          <option value="">Select a topic…</option>
251→          {topics.map((topic) => (
252→            <option key={topic.id} value={topic.id}>
253→              {topic.name}
254→            </option>
255→          ))}
256→        </select>
257→        {topicSelectionError && (
258→          <p className="text-xs text-destructive">{topicSelectionError}</p>
259→        )}
260→      </div>
261→
262→      <div className="space-y-2">
263→        <span className="text-xs font-semibold text-muted-foreground block">
264→          Secondary topics (optional)
265→        </span>
266→        <div className="flex flex-wrap gap-2">
267→          {availableSecondaryTopics.length === 0 ? (
268→            <span className="text-xs text-muted-foreground">No other topics available.</span>
269→          ) : (
270→            availableSecondaryTopics.map((topic) => {
271→              const checked = selectedSecondaryTopicIds.includes(topic.id);
272→              return (
273→                <label
274→                  key={topic.id}
275→                  className={`flex items-center gap-2 px-3 py-1.5 rounded-full border text-xs cursor-pointer transition ${
276→                    checked
277→                      ? 'border-transparent bg-accent text-accent-foreground shadow-sm'
278→                      : 'border-border bg-secondary hover:border-accent/50'
279→                  }`}
280→                >
281→                  <input
282→                    type="checkbox"
283→                    className="sr-only"
284→                    checked={checked}
285→                    onChange={() => toggleSecondaryForNew(topic.id)}
286→                  />
287→                  {topic.name}
288→                </label>
289→              );
290→            })
291→          )}
292→        </div>
293→      </div>
294→
295→      <div className="space-y-2 pt-1">
296→        <span className="text-xs font-semibold text-muted-foreground block">
297→          AI Study Buddy Modes
298→        </span>
299→        <p className="text-xs text-muted-foreground">
300→          Choose which AI assistance modes students can use for this activity.
301→        </p>
302→        <div className="space-y-2">
303→          <label className="flex items-center gap-2 cursor-pointer">
304→            <input
305→              type="checkbox"
306→              checked={enableTeachMode}
307→              onChange={(e) => {
308→                if (!e.target.checked && !enableGuideMode) {
309→                  alert('At least one AI mode must be enabled');
310→                  return;
311→                }
312→                setEnableTeachMode(e.target.checked);
313→              }}
314→              className="rounded border-primary/50 text-primary focus:ring-primary"
315→            />
316→            <span className="text-sm text-foreground">Teach me - Conceptual learning about topics</span>
317→          </label>
318→          <label className="flex items-center gap-2 cursor-pointer">
319→            <input
320→              type="checkbox"
321→              checked={enableGuideMode}
322→              onChange={(e) => {
323→                if (!e.target.checked && !enableTeachMode) {
324→                  alert('At least one AI mode must be enabled');
325→                  return;
326→                }
327→                setEnableGuideMode(e.target.checked);
328→              }}
