  1→import type { FormEvent } from 'react';
  2→import { useMemo, useState } from 'react';
  3→import type { Activity } from '../lib/types';
  4→import {
  5→  activityToFormValues,
  6→  buildUpdatePayload,
  7→  ensureChoiceSlots,
  8→  type ActivityFormValues,
  9→} from '../lib/activityForm';
 10→
 11→type EditActivityPanelProps = {
 12→  activity: Activity;
 13→  busy?: boolean;
 14→  error?: string | null;
 15→  onSubmit: (payload: {
 16→    title: string | null;
 17→    instructionsMd: string;
 18→    question: string;
 19→    type: 'MCQ' | 'SHORT_TEXT';
 20→    options: string[] | null;
 21→    answer: any;
 22→    hints: string[];
 23→  }) => Promise<void> | void;
 24→  onCancel: () => void;
 25→};
 26→
 27→export default function EditActivityPanel({ activity, busy, error, onSubmit, onCancel }: EditActivityPanelProps) {
 28→  const [values, setValues] = useState<ActivityFormValues>(() => activityToFormValues(activity));
 29→  const [formError, setFormError] = useState<string | null>(null);
 30→  const [prevActivity, setPrevActivity] = useState(activity);
 31→
 32→  if (prevActivity !== activity) {
 33→    setPrevActivity(activity);
 34→    setValues(activityToFormValues(activity));
 35→    setFormError(null);
 36→  }
 37→
 38→  const paddedChoices = useMemo(() => ensureChoiceSlots(values.choices), [values.choices]);
 39→  const choiceLabels = useMemo(
 40→    () => paddedChoices.map((_, index) => String.fromCharCode(65 + index)),
 41→    [paddedChoices],
 42→  );
 43→
 44→  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
 45→    event.preventDefault();
 46→    const { payload, error: buildError } = buildUpdatePayload(values);
 47→    if (buildError || !payload) {
 48→      setFormError(buildError ?? 'Invalid activity data.');
 49→      return;
 50→    }
 51→    setFormError(null);
 52→    await onSubmit(payload);
 53→  };
 54→
 55→  return (
 56→    <form
 57→      onSubmit={handleSubmit}
 58→      className="rounded-xl border border-primary/30 bg-primary/5 p-3 space-y-3"
 59→    >
 60→      <div className="space-y-2">
 61→        <label className="text-xs font-semibold text-muted-foreground">
 62→          Internal title (optional)
 63→        </label>
 64→        <input
 65→          value={values.title}
 66→          onChange={(event) => setValues((prev) => ({ ...prev, title: event.target.value }))}
 67→          placeholder="Optional internal label"
 68→          className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground text-sm focus:outline-none focus:ring-2 focus:ring-primary/50"
 69→        />
 70→      </div>
 71→
 72→      <div className="space-y-2">
 73→        <label className="text-xs font-semibold text-muted-foreground">
 74→          Question prompt
 75→        </label>
 76→        <textarea
 77→          value={values.question}
 78→          onChange={(event) => setValues((prev) => ({ ...prev, question: event.target.value }))}
 79→          rows={4}
 80→          className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground text-sm focus:outline-none focus:ring-2 focus:ring-primary/50"
 81→        />
 82→      </div>
 83→
 84→      <div className="flex gap-2 text-sm">
 85→        <label
 86→          className={`px-3 py-1 rounded-full cursor-pointer transition ${
 87→            values.type === 'MCQ' ? 'bg-primary/20 text-primary font-medium' : 'bg-secondary text-muted-foreground hover:bg-secondary/80'
 88→          }`}
 89→        >
 90→          <input
 91→            type="radio"
 92→            name="edit-type"
 93→            className="sr-only"
 94→            checked={values.type === 'MCQ'}
 95→            onChange={() =>
 96→              setValues((prev) => ({
 97→                ...prev,
 98→                type: 'MCQ',
 99→                choices: ensureChoiceSlots(prev.choices),
100→                correctIndex: 0,
101→              }))
102→            }
103→          />
104→          MCQ
105→        </label>
106→        <label
107→          className={`px-3 py-1 rounded-full cursor-pointer transition ${
108→            values.type === 'SHORT_TEXT'
109→              ? 'bg-primary/20 text-primary font-medium'
110→              : 'bg-secondary text-muted-foreground hover:bg-secondary/80'
111→          }`}
112→        >
113→          <input
114→            type="radio"
115→            name="edit-type"
116→            className="sr-only"
117→            checked={values.type === 'SHORT_TEXT'}
118→            onChange={() =>
119→              setValues((prev) => ({
120→                ...prev,
121→                type: 'SHORT_TEXT',
122→              }))
123→            }
124→          />
125→          Short answer
126→        </label>
127→      </div>
128→
129→      {values.type === 'MCQ' ? (
130→        <div className="space-y-3">
131→          <div className="text-xs font-semibold text-muted-foreground">Choices</div>
132→          <div className="space-y-2">
133→            {paddedChoices.map((choice, index) => {
134→              const isSelected = values.correctIndex === index;
135→              return (
136→                <label
137→                  key={index}
138→                  className={`flex items-center gap-3 px-3 py-2 rounded-xl border cursor-pointer transition focus-within:outline-none bg-background ${
139→                    isSelected
140→                      ? 'border-accent-foreground/50 bg-accent/30'
141→                      : 'border-border hover:border-primary/30'
142→                  }`}
143→                >
144→                  <input
145→                    type="radio"
146→                    name="correct-choice"
147→                    className="sr-only"
148→                    checked={isSelected}
149→                    onChange={() =>
150→                      setValues((prev) => ({
151→                        ...prev,
152→                        correctIndex: index,
153→                      }))
154→                    }
155→                  />
156→                  <span className="text-xs font-semibold text-muted-foreground w-6">
157→                    {choiceLabels[index] ?? String.fromCharCode(65 + index)}.
158→                  </span>
159→                  <input
160→                    value={choice}
161→                    onChange={(event) =>
162→                      setValues((prev) => {
163→                        const nextChoices = ensureChoiceSlots(prev.choices);
164→                        nextChoices[index] = event.target.value;
165→                        return { ...prev, choices: nextChoices };
166→                      })
167→                    }
168→                    placeholder="Option text"
169→                    className="flex-1 min-w-0 border-none bg-transparent text-foreground focus:outline-none"
170→                  />
171→                  {paddedChoices.length > 2 && (
172→                    <button
173→                      type="button"
174→                      onClick={() =>
175→                        setValues((prev) => {
176→                          if (prev.choices.length <= 2) return prev;
177→                          const nextChoices = ensureChoiceSlots(prev.choices).filter(
178→                            (_, idx) => idx !== index,
179→                          );
180→                          let nextCorrect = prev.correctIndex;
181→                          if (index === prev.correctIndex) {
182→                            nextCorrect = Math.max(0, nextCorrect - 1);
183→                          } else if (index < prev.correctIndex) {
184→                            nextCorrect = Math.max(0, nextCorrect - 1);
185→                          }
186→                          nextCorrect = Math.min(nextCorrect, nextChoices.length - 1);
187→                          return {
188→                            ...prev,
189→                            choices: ensureChoiceSlots(nextChoices),
190→                            correctIndex: nextCorrect,
191→                          };
192→                        })
193→                      }
194→                      className="text-[0.7rem] text-destructive hover:text-destructive/80"
195→                    >
196→                      Remove
197→                    </button>
198→                  )}
199→                </label>
200→              );
201→            })}
202→          </div>
203→          <button
204→            type="button"
205→            onClick={() =>
206→              setValues((prev) => ({
207→                ...prev,
208→                choices: [...ensureChoiceSlots(prev.choices), ''],
209→              }))
210→            }
211→            className="text-xs font-medium text-primary hover:text-primary/80"
212→          >
213→            Add choice
214→          </button>
215→        </div>
216→      ) : (
217→        <div className="space-y-2">
218→          <label className="text-xs font-semibold text-muted-foreground">
219→            Expected answer
220→          </label>
221→          <input
222→            value={values.textAnswer}
223→            onChange={(event) => setValues((prev) => ({ ...prev, textAnswer: event.target.value }))}
224→            placeholder="Ideal short response"
225→            className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground text-sm focus:outline-none focus:ring-2 focus:ring-primary/50"
226→          />
227→        </div>
228→      )}
229→
230→      <div className="space-y-2">
231→        <label className="text-xs font-semibold text-muted-foreground">
232→          Instructions (optional)
233→        </label>
234→        <textarea
235→          value={values.instructionsMd}
236→          onChange={(event) => setValues((prev) => ({ ...prev, instructionsMd: event.target.value }))}
237→          rows={3}
238→          className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground text-sm focus:outline-none focus:ring-2 focus:ring-primary/50"
239→        />
240→      </div>
241→
242→      <div className="space-y-2">
243→        <label className="text-xs font-semibold text-muted-foreground">
244→          Hints (one per line)
245→        </label>
246→        <textarea
247→          value={values.hintsText}
248→          onChange={(event) => setValues((prev) => ({ ...prev, hintsText: event.target.value }))}
249→          rows={3}
250→          className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground text-sm focus:outline-none focus:ring-2 focus:ring-primary/50"
251→        />
252→      </div>
253→
254→      {(formError || error) && (
255→        <p className="text-xs text-destructive">{formError || error}</p>
256→      )}
257→
258→      <div className="flex justify-end gap-2">
259→        <button
260→          type="button"
261→          className="px-3 py-2 rounded-lg border border-border text-foreground text-sm hover:bg-secondary transition"
262→          onClick={() => {
263→            setValues(activityToFormValues(activity));
264→            setFormError(null);
265→            onCancel();
266→          }}
267→          disabled={busy}
268→        >
269→          Cancel
270→        </button>
271→        <button
272→          type="submit"
273→          className="px-3 py-2 rounded-lg bg-primary text-primary-foreground text-sm font-semibold disabled:opacity-60 hover:bg-primary/90 transition"
274→          disabled={busy}
275→        >
276→          {busy ? 'Saving...' : 'Save changes'}
277→        </button>
278→      </div>
279→    </form>
280→  );
281→}
