 5→function routeForRole(role: string) {
 6→  if (role === 'STUDENT') return '/student';
 7→  if (role === 'PROFESSOR') return '/instructor';
 8→  if (role === 'ADMIN') return '/admin';
 9→  return '/';
10→}
