12→export default function UnsupportedRolePage() {
13→  const navigate = useNavigate();
14→  const { user, logout } = useLocalUser();
15→
16→  useEffect(() => {
17→    if (!user) {
18→      navigate('/', { replace: true });
19→      return;
20→    }
21→
22→    if (user.role !== 'TA') {
23→      navigate(routeForRole(user.role), { replace: true });
24→    }
25→  }, [navigate, user]);
26→
27→  const handleLogout = async () => {
28→    await logout();
29→    navigate('/', { replace: true });
30→  };
31→
32→  return (
