 1→import type { FormEvent } from 'react';
 2→import { useState } from 'react';
 3→import { useCourseTopicsContext } from '../hooks/useCourseTopics';
 4→
 5→type AddCourseTopicsButtonProps = {
 6→  disabled?: boolean;
 7→};
 8→
 9→export default function AddCourseTopicsButton({ disabled = false }: AddCourseTopicsButtonProps) {
10→  const { createTopic } = useCourseTopicsContext();
11→  const [open, setOpen] = useState(false);
12→  const [name, setName] = useState('');
13→  const [error, setError] = useState<string | null>(null);
14→  const [busy, setBusy] = useState(false);
15→
16→  const toggle = () => {
17→    if (disabled || busy) return;
18→    setError(null);
19→    setOpen((current) => {
20→      if (current) {
21→        setName('');
22→      }
23→      return !current;
24→    });
25→  };
26→
27→  const handleSubmit = async (event: FormEvent) => {
28→    event.preventDefault();
29→    const trimmed = name.trim();
30→    if (!trimmed) {
31→      setError('Topic name is required.');
32→      return;
33→    }
34→
35→    setBusy(true);
36→    setError(null);
37→    try {
38→      await createTopic(trimmed);
39→      setName('');
40→      setOpen(false);
41→    } catch (err) {
42→      console.error('Failed to create topic', err);
43→      setError('Could not create topic. Try a different name.');
44→    } finally {
45→      setBusy(false);
46→    }
47→  };
48→
49→  const buttonDisabled = disabled || busy;
50→
51→  return (
52→    <div className="space-y-2">
53→      <button
54→        type="button"
55→        onClick={toggle}
56→        disabled={buttonDisabled}
57→        className="w-full px-3 py-2 rounded-xl bg-gradient-to-r from-sky-600 to-indigo-600 text-white text-sm font-semibold disabled:opacity-50"
58→      >
59→        {open ? 'Cancel' : 'Add Topic'}
60→      </button>
61→      {open && (
62→        <form onSubmit={handleSubmit} className="space-y-2">
63→          <input
64→            value={name}
65→            onChange={(event) => setName(event.target.value)}
66→            placeholder="New topic name…"
67→            className="w-full px-3 py-2 rounded-xl border border-gray-300 dark:border-gray-700 bg-transparent"
68→          />
69→          {error && <p className="text-xs text-rose-500">{error}</p>}
70→          <div className="flex justify-end">
71→            <button
72→              type="submit"
73→              disabled={busy || !name.trim()}
74→              className="px-3 py-2 rounded-lg bg-indigo-600 text-white text-xs font-semibold disabled:opacity-40"
75→            >
76→              {busy ? 'Adding…' : 'Save Topic'}
77→            </button>
78→          </div>
79→        </form>
80→      )}
81→    </div>
82→  );
83→}
