  1→import { useMemo, useState } from 'react';
  2→import type { Topic } from '~/lib/types';
  3→
  4→type MissingTopic = { id: number; name: string };
  5→
  6→type Mapping = { fromTopicId: number; toTopicId: string; };
  7→
  8→export default function TopicSyncMappingDialog({
  9→  open,
 10→  onClose,
 11→  topics,
 12→  missing,
 13→  onApply,
 14→  busy = false,
 15→}: {
 16→  open: boolean;
 17→  onClose: () => void;
 18→  topics: Topic[];
 19→  missing: MissingTopic[];
 20→  onApply: (mappings: { fromTopicId: number; toTopicId: number }[]) => Promise<void>;
 21→  busy?: boolean;
 22→}) {
 23→  const [submitting, setSubmitting] = useState(false);
 24→  const [mappings, setMappings] = useState<Mapping[]>(() =>
 25→    missing.map((m) => ({ fromTopicId: m.id, toTopicId: '' })),
 26→  );
 27→
 28→  // Reset mapping rows when missing list changes or dialog reopens
 29→  const prevOpen = useMemo(() => open, [open]);
 30→  if (prevOpen && mappings.length !== missing.length) {
 31→    // Ensure we have one mapping per missing topic
 32→    const byFrom = new Map(mappings.map((m) => [m.fromTopicId, m.toTopicId]));
 33→    setMappings(missing.map((m) => ({ fromTopicId: m.id, toTopicId: byFrom.get(m.id) ?? '' })));
 34→  }
 35→
 36→  // Keep mappings in sync when missing changes
 37→  const missingIds = useMemo(() => new Set(missing.map((m) => m.id)), [missing]);
 38→  const mappingByFrom = useMemo(() => {
 39→    const map = new Map<number, string>();
 40→    for (const m of mappings) map.set(m.fromTopicId, m.toTopicId);
 41→    return map;
 42→  }, [mappings]);
 43→
 44→  const options = useMemo(() => topics, [topics]);
 45→
 46→  const allSelected = mappings.length > 0 && mappings.every((m) => m.toTopicId !== '');
 47→
 48→  const handleChange = (fromTopicId: number, value: string) => {
 49→    const toTopicId = value || '';
 50→    setMappings((prev) =>
 51→      prev.map((m) => (m.fromTopicId === fromTopicId ? { ...m, toTopicId } : m)),
