import { useMemo } from 'react';
import { useNavigate } from 'react-router';
import Nav from '../components/Nav';
import { ProgressBarFromData } from '../components/ProgressBar';
import type { Course } from '../lib/types';
import type { Route } from './+types/student';
import api from '~/lib/api';
import { requireClientUser } from '~/lib/client-auth';

export async function clientLoader(_: Route.ClientLoaderArgs) {
  await requireClientUser('STUDENT');
  const courses = (await api.listCourses()) as Course[];
  return { courses };
}

export default function StudentHome({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const courseList = useMemo(() => loaderData.courses ?? [], [loaderData.courses]);

  return (
    <div className="min-h-dvh bg-background relative noise">
      <Nav />

      {/* Layered atmospheric background */}
      <div className="fixed inset-0 -z-10 overflow-hidden pointer-events-none">
        <div className="absolute -top-40 -right-40 w-[900px] h-[900px] rounded-full bg-terracotta-100/40 dark:bg-terracotta-900/20 blur-[128px]" />
        <div className="absolute -bottom-60 -left-40 w-[700px] h-[700px] rounded-full bg-sage-100/50 dark:bg-sage-900/15 blur-[128px]" />
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] rounded-full bg-terracotta-50/30 dark:bg-terracotta-950/10 blur-[100px]" />
        <div className="absolute inset-0 dots-pattern opacity-30" />
      </div>

      <main className="container mx-auto px-6 sm:px-8 lg:px-10 pt-12 pb-20">
        {/* Editorial page header */}
        <header className="mb-14 animate-fade-up" data-tour="student-dashboard-header">
          <div className="max-w-3xl">
            <span className="tag tag-primary mb-4 inline-block animate-fade-down delay-75">
              Student Dashboard
            </span>
            <h1 className="font-display text-4xl sm:text-5xl lg:text-6xl font-bold tracking-tight text-foreground leading-[1.1] mb-4">
              My{' '}
              <span className="text-gradient">Courses</span>
            </h1>
            <p className="text-muted-foreground text-base sm:text-lg leading-relaxed max-w-xl">
              Continue where you left off or explore new learning materials.
            </p>
          </div>
          <div className="flex items-center gap-4 mt-6 animate-fade-up delay-150">
            <div className="h-px flex-1 bg-gradient-to-r from-border via-border to-transparent max-w-xs" />
            <span className="font-mono text-xs text-muted-foreground tracking-widest uppercase">
              {courseList.length} {courseList.length === 1 ? 'course' : 'courses'} enrolled
            </span>
            <div className="h-px flex-1 bg-gradient-to-l from-border via-border to-transparent max-w-xs" />
          </div>
        </header>

        {/* Course grid or empty state */}
        {courseList.length === 0 ? (
          <div className="animate-fade-up delay-200">
            <div className="card-editorial max-w-md mx-auto text-center px-10 py-16 relative">
              {/* Decorative corner accents */}
              <div className="absolute top-4 left-4 w-6 h-6 border-t-2 border-l-2 border-terracotta-300/40 dark:border-terracotta-700/30 rounded-tl-sm" />
              <div className="absolute bottom-4 right-4 w-6 h-6 border-b-2 border-r-2 border-terracotta-300/40 dark:border-terracotta-700/30 rounded-br-sm" />

              <div className="w-16 h-16 mx-auto mb-8 rounded-2xl bg-terracotta-50 dark:bg-terracotta-950/50 border border-terracotta-200/60 dark:border-terracotta-800/30 flex items-center justify-center animate-scale-in delay-300">
                <svg className="w-7 h-7 text-terracotta-400 dark:text-terracotta-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 006 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 016 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 016-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0018 18a8.967 8.967 0 00-6 2.292m0-14.25v14.25" />
                </svg>
              </div>
              <h2 className="font-display text-2xl font-bold text-foreground mb-3">
                No courses yet
              </h2>
              <p className="text-muted-foreground text-sm leading-relaxed max-w-xs mx-auto">
                You haven't been enrolled in any courses. Contact your instructor to get started.
              </p>
              <div className="mt-8 h-px w-16 mx-auto bg-gradient-to-r from-transparent via-terracotta-300/50 to-transparent dark:via-terracotta-700/30" />
            </div>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-7">
            {courseList.map((course, index) => {
              const pct = course.progress && course.progress.total > 0
                ? Math.round((course.progress.completed / course.progress.total) * 100)
                : null;

              return (
                <button
                  key={course.id}
                  onClick={() => navigate(`/student/courses/${course.id}`)}
                  className="group card-editorial text-left transition-all duration-500 glow animate-fade-up flex flex-col hover:shadow-xl hover:-translate-y-1.5"
                  style={{ animationDelay: `${150 + index * 75}ms` }}
                  data-tour={index === 0 ? 'student-course-card-first' : undefined}
                  data-tour-route={index === 0 ? `/student/courses/${course.id}` : undefined}
                >
                  {/* Top accent bar */}
                  <div className="h-1 w-full bg-gradient-to-r from-terracotta-400 via-terracotta-300 to-sage-400 dark:from-terracotta-600 dark:via-terracotta-500 dark:to-sage-600 rounded-t-2xl opacity-60 group-hover:opacity-100 transition-opacity duration-500" />

                  <div className="p-6 flex flex-col flex-1">
                    {/* Icon row */}
                    <div className="flex items-start justify-between mb-5">
                      <div className="w-11 h-11 rounded-xl bg-terracotta-50 dark:bg-terracotta-950/60 border border-terracotta-200/50 dark:border-terracotta-800/30 flex items-center justify-center text-terracotta-500 dark:text-terracotta-400 transition-all duration-300 group-hover:bg-primary group-hover:text-primary-foreground group-hover:border-primary group-hover:shadow-lg group-hover:shadow-primary/20">
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 006 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 016 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 016-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0018 18a8.967 8.967 0 00-6 2.292m0-14.25v14.25" />
                        </svg>
                      </div>

                      {/* Percentage badge */}
                      {pct !== null && (
                        <span className={`font-mono text-xs font-semibold tabular-nums px-2 py-0.5 rounded-md ${
                          pct === 100
                            ? 'bg-sage-100 text-sage-700 dark:bg-sage-900/50 dark:text-sage-300'
                            : 'bg-secondary text-muted-foreground'
                        }`}>
                          {pct}%
                        </span>
                      )}
                    </div>

                    {/* Course info */}
                    <div className="flex-1 mb-5">
                      <h3 className="font-display text-lg font-bold text-foreground mb-1.5 group-hover:text-primary transition-colors duration-300 line-clamp-2 leading-snug">
                        {course.title}
                      </h3>
                      {course.description && (
                        <p className="text-sm text-muted-foreground leading-relaxed line-clamp-2">
                          {course.description}
                        </p>
                      )}
                    </div>

                    {/* Footer: progress + arrow */}
                    <div className="pt-4 border-t border-border/70 flex items-end justify-between gap-3">
                      <div className="flex-1 min-w-0">
                        {course.progress && course.progress.total > 0 ? (
                          <ProgressBarFromData progress={course.progress} size="sm" showLabel />
                        ) : (
                          <span className="text-xs text-muted-foreground/70 italic">
                            No activities yet
                          </span>
                        )}
                      </div>
                      <div className="w-8 h-8 rounded-lg bg-secondary/80 dark:bg-secondary flex items-center justify-center opacity-0 translate-x-1 transition-all duration-300 group-hover:opacity-100 group-hover:translate-x-0 group-hover:bg-primary/10 shrink-0">
                        <svg className="w-4 h-4 text-foreground group-hover:text-primary transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                        </svg>
                      </div>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        )}
      </main>
    </div>
  );
}

