import type { MouseEvent } from "react";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "~/components/ui/tooltip";
import { cn } from "~/lib/utils";

type PublishStatusButtonProps = {
  isPublished: boolean;
  pending?: boolean;
  blockedReason?: string | null;
  onClick?: (event: MouseEvent<HTMLButtonElement>) => void;
  className?: string;
};

export function PublishStatusButton({
  isPublished,
  pending = false,
  blockedReason,
  onClick,
  className,
}: PublishStatusButtonProps) {
  const label = pending ? "Saving\u2026" : isPublished ? "Published" : "Draft";
  const blocked = Boolean(blockedReason);

  const handleClick = (event: MouseEvent<HTMLButtonElement>) => {
    if (blocked) {
      event.preventDefault();
      return;
    }
    onClick?.(event);
  };

  const button = (
    <button
      type="button"
      aria-disabled={blocked}
      className={cn(
        "inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-xs font-semibold tracking-wide uppercase transition-all duration-200",
        isPublished
          ? "bg-sage-100 text-sage-700 ring-1 ring-sage-300/60 hover:bg-sage-200 dark:bg-sage-900/40 dark:text-sage-300 dark:ring-sage-700/50 dark:hover:bg-sage-900/60"
          : "bg-secondary text-muted-foreground ring-1 ring-border hover:bg-muted dark:hover:bg-muted",
        blocked && "cursor-not-allowed opacity-50",
        pending && "animate-pulse-soft",
        className,
      )}
      onClick={handleClick}
    >
      <span
        className={cn(
          "inline-block h-1.5 w-1.5 rounded-full",
          isPublished
            ? "bg-sage-500 dark:bg-sage-400"
            : "bg-muted-foreground/40",
        )}
      />
      {label}
    </button>
  );

  if (!blockedReason) {
    return button;
  }

  return (
    <TooltipProvider delayDuration={150}>
      <Tooltip>
        <TooltipTrigger asChild>{button}</TooltipTrigger>
        <TooltipContent
          className="max-w-xs rounded-xl border border-border bg-card px-3 py-2 text-xs text-muted-foreground shadow-lg"
        >
          {blockedReason}
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

