 849→function normalizePolicy(raw: unknown, models: AdminAiModelOption[]): AdminAiModelPolicy {
 850→  const fallbackTutor = models[0]?.modelId ?? null;
 851→  const allowedTutorModelIds = Array.isArray((raw as { allowedTutorModelIds?: unknown })?.allowedTutorModelIds)
 852→    ? (raw as { allowedTutorModelIds: unknown[] }).allowedTutorModelIds.filter(
 853→        (value): value is string => typeof value === 'string',
 854→      )
 855→    : fallbackTutor
 856→      ? [fallbackTutor]
 857→      : [];
 858→
 859→  const defaultTutorModelId =
 860→    typeof (raw as { defaultTutorModelId?: unknown })?.defaultTutorModelId === 'string'
 861→      ? (raw as { defaultTutorModelId: string }).defaultTutorModelId
 862→      : allowedTutorModelIds[0] ?? null;
 863→
 864→  return {
 865→    allowedTutorModelIds,
 866→    defaultTutorModelId:
 867→      defaultTutorModelId && allowedTutorModelIds.includes(defaultTutorModelId)
 868→        ? defaultTutorModelId
 869→        : allowedTutorModelIds[0] ?? null,
 870→    defaultSupervisorModelId:
 871→      typeof (raw as { defaultSupervisorModelId?: unknown })?.defaultSupervisorModelId === 'string'
 872→        ? (raw as { defaultSupervisorModelId: string }).defaultSupervisorModelId
 873→        : models[0]?.modelId ?? null,
 874→    dualLoopEnabled:
 875→      typeof (raw as { dualLoopEnabled?: unknown })?.dualLoopEnabled === 'boolean'
 876→        ? (raw as { dualLoopEnabled: boolean }).dualLoopEnabled
 877→        : true,
 878→    maxSupervisorIterations:
 879→      typeof (raw as { maxSupervisorIterations?: unknown })?.maxSupervisorIterations === 'number'
 880→        ? Math.max(1, Math.min(5, (raw as { maxSupervisorIterations: number }).maxSupervisorIterations))
 881→        : DEFAULT_POLICY.maxSupervisorIterations,
 882→  };
 883→}
