 885→async function loadAdminAiPolicy(settingsApi: AdminSettingsApi) {
 886→  if (typeof settingsApi.getAdminAiModelPolicy !== 'function') {
 887→    return { policy: null, error: null };
 888→  }
 889→
 890→  try {
 891→    const policy = await settingsApi.getAdminAiModelPolicy();
 892→    return { policy: policy as AdminAiModelPolicy, error: null };
 893→  } catch {
 894→    return {
 895→      policy: null,
 896→      error: 'AI model settings could not be loaded. The rest of the admin tools are still available.',
 897→    };
 898→  }
 899→}
