 901→async function loadAdminAiModels(settingsApi: AdminSettingsApi) {
 902→  if (typeof settingsApi.listAiModels !== 'function') {
 903→    return { models: [] as AdminAiModelOption[] };
 904→  }
 905→
 906→  try {
 907→    const models = await settingsApi.listAiModels();
 908→    const normalized = Array.isArray(models)
 909→      ? models
 910→          .map((model, index) => normalizeModelOption(model, index))
 911→          .filter((model): model is AdminAiModelOption => model !== null)
 912→      : [];
 913→
 914→    return { models: normalized };
 915→  } catch {
 916→    return { models: [] as AdminAiModelOption[] };
 917→  }
 918→}
