 920→function normalizeModelOption(raw: unknown, index: number): AdminAiModelOption | null {
 921→  if (!raw || typeof raw !== 'object') return null;
 922→
 923→  const record = raw as Record<string, unknown>;
 924→  const modelId =
 925→    typeof record.modelId === 'string'
 926→      ? record.modelId
 927→      : typeof record.id === 'string'
 928→        ? record.id
 929→        : null;
 930→
 931→  if (!modelId) {
 932→    return null;
 933→  }
 934→
 935→  const provider =
 936→    typeof record.provider === 'string' ? record.provider : inferProvider(modelId);
 937→  const costTier =
 938→    record.costTier === 'LOW' || record.costTier === 'MEDIUM' || record.costTier === 'HIGH'
 939→      ? record.costTier
 940→      : inferCostTier(modelId, String(record.modelName ?? modelId));
 941→
 942→  return {
