import { useMemo } from 'react';
import { Link, useNavigate } from 'react-router';
import Nav from '../components/Nav';
import { ProgressBarFromData } from '../components/ProgressBar';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import type { Course, Lesson, ModuleDetail } from '../lib/types';
import type { Route } from './+types/student.topic';
import api from '~/lib/api';
import { requireClientUser } from '~/lib/client-auth';

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('STUDENT');
  const moduleId = Number(params.moduleId);
  if (!Number.isFinite(moduleId)) {
    throw new Response('Invalid module id', { status: 400 });
  }

  const [module, lessons] = await Promise.all([
    api.moduleById(moduleId) as Promise<ModuleDetail>,
    api.lessonsForModule(moduleId) as Promise<Lesson[]>,
  ]);

  let course: Course | null = null;
  if (module.courseOfferingId) {
    course = (await api.courseById(module.courseOfferingId)) as Course;
  }

  return { course, module, lessons };
}

export default function StudentModuleLessons({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const { course, module, lessons } = loaderData;
  const lessonList = useMemo(() => lessons ?? [], [lessons]);

  return (
    <div className="min-h-dvh bg-background">
      <Nav />

      {/* Subtle background texture */}
      <div className="fixed inset-0 -z-10 pointer-events-none">
        <div className="absolute inset-0 noise" />
        <div className="absolute top-0 left-1/2 w-[500px] h-[500px] bg-accent/[0.04] rounded-full blur-[120px] -translate-y-1/3 -translate-x-1/2" />
        <div className="absolute bottom-0 right-0 w-[400px] h-[400px] bg-primary/[0.04] rounded-full blur-[120px] translate-y-1/3 translate-x-1/4" />
      </div>

      <div className="max-w-4xl mx-auto px-6 sm:px-8 py-10">
        {/* Breadcrumb */}
        <Breadcrumb className="mb-10 animate-fade-in">
          <BreadcrumbList className="text-sm tracking-wide">
            <BreadcrumbItem>
              <BreadcrumbLink asChild>
                <Link to="/student" className="text-muted-foreground hover:text-foreground transition-colors duration-200">
                  My Courses
                </Link>
              </BreadcrumbLink>
            </BreadcrumbItem>
            <BreadcrumbSeparator className="text-border/60 mx-1">/</BreadcrumbSeparator>
            <BreadcrumbItem>
              {course && module ? (
                <BreadcrumbLink asChild>
                  <Link
                    to={`/student/courses/${module.courseOfferingId}`}
                    className="text-muted-foreground hover:text-foreground transition-colors duration-200"
                  >
                    {course.title}
                  </Link>
                </BreadcrumbLink>
              ) : (
                <BreadcrumbPage>Course</BreadcrumbPage>
              )}
            </BreadcrumbItem>
            <BreadcrumbSeparator className="text-border/60 mx-1">/</BreadcrumbSeparator>
            <BreadcrumbItem>
              <BreadcrumbPage className="font-medium text-foreground">
                {module?.title || 'Module'}
              </BreadcrumbPage>
            </BreadcrumbItem>
          </BreadcrumbList>
        </Breadcrumb>

        {/* Page header */}
        <header className="mb-14 animate-fade-up">
          <div className="mb-4">
            <span className="tag tag-accent text-[10px] tracking-[0.15em] mb-3 inline-block">
              Module
            </span>
            <h1 className="font-display text-4xl sm:text-5xl font-bold tracking-tight text-foreground leading-[1.1]">
              {module?.title || 'Module'}
            </h1>
          </div>
          <div className="mt-6 pt-6 border-t border-border/60">
            <span className="font-mono text-sm text-muted-foreground tracking-wide">
              {String(lessonList.length).padStart(2, '0')}{' '}
              <span className="text-border mx-1">/</span>{' '}
              {lessonList.length === 1 ? 'Lesson' : 'Lessons'}
            </span>
          </div>
        </header>

        {/* Lesson list */}
        {lessonList.length === 0 ? (
          <div className="animate-fade-up delay-150">
            <div className="card-editorial px-8 py-16 text-center max-w-md mx-auto">
              <div className="w-12 h-12 mx-auto mb-5 rounded-xl bg-secondary flex items-center justify-center">
                <svg className="w-6 h-6 text-muted-foreground" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M4.26 10.147a60.436 60.436 0 00-.491 6.347A48.627 48.627 0 0112 20.904a48.627 48.627 0 018.232-4.41 60.46 60.46 0 00-.491-6.347m-15.482 0a50.57 50.57 0 00-2.658-.813A59.905 59.905 0 0112 3.493a59.902 59.902 0 0110.399 5.84c-.896.248-1.783.52-2.658.814m-15.482 0A50.697 50.697 0 0112 13.489a50.702 50.702 0 017.74-3.342" />
                </svg>
              </div>
              <h2 className="font-display text-lg font-bold text-foreground mb-2">
                No lessons yet
              </h2>
              <p className="text-muted-foreground text-sm leading-relaxed">
                This module doesn't have any lessons available. Check back later.
              </p>
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            {lessonList.map((lesson, index) => (
              <button
                key={lesson.id}
                onClick={() => navigate(`/student/lesson/${lesson.id}`)}
                className="group w-full text-left card-editorial transition-all duration-300 hover:shadow-lg hover:border-primary/20 glow animate-fade-up"
                style={{ animationDelay: `${100 + index * 60}ms` }}
                data-tour={index === 0 ? 'student-lesson-card-first' : undefined}
                data-tour-route={index === 0 ? `/student/lesson/${lesson.id}` : undefined}
              >
                <div className="flex items-center gap-5 sm:gap-6 p-5 sm:p-6">
                  {/* Lesson index */}
                  <div className="flex-shrink-0 w-12 h-12 rounded-xl bg-accent/40 flex items-center justify-center transition-colors duration-300 group-hover:bg-accent/60">
                    <span className="font-mono text-sm font-semibold text-accent-foreground tabular-nums">
                      {String(index + 1).padStart(2, '0')}
                    </span>
                  </div>

                  {/* Lesson content */}
                  <div className="flex-1 min-w-0">
                    <h3 className="font-display text-lg font-bold text-foreground group-hover:text-primary transition-colors duration-200 truncate">
                      {lesson.title}
                    </h3>

                    {/* Progress */}
                    {lesson.progress && lesson.progress.total > 0 && (
                      <div className="mt-3 max-w-xs">
                        <ProgressBarFromData progress={lesson.progress} size="sm" showLabel />
                      </div>
                    )}
                  </div>

                  {/* Arrow indicator */}
                  <div className="flex-shrink-0 w-8 h-8 rounded-lg flex items-center justify-center text-muted-foreground/40 transition-all duration-300 group-hover:text-primary group-hover:translate-x-0.5">
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                    </svg>
                  </div>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

import { useMemo, useState } from 'react';
import type { Topic } from '~/lib/types';

type MissingTopic = { id: number; name: string };

type Mapping = { fromTopicId: number; toTopicId: string; };

export default function TopicSyncMappingDialog({
  open,
  onClose,
  topics,
  missing,
  onApply,
  busy = false,
}: {
  open: boolean;
  onClose: () => void;
  topics: Topic[];
  missing: MissingTopic[];
  onApply: (mappings: { fromTopicId: number; toTopicId: number }[]) => Promise<void>;
  busy?: boolean;
}) {
  const [submitting, setSubmitting] = useState(false);
  const [mappings, setMappings] = useState<Mapping[]>(() =>
    missing.map((m) => ({ fromTopicId: m.id, toTopicId: '' })),
  );

  // Reset mapping rows when missing list changes or dialog reopens
  const prevOpen = useMemo(() => open, [open]);
  if (prevOpen && mappings.length !== missing.length) {
    // Ensure we have one mapping per missing topic
    const byFrom = new Map(mappings.map((m) => [m.fromTopicId, m.toTopicId]));
    setMappings(missing.map((m) => ({ fromTopicId: m.id, toTopicId: byFrom.get(m.id) ?? '' })));
  }

  // Keep mappings in sync when missing changes
  const missingIds = useMemo(() => new Set(missing.map((m) => m.id)), [missing]);
  const mappingByFrom = useMemo(() => {
    const map = new Map<number, string>();
    for (const m of mappings) map.set(m.fromTopicId, m.toTopicId);
    return map;
  }, [mappings]);

  const options = useMemo(() => topics, [topics]);

  const allSelected = mappings.length > 0 && mappings.every((m) => m.toTopicId !== '');

  const handleChange = (fromTopicId: number, value: string) => {
    const toTopicId = value || '';
    setMappings((prev) =>
      prev.map((m) => (m.fromTopicId === fromTopicId ? { ...m, toTopicId } : m)),
    );
  };

  const onSubmit = async () => {
    if (!allSelected || submitting || busy) return;
    setSubmitting(true);
    try {
      const payload = mappings
        .filter((m) => m.toTopicId !== '')
        .map((m) => ({ fromTopicId: m.fromTopicId, toTopicId: Number(m.toTopicId) }));
      await onApply(payload);
      onClose();
    } finally {
      setSubmitting(false);
    }
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-foreground/20 backdrop-blur-sm"
        onClick={onClose}
        onKeyDown={(e) => {
          if (e.key === 'Escape') onClose();
        }}
        role="presentation"
      />

      {/* Dialog */}
      <div className="relative w-[min(720px,95vw)] card-editorial p-8 shadow-2xl animate-scale-in">
        {/* Decorative corner accent */}
        <div className="absolute top-0 right-0 w-24 h-24 dots-pattern opacity-40 rounded-bl-3xl" />

        <h3 className="font-display text-xl font-semibold text-foreground tracking-tight">
          Review topic changes
        </h3>
        <p className="mt-2 text-sm text-muted-foreground leading-relaxed">
          Some topics in this course are no longer present in EduAI. Please map them to existing topics so activities remain correctly tagged.
        </p>

        <div className="mt-6 space-y-3 max-h-[50vh] overflow-y-auto pr-1">
          {missing.map((m, idx) => (
            <div
              key={m.id}
              className="rounded-xl border border-border bg-background/60 p-4 animate-fade-up"
              style={{ animationDelay: `${idx * 60}ms` }}
            >
              <div className="flex items-start gap-3">
                <span className="mt-0.5 flex-shrink-0 font-mono text-xs text-muted-foreground tabular-nums">
                  {String(idx + 1).padStart(2, '0')}
                </span>
                <div className="flex-1 space-y-2">
                  <div className="text-sm text-foreground">
                    <span className="font-semibold">{m.name}</span>{' '}
                    <span className="text-muted-foreground">no longer exists. Choose a replacement:</span>
                  </div>
                  <select
                    className="input-field text-sm !py-2"
                    value={mappingByFrom.get(m.id) ?? ''}
                    onChange={(e) => handleChange(m.id, e.target.value)}
                  >
                    <option value="">Select replacement...</option>
                    {options
                      .filter((t) => t.id !== m.id)
                      .map((t) => (
                        <option key={t.id} value={t.id}>
                          {t.name}
                        </option>
                      ))}
                  </select>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-6 flex justify-end gap-3">
          <button
            type="button"
            onClick={onClose}
            className="btn-ghost text-sm"
            disabled={submitting || busy}
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={onSubmit}
            disabled={!allSelected || submitting || busy}
            className="btn-primary text-sm"
          >
            {submitting ? 'Applying\u2026' : 'Apply mappings'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useOptimistic, useState } from 'react';
import { useNavigate } from 'react-router';
import Nav from '../components/Nav';
import { PublishStatusButton } from '../components/PublishStatusButton';
import api from '../lib/api';
import type { Course, EduAiCourse } from '../lib/types';
import type { Route } from './+types/instructor';
import { requireClientUser } from '~/lib/client-auth';

export async function clientLoader(_: Route.ClientLoaderArgs) {
  await requireClientUser('PROFESSOR');
  const courses = (await api.listCourses()) as Course[];
  return { courses };
}

export default function InstructorHome({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const [courses, setCourses] = useState<Course[]>(loaderData.courses ?? []);
  const [loading, setLoading] = useState(false);
  const [showEduAiImport, setShowEduAiImport] = useState(false);
  const [publishingId, setPublishingId] = useState<number | null>(null);
  const [eduAiCourses, setEduAiCourses] = useState<EduAiCourse[]>([]);
  const [loadingEduAiCourses, setLoadingEduAiCourses] = useState(false);
  const [importingExternalId, setImportingExternalId] = useState<string | null>(null);
  const [eduAiError, setEduAiError] = useState<string | null>(null);

  const [oCourses, addCourseOpt] = useOptimistic(
    courses,
    (state, patch: (items: Course[]) => Course[]) => patch(state),
  );

  const parseErrorMessage = (error: unknown) => {
    if (error instanceof Error) {
      try {
        const parsed = JSON.parse(error.message);
        if (parsed && typeof parsed === 'object' && typeof parsed.error === 'string') {
          return parsed.error;
        }
      } catch {
        // Ignore JSON parse failures
      }
      return error.message;
    }
    return 'Something went wrong. Please try again.';
  };

  const loadCourses = async () => {
    setLoading(true);
    try {
      const data: Course[] = await api.listCourses();
      setCourses(data);
    } catch (error) {
      console.error('Failed to load courses:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchEduAiCourses = async () => {
    setLoadingEduAiCourses(true);
    setEduAiError(null);
    try {
      const data = (await api.listEduAiCourses()) as EduAiCourse[];
      setEduAiCourses(data);
    } catch (error) {
      console.error('Failed to load EduAI courses:', error);
      setEduAiError(parseErrorMessage(error));
    } finally {
      setLoadingEduAiCourses(false);
    }
  };

  const ensureEduAiCourses = () => {
    if (eduAiCourses.length > 0 || loadingEduAiCourses) return;
    fetchEduAiCourses();
  };

  const importEduAiCourse = async (externalCourseId: string) => {
    if (!externalCourseId) return;
    setImportingExternalId(externalCourseId);
    setEduAiError(null);
    try {
      await api.importEduAiCourse({ externalCourseId });
      setEduAiCourses((prev) => prev.filter((course) => course.id !== externalCourseId));
      await loadCourses();
    } catch (error) {
      console.error('Failed to import EduAI course:', error);
      setEduAiError(parseErrorMessage(error));
    } finally {
      setImportingExternalId((current) => (current === externalCourseId ? null : current));
    }
  };

  const togglePublish = async (courseId: number, currentlyPublished: boolean) => {
    addCourseOpt((items) =>
      items.map((course) =>
        course.id === courseId ? { ...course, isPublished: !currentlyPublished } : course,
      ),
    );
    setPublishingId(courseId);

    try {
      const updated = currentlyPublished
        ? await api.unpublishCourse(courseId)
        : await api.publishCourse(courseId);
      setCourses((prev) =>
        prev.map((course) => (course.id === courseId ? updated : course))
      );
    } catch (error) {
      console.error('Failed to toggle publish status', error);
      setCourses((prev) =>
        prev.map((course) =>
          course.id === courseId ? { ...course, isPublished: currentlyPublished } : course,
        ),
      );
    } finally {
      setPublishingId((current) => (current === courseId ? null : current));
    }
  };

  return (
    <div className="min-h-dvh bg-background relative">
      <Nav />

      {/* Atmospheric background */}
      <div className="fixed inset-0 -z-10 overflow-hidden pointer-events-none">
        <div className="absolute -top-32 left-1/3 w-[900px] h-[600px] bg-primary/[0.04] rounded-full blur-[100px]" />
        <div className="absolute bottom-0 right-0 w-[600px] h-[600px] bg-accent/[0.06] rounded-full blur-[120px] translate-y-1/4 translate-x-1/6" />
        <div className="absolute top-1/2 left-0 w-[400px] h-[400px] bg-primary/[0.02] rounded-full blur-[80px] -translate-x-1/2" />
        <div className="absolute inset-0 dots-pattern opacity-[0.35]" />
      </div>

      <main className="container mx-auto max-w-6xl px-6 pt-12 pb-20 space-y-10">

        {/* ── Page Header ─────────────────────────────── */}
        <header className="animate-fade-up">
          <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-6">
            <div className="space-y-1">
              <p className="text-xs font-mono font-medium tracking-[0.2em] uppercase text-primary/70">
                Instructor Dashboard
              </p>
              <h1 className="font-display text-4xl sm:text-5xl font-bold tracking-tight text-foreground leading-[1.1]">
                Teaching
              </h1>
              <p className="text-muted-foreground text-sm max-w-md mt-2">
                Manage your courses, import content from EduAI, and control what students can see.
              </p>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden sm:flex items-center gap-2 mr-2">
                <span className="font-mono text-2xl font-bold text-foreground">{oCourses.length}</span>
                <span className="text-xs text-muted-foreground leading-tight">
                  {oCourses.length === 1 ? 'course' : 'courses'}
                </span>
              </div>
              <button
                onClick={() => {
                  setShowEduAiImport((prev) => {
                    const next = !prev;
                    if (next) {
                      ensureEduAiCourses();
                    } else {
                      setEduAiError(null);
                    }
                    return next;
                  });
                }}
                className={showEduAiImport ? 'btn-secondary' : 'btn-primary'}
              >
                {showEduAiImport ? (
                  <>
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                    Close
                  </>
                ) : (
                  <>
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                    </svg>
                    Import from EduAI
                  </>
                )}
              </button>
            </div>
          </div>

          {/* Divider with accent */}
          <div className="mt-8 flex items-center gap-4">
            <div className="h-px flex-1 bg-gradient-to-r from-border via-border to-transparent" />
            <div className="w-1.5 h-1.5 rounded-full bg-primary/40" />
            <div className="w-1 h-1 rounded-full bg-primary/20" />
          </div>
        </header>

        {/* ── EduAI Import Panel ──────────────────────── */}
        {showEduAiImport && (
          <section className="animate-scale-in">
            <div className="panel-glass rounded-2xl p-8 noise relative">
              {/* Corner ornament */}
              <div className="absolute top-0 right-0 w-32 h-32 bg-primary/[0.04] rounded-full blur-2xl -translate-y-1/2 translate-x-1/2 pointer-events-none" />

              <div className="relative flex flex-col sm:flex-row sm:items-start justify-between gap-5 mb-6">
                <div className="flex items-start gap-4">
                  <div className="w-11 h-11 rounded-xl bg-primary/10 border border-primary/10 flex items-center justify-center flex-shrink-0">
