                  >
                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
                    </svg>
                    Get started
                  </button>
                )}
              </div>
            </div>
          </div>
        ) : (
          <section>
            {/* Section label */}
            <div className="flex items-center gap-3 mb-6 animate-fade-up delay-75">
              <h2 className="text-xs font-mono font-medium tracking-[0.2em] uppercase text-muted-foreground">
                Your Courses
              </h2>
              <div className="h-px flex-1 bg-border/50" />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
              {oCourses.map((c, index) => (
                <div
                  key={c.id}
                  role="button"
                  tabIndex={0}
                  onClick={() => navigate(`/instructor/courses/${c.id}`)}
                  onKeyDown={(event) => {
                    if (event.key === 'Enter' || event.key === ' ') {
                      event.preventDefault();
                      navigate(`/instructor/courses/${c.id}`);
                    }
                  }}
                  className="group card-editorial p-0 cursor-pointer transition-all duration-300 hover:shadow-xl hover:-translate-y-1 glow flex flex-col animate-fade-up focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 overflow-hidden"
                  style={{ animationDelay: `${100 + index * 60}ms` }}
