                  {/* Colored top accent bar */}
                  <div className="h-1 w-full bg-gradient-to-r from-primary/70 via-primary/40 to-transparent group-hover:from-primary group-hover:via-primary/60 transition-all duration-500" />

                  <div className="p-6 flex flex-col flex-1">
                    {/* Tags row */}
                    <div className="flex items-center gap-2 mb-4">
                      <span className={`tag ${c.isPublished ? 'tag-accent' : ''} text-[10px]`}>
                        {c.isPublished ? 'Published' : 'Draft'}
                      </span>
                      {c.externalSource === 'EDUAI' && (
                        <span className="tag tag-primary text-[10px]">
                          EduAI
                        </span>
                      )}
                    </div>

                    {/* Course title and description */}
                    <div className="flex-1 mb-5">
                      <h3 className="font-display text-lg font-bold text-foreground mb-1.5 group-hover:text-primary transition-colors duration-300 line-clamp-2 leading-snug">
                        {c.title}
                      </h3>
                      {c.description && (
                        <p className="text-sm text-muted-foreground line-clamp-2 leading-relaxed">
                          {c.description}
                        </p>
                      )}
                    </div>

                    {/* Footer */}
                    <div className="pt-4 border-t border-border/50 flex items-center justify-between">
                      <div className="flex items-center gap-2 text-sm text-muted-foreground group-hover:text-primary transition-colors duration-300">
                        <span className="font-medium">Open</span>
                        <svg className="w-3.5 h-3.5 transition-transform duration-300 group-hover:translate-x-1" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" />
                        </svg>
                      </div>

                      <div
                        onClick={(event) => event.stopPropagation()}
                        onKeyDown={(event) => event.stopPropagation()}
                      >
                        <PublishStatusButton
                          isPublished={c.isPublished}
                          pending={publishingId === c.id}
                          onClick={() => {
                            if (publishingId === c.id) return;
                            togglePublish(c.id, c.isPublished);
                          }}
                        />
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

