  9→
 10→export async function clientLoader(_: Route.ClientLoaderArgs) {
 11→  await requireClientUser('PROFESSOR');
 12→  const courses = (await api.listCourses()) as Course[];
 13→  return { courses };
 14→}
 15→
 16→export default function InstructorHome({ loaderData }: Route.ComponentProps) {
 17→  const navigate = useNavigate();
 18→  const [courses, setCourses] = useState<Course[]>(loaderData.courses ?? []);
 19→  const [loading, setLoading] = useState(false);
 20→  const [showEduAiImport, setShowEduAiImport] = useState(false);
 21→  const [publishingId, setPublishingId] = useState<number | null>(null);
 22→  const [eduAiCourses, setEduAiCourses] = useState<EduAiCourse[]>([]);
 23→  const [loadingEduAiCourses, setLoadingEduAiCourses] = useState(false);
 24→  const [importingExternalId, setImportingExternalId] = useState<string | null>(null);
 25→  const [eduAiError, setEduAiError] = useState<string | null>(null);
 26→
 27→  const [oCourses, addCourseOpt] = useOptimistic(
 28→    courses,
 29→    (state, patch: (items: Course[]) => Course[]) => patch(state),
 30→  );
 31→
 32→  const parseErrorMessage = (error: unknown) => {
 33→    if (error instanceof Error) {
 34→      try {
 35→        const parsed = JSON.parse(error.message);
 36→        if (parsed && typeof parsed === 'object' && typeof parsed.error === 'string') {
 37→          return parsed.error;
 38→        }
 39→      } catch {
 40→        // Ignore JSON parse failures
 41→      }
 42→      return error.message;
 43→    }
 44→    return 'Something went wrong. Please try again.';
 45→  };
 46→
 47→  const loadCourses = async () => {
 48→    setLoading(true);
 49→    try {
 50→      const data: Course[] = await api.listCourses();
 51→      setCourses(data);
 52→    } catch (error) {
 53→      console.error('Failed to load courses:', error);
 54→    } finally {
 55→      setLoading(false);
 56→    }
 57→  };
 58→
 59→  const fetchEduAiCourses = async () => {
 60→    setLoadingEduAiCourses(true);
 61→    setEduAiError(null);
 62→    try {
 63→      const data = (await api.listEduAiCourses()) as EduAiCourse[];
 64→      setEduAiCourses(data);
 65→    } catch (error) {
 66→      console.error('Failed to load EduAI courses:', error);
 67→      setEduAiError(parseErrorMessage(error));
 68→    } finally {
 69→      setLoadingEduAiCourses(false);
 70→    }
 71→  };
 72→
 73→  const ensureEduAiCourses = () => {
 74→    if (eduAiCourses.length > 0 || loadingEduAiCourses) return;
 75→    fetchEduAiCourses();
