 88→      setEduAiError(parseErrorMessage(error));
 89→    } finally {
 90→      setImportingExternalId((current) => (current === externalCourseId ? null : current));
 91→    }
 92→  };
 93→
 94→  const togglePublish = async (courseId: number, currentlyPublished: boolean) => {
 95→    addCourseOpt((items) =>
 96→      items.map((course) =>
 97→        course.id === courseId ? { ...course, isPublished: !currentlyPublished } : course,
 98→      ),
