101→
102→    try {
103→      const updated = currentlyPublished
104→        ? await api.unpublishCourse(courseId)
105→        : await api.publishCourse(courseId);
106→      setCourses((prev) =>
107→        prev.map((course) => (course.id === courseId ? updated : course))
108→      );
109→    } catch (error) {
110→      console.error('Failed to toggle publish status', error);
111→      setCourses((prev) =>
112→        prev.map((course) =>
113→          course.id === courseId ? { ...course, isPublished: currentlyPublished } : course,
114→        ),
115→      );
116→    } finally {
117→      setPublishingId((current) => (current === courseId ? null : current));
118→    }
