130→        <div className="absolute inset-0 dots-pattern opacity-[0.35]" />
131→      </div>
132→
133→      <main className="container mx-auto max-w-6xl px-6 pt-12 pb-20 space-y-10">
134→
135→        {/* ── Page Header ─────────────────────────────── */}
136→        <header className="animate-fade-up">
137→          <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-6">
138→            <div className="space-y-1">
139→              <p className="text-xs font-mono font-medium tracking-[0.2em] uppercase text-primary/70">
140→                Instructor Dashboard
141→              </p>
142→              <h1 className="font-display text-4xl sm:text-5xl font-bold tracking-tight text-foreground leading-[1.1]">
143→                Teaching
144→              </h1>
145→              <p className="text-muted-foreground text-sm max-w-md mt-2">
146→                Manage your courses, import content from EduAI, and control what students can see.
147→              </p>
148→            </div>
149→
150→            <div className="flex items-center gap-3">
151→              <div className="hidden sm:flex items-center gap-2 mr-2">
152→                <span className="font-mono text-2xl font-bold text-foreground">{oCourses.length}</span>
153→                <span className="text-xs text-muted-foreground leading-tight">
154→                  {oCourses.length === 1 ? 'course' : 'courses'}
155→                </span>
156→              </div>
157→              <button
