165→                    }
166→                    return next;
167→                  });
168→                }}
169→                className={showEduAiImport ? 'btn-secondary' : 'btn-primary'}
170→              >
171→                {showEduAiImport ? (
172→                  <>
173→                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
174→                      <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
175→                    </svg>
176→                    Close
