178→                ) : (
179→                  <>
180→                    <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
181→                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" />
182→                    </svg>
183→                    Import from EduAI
184→                  </>
185→                )}
186→              </button>
187→            </div>
188→          </div>
189→
190→          {/* Divider with accent */}
191→          <div className="mt-8 flex items-center gap-4">
192→            <div className="h-px flex-1 bg-gradient-to-r from-border via-border to-transparent" />
193→            <div className="w-1.5 h-1.5 rounded-full bg-primary/40" />
194→            <div className="w-1 h-1 rounded-full bg-primary/20" />
195→          </div>
196→        </header>
197→
198→        {/* ── EduAI Import Panel ──────────────────────── */}
199→        {showEduAiImport && (
