import type { FormEvent } from 'react';
import { useOptimistic, useRef, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router';
import Nav from '../components/Nav';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import { PublishStatusButton } from '../components/PublishStatusButton';
import api from '../lib/api';
import type { Course, Module } from '../lib/types';
import type { Route } from './+types/instructor.course';
import { requireClientUser } from '~/lib/client-auth';

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('PROFESSOR');
  const courseId = Number(params.courseId);
  if (!Number.isFinite(courseId)) {
    throw new Response('Invalid course id', { status: 400 });
  }

  const [course, modules] = await Promise.all([
    api.courseById(courseId) as Promise<Course>,
    api.modulesForCourse(courseId) as Promise<Module[]>,
  ]);

  return { course, modules };
}

export default function InstructorCourseModules({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const { courseId } = useParams();
  const numericCourseId = courseId ? Number(courseId) : null;
  const { course, modules: initialModules } = loaderData;
  const [modules, setModules] = useState<Module[]>(initialModules);
  const [title, setTitle] = useState('');
  const [creating, setCreating] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [availableCourses, setAvailableCourses] = useState<Course[]>([]);
  const [selectedSourceCourseId, setSelectedSourceCourseId] = useState<number | null>(null);
  const [sourceModules, setSourceModules] = useState<Module[]>([]);
  const [loadingSourceCourses, setLoadingSourceCourses] = useState(false);
  const [loadingSourceModules, setLoadingSourceModules] = useState(false);
  const [selectedModuleIds, setSelectedModuleIds] = useState<Set<number>>(new Set());
  const [importing, setImporting] = useState(false);
  const [publishingId, setPublishingId] = useState<number | null>(null);
  const modulesRequestIdRef = useRef(0);

  const [oModules, addModuleOpt] = useOptimistic(
    modules,
    (state, patch: (items: Module[]) => Module[]) => patch(state),
  );

  // Adjust state during render when loader data changes
  const [prevInitialModules, setPrevInitialModules] = useState(initialModules);
  if (initialModules !== prevInitialModules) {
    setPrevInitialModules(initialModules);
    setModules(initialModules);
  }

  const refreshModules = async () => {
    if (!numericCourseId) return;
    try {
      const modulesData = await api.modulesForCourse(numericCourseId);
      setModules(modulesData);
    } catch (error) {
      console.error('Failed to refresh modules', error);
    }
  };

  const ensureSourceCoursesLoaded = () => {
    if (availableCourses.length > 0) return;
    setLoadingSourceCourses(true);
    api
      .listCourses()
      .then((data: Course[]) => {
        const nextCourses = numericCourseId
          ? data.filter((course: Course) => course.id !== numericCourseId)
          : data;
        setAvailableCourses(nextCourses);
      })
      .catch((error) => console.error('Failed to load courses', error))
      .finally(() => setLoadingSourceCourses(false));
  };

  const handleSourceCourseSelection = async (nextCourseId: number | null) => {
    const requestId = ++modulesRequestIdRef.current;
    setSelectedSourceCourseId(nextCourseId);
    setSourceModules([]);
    setSelectedModuleIds(new Set());

    if (nextCourseId == null) {
      setLoadingSourceModules(false);
      return;
    }

    setLoadingSourceModules(true);
    try {
      const data = await api.modulesForCourse(nextCourseId);
      if (modulesRequestIdRef.current === requestId) {
        setSourceModules(data);
      }
    } catch (error) {
      if (modulesRequestIdRef.current === requestId) {
        console.error('Failed to load modules for course', error);
        setSourceModules([]);
      }
    } finally {
      if (modulesRequestIdRef.current === requestId) {
        setLoadingSourceModules(false);
      }
    }
  };

  const onCreateModule = async (event: FormEvent) => {
    event.preventDefault();
    if (!numericCourseId || !title.trim()) return;
    setCreating(true);
    try {
      await api.createModule(numericCourseId, { title: title.trim() });
      setTitle('');
      await refreshModules();
    } catch (error) {
      console.error('Failed to create module', error);
    } finally {
      setCreating(false);
    }
  };

  const toggleModuleSelection = (moduleId: number) => {
    setSelectedModuleIds((prev) => {
      const next = new Set(prev);
      if (next.has(moduleId)) next.delete(moduleId);
      else next.add(moduleId);
      return next;
    });
  };

  const onImport = async () => {
    if (!numericCourseId || selectedSourceCourseId == null || selectedModuleIds.size === 0) return;
    setImporting(true);
    try {
      await api.importIntoCourse(numericCourseId, {
        sourceCourseId: selectedSourceCourseId,
        moduleIds: Array.from(selectedModuleIds),
      });
      setShowImport(false);
      await handleSourceCourseSelection(null);
      await refreshModules();
    } catch (error) {
      console.error('Import failed', error);
    } finally {
      setImporting(false);
    }
  };


  const togglePublish = async (moduleId: number, currentlyPublished: boolean) => {
    // Optimistic update via useOptimistic
    addModuleOpt((items) =>
      items.map((m) => (m.id === moduleId ? { ...m, isPublished: !currentlyPublished } : m)),
    );
    setPublishingId(moduleId);

    try {
      const updated = currentlyPublished
        ? await api.unpublishModule(moduleId)
        : await api.publishModule(moduleId);
      // Confirm with server response
      setModules((prev) => prev.map((m) => (m.id === moduleId ? updated : m)));
    } catch (error) {
      console.error('Failed to toggle publish status', error);
      // Rollback on error to clear optimistic change
      setModules((prev) =>
        prev.map((m) => (m.id === moduleId ? { ...m, isPublished: currentlyPublished } : m)),
      );
    } finally {
      setPublishingId((current) => (current === moduleId ? null : current));
    }
  };

  return (
    <div className="min-h-dvh bg-background relative">
      {/* Subtle atmosphere */}
      <div className="fixed inset-0 dots-pattern opacity-30 pointer-events-none" />
      <div className="fixed top-0 right-0 w-[600px] h-[600px] bg-primary/[0.02] rounded-full blur-3xl pointer-events-none -translate-y-1/2 translate-x-1/3" />

      <Nav />

      <div className="relative container mx-auto max-w-5xl px-4 py-10 space-y-8">
        {/* Breadcrumb */}
        <Breadcrumb className="animate-fade-down">
          <BreadcrumbList>
            <BreadcrumbItem>
              <BreadcrumbLink asChild>
                <Link to="/instructor" className="text-muted-foreground hover:text-primary transition-colors">
                  Teaching
                </Link>
              </BreadcrumbLink>
            </BreadcrumbItem>
            <BreadcrumbSeparator>/</BreadcrumbSeparator>
            <BreadcrumbItem>
              <BreadcrumbPage className="font-medium text-foreground">
                {course?.title || 'Course'}
              </BreadcrumbPage>
            </BreadcrumbItem>
          </BreadcrumbList>
        </Breadcrumb>

        {/* Page header */}
        <div className="flex items-end justify-between gap-4 animate-fade-up">
          <div className="space-y-1">
            <h1 className="font-display text-3xl font-bold tracking-tight text-foreground">
              Modules
            </h1>
            <p className="text-sm text-muted-foreground">
              {oModules.length === 0
                ? 'Get started by creating your first module'
                : `${oModules.length} module${oModules.length !== 1 ? 's' : ''} in this course`}
            </p>
          </div>
          <button
            onClick={() => {
              if (!showImport) {
                ensureSourceCoursesLoaded();
              } else {
                void handleSourceCourseSelection(null);
              }
              setShowImport((prev) => !prev);
            }}
            className="btn-ghost text-sm"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
              {showImport ? (
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              ) : (
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
              )}
            </svg>
            {showImport ? 'Close' : 'Import'}
          </button>
        </div>

        {/* Import panel */}
        {showImport && (
          <div className="card-editorial p-6 space-y-5 animate-scale-in">
            <div className="flex items-center gap-3 mb-1">
              <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
                <svg className="w-4 h-4 text-primary" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
                </svg>
              </div>
              <div>
                <h3 className="font-display text-base font-semibold text-foreground">Import Modules</h3>
                <p className="text-xs text-muted-foreground">Copy modules from another course, including all lessons and activities.</p>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-foreground mb-2">Source course</label>
              <select
                value={selectedSourceCourseId ?? ''}
                onChange={(e) => {
                  const nextValue = e.target.value ? Number(e.target.value) : null;
                  void handleSourceCourseSelection(nextValue);
                }}
                className="input-field"
              >
                <option value="">Select course...</option>
                {availableCourses.map((course) => (
                  <option key={course.id} value={course.id}>
                    {course.title}
                  </option>
                ))}
              </select>
              {loadingSourceCourses && (
                <p className="mt-2 text-xs text-muted-foreground animate-pulse-soft">Loading courses...</p>
              )}
              {!loadingSourceCourses && availableCourses.length === 0 && (
                <p className="mt-2 text-xs text-muted-foreground">
                  No other courses available to copy from.
                </p>
              )}
            </div>

            {selectedSourceCourseId == null ? (
              <p className="text-sm text-muted-foreground italic">Select a course to preview its modules.</p>
            ) : loadingSourceModules ? (
              <p className="text-sm text-muted-foreground animate-pulse-soft">Loading modules...</p>
            ) : sourceModules.length === 0 ? (
              <p className="text-sm text-muted-foreground">Selected course has no modules yet.</p>
            ) : (
              <div className="space-y-4">
                <p className="text-sm text-muted-foreground">
                  Select modules to import (lessons and activities included).
                </p>
                <div className="grid sm:grid-cols-2 gap-3">
                  {sourceModules.map((module, idx) => {
                    const isSelected = selectedModuleIds.has(module.id);
                    return (
                      <label
                        key={module.id}
                        className={`relative p-4 rounded-xl border cursor-pointer transition-all duration-200 animate-fade-up ${
                          isSelected
                            ? 'border-primary ring-2 ring-primary/20 bg-primary/5'
                            : 'border-border hover:border-primary/40 hover:bg-card'
                        }`}
                        style={{ animationDelay: `${idx * 40}ms` }}
                      >
                        <input
                          type="checkbox"
                          className="sr-only"
                          checked={isSelected}
                          onChange={() => toggleModuleSelection(module.id)}
                        />
                        <div className="flex items-start gap-3">
                          <span className={`flex-shrink-0 w-5 h-5 mt-0.5 rounded border-2 flex items-center justify-center transition-all ${
                            isSelected
                              ? 'border-primary bg-primary text-primary-foreground'
                              : 'border-border'
                          }`}>
                            {isSelected && (
                              <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                              </svg>
                            )}
                          </span>
                          <div className="min-w-0">
                            <div className="font-medium text-sm text-foreground">{module.title}</div>
                            {module.description && (
                              <div className="text-xs text-muted-foreground mt-0.5 line-clamp-2">{module.description}</div>
                            )}
                          </div>
                        </div>
                      </label>
                    );
                  })}
                </div>
                <div className="flex items-center justify-between pt-2 border-t border-border">
                  <span className="text-xs text-muted-foreground">
                    {selectedModuleIds.size} of {sourceModules.length} selected
                  </span>
                  <button
                    onClick={onImport}
                    disabled={
                      importing ||
                      selectedSourceCourseId == null ||
                      selectedModuleIds.size === 0
                    }
                    className="btn-primary text-sm"
                  >
                    {importing ? 'Importing...' : `Import module${selectedModuleIds.size !== 1 ? 's' : ''}`}
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Create form */}
        <form onSubmit={onCreateModule} className="flex gap-3 animate-fade-up" style={{ animationDelay: '100ms' }}>
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="New module title..."
            className="input-field flex-1"
          />
          <button
            disabled={creating || !title.trim()}
            className="btn-primary whitespace-nowrap"
          >
            {creating ? 'Adding...' : 'Add Module'}
          </button>
        </form>

        {/* Module list */}
        {oModules.length === 0 ? (
          <div className="card-editorial p-12 text-center animate-fade-up" style={{ animationDelay: '150ms' }}>
            <div className="mx-auto w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center mb-4">
              <svg className="w-6 h-6 text-primary/60" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M12 6.042A8.967 8.967 0 006 3.75c-1.052 0-2.062.18-3 .512v14.25A8.987 8.987 0 016 18c2.305 0 4.408.867 6 2.292m0-14.25a8.966 8.966 0 016-2.292c1.052 0 2.062.18 3 .512v14.25A8.987 8.987 0 0018 18a8.967 8.967 0 00-6 2.292m0-14.25v14.25" />
              </svg>
            </div>
            <p className="text-muted-foreground font-medium">No modules yet</p>
            <p className="text-sm text-muted-foreground/70 mt-1">Create your first module to begin building this course.</p>
          </div>
        ) : (
          <div className="space-y-3">
            {oModules.map((m, idx) => {
              const canPublish = course?.isPublished;
              const blocked = !m.isPublished && !canPublish;
              const tooltipMessage = blocked
                ? `Publish ${m.title} after publishing ${course?.title ?? 'the parent course'}.`
                : null;
              const busy = publishingId === m.id;
              return (
                <div
                  key={m.id}
                  className="card-editorial group cursor-pointer transition-all duration-300 hover:shadow-lg hover:-translate-y-px animate-fade-up"
                  style={{ animationDelay: `${idx * 60}ms` }}
                  onClick={() => navigate(`/instructor/module/${m.id}`)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={(event) => {
                    if (event.key === 'Enter' || event.key === ' ') {
                      event.preventDefault();
                      navigate(`/instructor/module/${m.id}`);
                    }
                  }}
                >
                  <div className="flex items-center gap-5 p-5">
                    {/* Editorial number */}
                    <span className="flex-shrink-0 font-mono text-lg tabular-nums text-primary/40 group-hover:text-primary transition-colors duration-300 w-8 text-right">
                      {String(idx + 1).padStart(2, '0')}
                    </span>

                    {/* Divider line */}
                    <div className="w-px h-10 bg-border group-hover:bg-primary/30 transition-colors duration-300" />

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <h3 className="font-display text-base font-semibold text-foreground group-hover:text-primary transition-colors duration-300 truncate">
                        {m.title}
                      </h3>
                      {m.description && (
                        <p className="text-sm text-muted-foreground mt-0.5 line-clamp-1">{m.description}</p>
                      )}
                    </div>

                    {/* Status + arrow */}
                    <div className="flex items-center gap-3 flex-shrink-0">
                      <div onClick={(e) => e.stopPropagation()} onKeyDown={(e) => e.stopPropagation()}>
                        <PublishStatusButton
                          isPublished={m.isPublished}
                          pending={busy}
                          blockedReason={tooltipMessage}
                          onClick={() => {
                            if (busy || blocked) return;
                            togglePublish(m.id, m.isPublished);
                          }}
                        />
                      </div>
                      <svg
                        className="w-4 h-4 text-muted-foreground/40 group-hover:text-primary group-hover:translate-x-0.5 transition-all duration-300"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                        strokeWidth={1.5}
                      >
                        <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                      </svg>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import { useEffect, useOptimistic, useRef, useState } from 'react';
import { Link, useParams } from 'react-router';
import AddActivityPanel from '../components/AddActivityPanel';
import ActivityDetailsCard from '../components/ActivityDetailsCard';
import EditActivityPanel from '../components/EditActivityPanel';
import AddCourseTopicsButton from '../components/AddCourseTopicsButton';
import Nav from '../components/Nav';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import api from '../lib/api';
import type { Activity, Course, Lesson, ModuleDetail } from '../lib/types';
import { CourseTopicsProvider, useCourseTopics } from '../hooks/useCourseTopics';
import type { Route } from './+types/instructor.list';
import { requireClientUser } from '~/lib/client-auth';

import type { ActivityUpdatePayload } from '../lib/activityForm';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '~/components/ui/tooltip';
import TopicSyncMappingDialog from '~/components/TopicSyncMappingDialog';

function SyncTopicsButton({
  courseId,
  syncing,
  onSync,
}: {
  courseId: number;
  syncing: boolean;
  onSync: () => Promise<void>;
}) {
  const label = syncing ? 'Syncing…' : 'Sync now';
  return (
    <TooltipProvider delayDuration={150}>
      <Tooltip>
        <TooltipTrigger asChild>
          <button
            type="button"
            aria-label="Sync topics now"
            onClick={() => {
              if (!syncing) onSync();
            }}
            disabled={syncing}
            className="w-full btn-secondary text-sm"
          >
            {label}
          </button>
        </TooltipTrigger>
        <TooltipContent>Topics are synced from EduAI for this course.</TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('PROFESSOR');
  const lessonId = Number(params.lessonId);
  if (!Number.isFinite(lessonId)) {
    throw new Response('Invalid lesson id', { status: 400 });
  }

  const [lesson, activities] = await Promise.all([
    api.lessonById(lessonId) as Promise<Lesson>,
    api.activitiesForLesson(lessonId) as Promise<Activity[]>,
  ]);

  let module: ModuleDetail | null = null;
  let course: Course | null = null;
  if (lesson.moduleId) {
    module = (await api.moduleById(lesson.moduleId)) as ModuleDetail;
    if (module.courseOfferingId) {
      course = (await api.courseById(module.courseOfferingId)) as Course;
    }
  }

  return { course, module, lesson, activities };
}

export default function InstructorLessonBuilder({ loaderData }: Route.ComponentProps) {
  const { lessonId } = useParams();
  const numericLessonId = lessonId ? Number(lessonId) : null;
  const { course, module, lesson, activities: initialActivities } = loaderData;
  const [activities, setActivities] = useState<Activity[]>(initialActivities);
  const [oActivities, addActivityOpt] = useOptimistic(
    activities,
    (state, patch: (items: Activity[]) => Activity[]) => patch(state),
  );

  const [updatingTopicsFor, setUpdatingTopicsFor] = useState<number | null>(null);
  const [updatingModesFor, setUpdatingModesFor] = useState<number | null>(null);

  const [showAddPanel, setShowAddPanel] = useState(false);

  const [editingActivityId, setEditingActivityId] = useState<number | null>(null);
  const [savingActivityId, setSavingActivityId] = useState<number | null>(null);
  const [deletingActivityId, setDeletingActivityId] = useState<number | null>(null);
  const [editError, setEditError] = useState<string | null>(null);

  const courseOfferingId = lesson?.courseOfferingId ?? null;
  const courseTopics = useCourseTopics(courseOfferingId);
  const { topics, loading: loadingTopics, error: topicsError } = courseTopics;
  const [syncingTopics, setSyncingTopics] = useState(false);
  const [showMapping, setShowMapping] = useState(false);
  const [missingTopics, setMissingTopics] = useState<{ id: number; name: string }[]>([]);

  const [showTopicSaving, setShowTopicSaving] = useState(false);
  const topicSavingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const [showModeSaving, setShowModeSaving] = useState(false);
  const modeSavingTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [promptDrafts, setPromptDrafts] = useState<Record<number, string>>({});
  const [titleDrafts, setTitleDrafts] = useState<Record<number, string>>({});
  const [savingPromptId, setSavingPromptId] = useState<number | null>(null);
  const [promptErrors, setPromptErrors] = useState<Record<number, string>>({});
  const [promptSaved, setPromptSaved] = useState<Record<number, boolean>>({});

  const beginTopicUpdate = (activityId: number) => {
    setUpdatingTopicsFor(activityId);
    setShowTopicSaving(false);
    if (topicSavingTimeoutRef.current) {
      clearTimeout(topicSavingTimeoutRef.current);
    }
    topicSavingTimeoutRef.current = setTimeout(() => setShowTopicSaving(true), 300);
  };

  const endTopicUpdate = (activityId: number) => {
    let shouldClear = false;
    setUpdatingTopicsFor((current) => {
      if (current !== activityId) {
        return current;
      }
      shouldClear = true;
      return null;
    });
    if (shouldClear) {
      if (topicSavingTimeoutRef.current) {
        clearTimeout(topicSavingTimeoutRef.current);
        topicSavingTimeoutRef.current = null;
      }
      setShowTopicSaving(false);
    }
  };

  const beginModeUpdate = (activityId: number) => {
    setUpdatingModesFor(activityId);
    setShowModeSaving(false);
    if (modeSavingTimeoutRef.current) {
      clearTimeout(modeSavingTimeoutRef.current);
    }
    modeSavingTimeoutRef.current = setTimeout(() => setShowModeSaving(true), 300);
  };

  const endModeUpdate = (activityId: number) => {
    let shouldClear = false;
    setUpdatingModesFor((current) => {
      if (current !== activityId) {
        return current;
      }
      shouldClear = true;
      return null;
    });
    if (shouldClear) {
      if (modeSavingTimeoutRef.current) {
        clearTimeout(modeSavingTimeoutRef.current);
        modeSavingTimeoutRef.current = null;
      }
      setShowModeSaving(false);
    }
  };

  // Adjust state during render when loader data changes
  const [prevInitialActivities, setPrevInitialActivities] = useState(initialActivities);
  if (initialActivities !== prevInitialActivities) {
    setPrevInitialActivities(initialActivities);
    setActivities(initialActivities);
  }

  const beginEditingActivity = (activity: Activity) => {
    setEditingActivityId(activity.id);
    setEditError(null);
  };

  const cancelEditingActivity = () => {
    setEditingActivityId(null);
    setSavingActivityId(null);
    setEditError(null);
  };

  const handleEditSubmit = async (activityId: number, payload: ActivityUpdatePayload) => {
    setEditError(null);
    setSavingActivityId(activityId);
    try {
      const updatePayload: Parameters<typeof api.updateActivity>[1] = {
        title: payload.title,
        instructionsMd: payload.instructionsMd,
        question: payload.question,
        type: payload.type,
        options: payload.options,
        answer: payload.answer,
        hints: payload.hints,
      };

      const updated = await api.updateActivity(activityId, updatePayload);
      setActivities((prev) =>
        prev.map((activity) => (activity.id === activityId ? updated : activity)),
      );
      cancelEditingActivity();
    } catch (error) {
      console.error('Failed to update activity', error);
      setEditError('Could not save activity. Please try again.');
    } finally {
      setSavingActivityId((current) => (current === activityId ? null : current));
    }
  };

  const refreshActivities = async () => {
    if (!numericLessonId) return;
    try {
      const activityData = await api.activitiesForLesson(numericLessonId);
      setActivities(activityData);
    } catch (error) {
      console.error('Failed to refresh activities', error);
    }
  };

  useEffect(() => {
    return () => {
      if (topicSavingTimeoutRef.current) {
        clearTimeout(topicSavingTimeoutRef.current);
        topicSavingTimeoutRef.current = null;
      }
      if (modeSavingTimeoutRef.current) {
        clearTimeout(modeSavingTimeoutRef.current);
        modeSavingTimeoutRef.current = null;
      }
    };
  }, []);



  const handleDeleteActivity = async (activityId: number) => {
    if (typeof window === 'undefined') {
      return;
    }
    const confirmed = window.confirm('Remove this activity? This action cannot be undone.');
    if (!confirmed) {
      return;
    }

    setDeletingActivityId(activityId);
    try {
      await api.deleteActivity(activityId);
      setActivities((prev) => prev.filter((activity) => activity.id !== activityId));
      if (editingActivityId === activityId) {
        cancelEditingActivity();
      }
    } catch (error) {
      console.error('Failed to remove activity', error);
      alert('Failed to remove activity. Please try again.');
    } finally {
      setDeletingActivityId((current) => (current === activityId ? null : current));
    }
  };

  const handleActivityModeChange = async (
    activityId: number,
    mode: 'teach' | 'guide' | 'custom',
    enabled: boolean
  ) => {
    const activity = oActivities.find((a) => a.id === activityId);
    if (!activity) return;

    const newTeach = mode === 'teach' ? enabled : activity.enableTeachMode;
    const newGuide = mode === 'guide' ? enabled : activity.enableGuideMode;
    const newCustom = mode === 'custom' ? enabled : activity.enableCustomMode;

    if (!newTeach && !newGuide && !newCustom) {
      alert('At least one AI mode must be enabled');
      return;
    }

    // Optimistic UI via useOptimistic
    addActivityOpt((items) =>
      items.map((a) =>
        a.id === activityId
          ? {
              ...a,
              enableTeachMode: newTeach,
              enableGuideMode: newGuide,
              enableCustomMode: newCustom,
              customPrompt: mode === 'custom' && !enabled ? null : a.customPrompt,
            }
          : a,
      ),
    );
    if (mode === 'custom' && !enabled) {
      setPromptSaved((prev) => ({ ...prev, [activityId]: false }));
    }

    beginModeUpdate(activityId);
    try {
      const payload: Record<string, unknown> = {
        enableTeachMode: newTeach,
        enableGuideMode: newGuide,
        enableCustomMode: newCustom,
      };
      if (mode === 'custom' && !enabled) {
        payload.customPrompt = null;
      }
      const updated = await api.updateActivity(activityId, payload);
      setActivities((prev) => prev.map((a) => (a.id === activityId ? updated : a)));
    } catch (error) {
      console.error('Failed to update AI modes', error);
    } finally {
      endModeUpdate(activityId);
    }
  };

  const handleCustomPromptSave = async (activity: Activity) => {
    const draft = (promptDrafts[activity.id] ?? activity.customPrompt ?? '').trim();
    const titleDraft = (titleDrafts[activity.id] ?? activity.customPromptTitle ?? '').trim().slice(0, 20);

    // Validate: both title and prompt are required
    if (!titleDraft) {
      setPromptErrors((prev) => ({
        ...prev,
        [activity.id]: 'Please provide a title for the custom prompt (max 20 characters).',
      }));
      return;
    }
    if (!draft) {
      setPromptErrors((prev) => ({
        ...prev,
        [activity.id]: 'Please provide the custom prompt text.',
      }));
      return;
    }

    setPromptErrors((prev) => ({ ...prev, [activity.id]: '' }));

    addActivityOpt((items) =>
      items.map((item) =>
        item.id === activity.id
          ? { ...item, customPrompt: draft, customPromptTitle: titleDraft }
          : item,
      ),
    );
    setSavingPromptId(activity.id);
    try {
      const updated = await api.updateActivity(activity.id, {
        customPrompt: draft,
        customPromptTitle: titleDraft,
      });
      setActivities((prev) =>
        prev.map((item) => (item.id === activity.id ? updated : item)),
      );
      setPromptSaved((prev) => ({ ...prev, [activity.id]: true }));
    } catch (error) {
      console.error('Failed to save custom prompt', error);
      setPromptErrors((prev) => ({
        ...prev,
        [activity.id]: 'Could not save the custom prompt. Please try again.',
      }));
      setActivities((prev) => [...prev]);
    } finally {
      setSavingPromptId((current) => (current === activity.id ? null : current));
    }
  };

  const handleActivityMainTopicChange = async (activityId: number, value: string) => {
    if (!value) return;
    const newTopicId = Number(value);
    if (!Number.isFinite(newTopicId)) return;

    const topic = topics.find((entry) => entry.id === newTopicId);
    if (!topic) return;

    const targetActivity = oActivities.find((activity) => activity.id === activityId);
    if (!targetActivity) return;
    // Optimistic UI via useOptimistic
    addActivityOpt((items) =>
      items.map((activity) =>
        activity.id === activityId
          ? {
              ...activity,
              mainTopic: topic,
              secondaryTopics: activity.secondaryTopics.filter((item) => item.id !== newTopicId),
            }
          : activity,
      ),
    );

    beginTopicUpdate(activityId);
    try {
      const updated = await api.updateActivity(activityId, { mainTopicId: newTopicId });
      setActivities((prev) =>
        prev.map((activity) =>
          activity.id === activityId
            ? {
                ...activity,
                mainTopic: updated.mainTopic,
                secondaryTopics: updated.secondaryTopics,
              }
            : activity,
        ),
      );
    } catch (error) {
      console.error('Failed to update main topic', error);
      // Base state remains unchanged; optimistic view will clear on next render
    } finally {
      endTopicUpdate(activityId);
    }
  };

  const handleActivitySecondaryToggle = async (
    activityId: number,
    topicId: number,
    checked: boolean,
  ) => {
    const topic = topics.find((entry) => entry.id === topicId);
    if (!topic) return;

    const targetActivity = oActivities.find((activity) => activity.id === activityId);
    if (!targetActivity) return;

    const nextSecondary = checked
      ? [...targetActivity.secondaryTopics.filter((item) => item.id !== topicId), topic]
      : targetActivity.secondaryTopics.filter((item) => item.id !== topicId);

    // Optimistic UI via useOptimistic
    addActivityOpt((items) =>
      items.map((activity) =>
        activity.id === activityId
          ? {
              ...activity,
              secondaryTopics: nextSecondary.sort((a, b) => a.name.localeCompare(b.name)),
            }
          : activity,
      ),
    );

    beginTopicUpdate(activityId);
    try {
      const updated = await api.updateActivity(activityId, {
        secondaryTopicIds: nextSecondary.map((item) => item.id),
      });
      setActivities((prev) =>
        prev.map((activity) =>
          activity.id === activityId
            ? {
                ...activity,
                secondaryTopics: updated.secondaryTopics,
                mainTopic: updated.mainTopic,
              }
            : activity,
        ),
      );
    } catch (error) {
      console.error('Failed to update secondary topics', error);
      // Base state remains unchanged; optimistic view will clear on next render
    } finally {
      endTopicUpdate(activityId);
    }
  };

  return (
    <CourseTopicsProvider value={courseTopics}>
      <div className="min-h-dvh bg-background">
        <Nav />

        {/* Hero header */}
        <div className="relative border-b border-border bg-card overflow-hidden">
          <div className="absolute inset-0 dots-pattern opacity-40" />
          <div className="relative container mx-auto px-4 pt-6 pb-8">
            <Breadcrumb className="mb-5 animate-fade-down">
              <BreadcrumbList>
                <BreadcrumbItem>
                  <BreadcrumbLink asChild>
                    <Link to="/instructor" className="text-muted-foreground hover:text-primary transition-colors">Teaching</Link>
                  </BreadcrumbLink>
                </BreadcrumbItem>
                <BreadcrumbSeparator>/</BreadcrumbSeparator>
                <BreadcrumbItem>
                  {course && module ? (
                    <BreadcrumbLink asChild>
                      <Link to={`/instructor/courses/${module.courseOfferingId}`} className="text-muted-foreground hover:text-primary transition-colors">{course.title}</Link>
                    </BreadcrumbLink>
                  ) : (
                    <BreadcrumbPage>Course</BreadcrumbPage>
                  )}
                </BreadcrumbItem>
                <BreadcrumbSeparator>/</BreadcrumbSeparator>
                <BreadcrumbItem>
                  {module && lesson ? (
                    <BreadcrumbLink asChild>
                      <Link to={`/instructor/module/${lesson.moduleId}`} className="text-muted-foreground hover:text-primary transition-colors">{module.title}</Link>
                    </BreadcrumbLink>
                  ) : (
                    <BreadcrumbPage>Module</BreadcrumbPage>
                  )}
                </BreadcrumbItem>
                <BreadcrumbSeparator>/</BreadcrumbSeparator>
                <BreadcrumbItem>
                  <BreadcrumbPage className="font-semibold text-foreground">{lesson?.title || 'Lesson'}</BreadcrumbPage>
                </BreadcrumbItem>
              </BreadcrumbList>
            </Breadcrumb>

            <div className="flex items-end justify-between gap-4 animate-fade-up">
              <div>
                <h1 className="font-display text-3xl font-bold tracking-tight text-foreground">
                  {lesson?.title || 'Lesson'}
                </h1>
                <p className="mt-1.5 text-sm text-muted-foreground">
                  {oActivities.length === 0
                    ? 'No activities yet — create your first one below.'
                    : `${oActivities.length} ${oActivities.length === 1 ? 'activity' : 'activities'} in this lesson`}
                </p>
              </div>
              <button
                type="button"
                onClick={() => setShowAddPanel((open) => !open)}
                className="btn-primary flex-shrink-0"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d={showAddPanel ? "M6 18L18 6M6 6l12 12" : "M12 4.5v15m7.5-7.5h-15"} /></svg>
                {showAddPanel ? 'Close panel' : 'New activity'}
              </button>
            </div>
          </div>
        </div>

        {/* Main content */}
        <div className="container mx-auto px-4 py-8">
          <div className="grid grid-cols-1 lg:grid-cols-[1fr_320px] gap-8 items-start">

            {/* Left column: Activities */}
            <div className="space-y-6">
              {/* Add activity panel (collapsible) */}
              {showAddPanel && numericLessonId !== null && (
                <div className="animate-scale-in">
                  <AddActivityPanel
                    lessonId={numericLessonId}
                    onActivityCreated={refreshActivities}
                  />
                </div>
              )}

              {/* Activity list */}
              {oActivities.length === 0 ? (
                <div className="card-editorial p-12 text-center animate-fade-up">
                  <div className="mx-auto w-16 h-16 rounded-2xl bg-primary/10 flex items-center justify-center mb-4">
                    <svg className="w-8 h-8 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 0 0-3.375-3.375h-1.5A1.125 1.125 0 0 1 13.5 7.125v-1.5a3.375 3.375 0 0 0-3.375-3.375H8.25m3.75 9v6m3-3H9m1.5-12H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 0 0-9-9Z" /></svg>
                  </div>
                  <h3 className="font-display text-lg font-semibold text-foreground mb-1">No activities yet</h3>
                  <p className="text-sm text-muted-foreground max-w-xs mx-auto">
                    Click "New activity" above to begin building this lesson.
                  </p>
                </div>
              ) : (
                <div className="space-y-4">
                  {oActivities.map((activity, i) => {
                    const isUpdatingTopics = updatingTopicsFor === activity.id;
                    const isUpdatingModes = updatingModesFor === activity.id;
                    const mainTopicId = activity.mainTopic?.id ?? '';
                    const secondaryIds = new Set(activity.secondaryTopics.map((item) => item.id));
                    const isEditing = editingActivityId === activity.id;
                    const isSaving = savingActivityId === activity.id;
                    const isDeleting = deletingActivityId === activity.id;
                    const isCustomEnabled = activity.enableCustomMode;
                    const promptDraft = promptDrafts[activity.id] ?? activity.customPrompt ?? '';
                    const isSavingPrompt = savingPromptId === activity.id;
                    const isPromptSaved =
                      promptSaved[activity.id] ??
                      Boolean(activity.enableCustomMode && activity.customPrompt);
                    const promptError = promptErrors[activity.id];
                    return (
                      <article
                        key={activity.id}
                        className="card-editorial overflow-hidden animate-fade-up"
                        style={{ animationDelay: `${i * 60}ms` }}
                      >
                        {/* Activity header */}
                        <div className="px-5 py-4 border-b border-border/60">
                          <div className="flex items-start justify-between gap-3">
                            <div className="flex items-start gap-3 min-w-0">
                              <span className="flex-shrink-0 w-8 h-8 rounded-xl bg-primary/10 text-primary flex items-center justify-center font-mono font-bold text-sm">
                                {i + 1}
                              </span>
                              <div className="min-w-0">
                                <div className="flex items-center gap-2 mb-1">
                                  <span className="tag tag-primary text-[0.65rem]">
                                    {activity.type === 'MCQ' ? 'Multiple Choice' : 'Short Answer'}
                                  </span>
                                  {(isSaving || isDeleting) && (
                                    <span className="tag text-[0.65rem] animate-pulse-soft">
                                      {isSaving ? 'Saving…' : 'Removing…'}
                                    </span>
                                  )}
                                </div>
                                <p className="font-medium text-foreground whitespace-pre-wrap leading-relaxed">
                                  {activity.question}
                                </p>
                              </div>
                            </div>

                            <div className="flex items-center gap-1.5 flex-shrink-0">
                              {isEditing ? (
                                <span className="tag tag-accent text-[0.65rem]">
                                  Editing
                                </span>
                              ) : (
                                <>
                                  <button
                                    type="button"
                                    onClick={() => beginEditingActivity(activity)}
                                    className="btn-ghost text-xs px-3 py-1.5"
                                    disabled={isDeleting}
                                  >
                                    <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m16.862 4.487 1.687-1.688a1.875 1.875 0 1 1 2.652 2.652L10.582 16.07a4.5 4.5 0 0 1-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 0 1 1.13-1.897l8.932-8.931Zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0 1 15.75 21H5.25A2.25 2.25 0 0 1 3 18.75V8.25A2.25 2.25 0 0 1 5.25 6H10" /></svg>
                                    Edit
                                  </button>
                                  <button
                                    type="button"
                                    onClick={() => handleDeleteActivity(activity.id)}
                                    className="btn-ghost text-xs px-3 py-1.5 text-destructive hover:text-destructive hover:bg-destructive/10"
                                    disabled={isDeleting}
                                  >
                                    {isDeleting ? 'Removing…' : 'Remove'}
                                  </button>
                                </>
                              )}
                            </div>
                          </div>
                        </div>

                        {/* Activity body */}
                        <div className="px-5 py-4 space-y-4">
                          {isEditing ? (
                            <EditActivityPanel
                              key={activity.id}
                              activity={activity}
                              busy={isSaving}
                              error={editError}
                              onSubmit={(payload) => handleEditSubmit(activity.id, payload)}
                              onCancel={cancelEditingActivity}
                            />
                          ) : (
                            <ActivityDetailsCard activity={activity} />
                          )}

                          {/* Topic assignment section */}
                          <div className="rounded-xl border border-border bg-accent/5 overflow-hidden">
                            <div className="px-4 py-2.5 border-b border-border/60 bg-accent/10">
                              <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                  <svg className="w-3.5 h-3.5 text-accent-foreground" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M9.568 3H5.25A2.25 2.25 0 0 0 3 5.25v4.318c0 .597.237 1.17.659 1.591l9.581 9.581c.699.699 1.78.872 2.607.33a18.095 18.095 0 0 0 5.223-5.223c.542-.827.369-1.908-.33-2.607L11.16 3.66A2.25 2.25 0 0 0 9.568 3Z" /><path strokeLinecap="round" strokeLinejoin="round" d="M6 6h.008v.008H6V6Z" /></svg>
                                  <span className="text-xs font-semibold text-accent-foreground tracking-wide uppercase">Topics</span>
                                </div>
                                {showTopicSaving && isUpdatingTopics && (
                                  <span className="text-[0.65rem] text-accent-foreground animate-pulse-soft">Saving…</span>
                                )}
                              </div>
                            </div>
                            <div className="p-4 space-y-3">
                              {topics.length === 0 ? (
                                <p className="text-xs text-muted-foreground">
                                  Define course topics in the sidebar to tag this activity.
                                </p>
                              ) : (
                                <>
                                  <div>
                                    <label className="text-xs font-semibold text-muted-foreground block mb-1.5">
                                      Main topic
                                    </label>
                                    <select
                                      value={mainTopicId}
                                      onChange={(event) =>
                                        handleActivityMainTopicChange(activity.id, event.target.value)
                                      }
                                      disabled={loadingTopics || isUpdatingTopics}
                                      className={`input-field text-sm ${
                                        showTopicSaving ? 'disabled:opacity-60' : ''
                                      }`}
                                    >
                                      <option value="">Select a topic…</option>
                                      {topics.map((topic) => (
                                        <option key={topic.id} value={topic.id}>
                                          {topic.name}
                                        </option>
                                      ))}
                                    </select>
                                  </div>
                                  <div>
                                    <span className="text-xs font-semibold text-muted-foreground block mb-2">
                                      Secondary topics
                                    </span>
                                    <div className="flex flex-wrap gap-1.5">
                                      {topics
                                        .filter((topic) => topic.id !== mainTopicId)
                                        .map((topic) => {
                                          const checked = secondaryIds.has(topic.id);
                                          return (
                                            <label
                                              key={topic.id}
                                              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs cursor-pointer transition-all duration-200 ${
                                                checked
                                                  ? 'tag-accent shadow-sm font-semibold'
                                                  : 'bg-secondary text-secondary-foreground hover:bg-muted border border-border'
                                              } ${
                                                showTopicSaving && isUpdatingTopics ? 'opacity-60' : ''
                                              }`}
                                            >
                                              <input
                                                type="checkbox"
                                                className="sr-only"
                                                checked={checked}
                                                disabled={isUpdatingTopics}
                                                onChange={(event) =>
                                                  handleActivitySecondaryToggle(
                                                    activity.id,
                                                    topic.id,
                                                    event.target.checked,
                                                  )
                                                }
                                              />
                                              {checked && (
                                                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" /></svg>
                                              )}
                                              {topic.name}
                                            </label>
                                          );
                                        })}
                                    </div>
                                  </div>
                                </>
                              )}
                            </div>
                          </div>

                          {/* AI modes section */}
                          <div className="rounded-xl border border-border bg-primary/[0.03] overflow-hidden">
                            <div className="px-4 py-2.5 border-b border-border/60 bg-primary/[0.06]">
                              <div className="flex items-center justify-between">
                                <div className="flex items-center gap-2">
                                  <svg className="w-3.5 h-3.5 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904 9 18.75l-.813-2.846a4.5 4.5 0 0 0-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 0 0 3.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 0 0 3.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 0 0-3.09 3.09ZM18.259 8.715 18 9.75l-.259-1.035a3.375 3.375 0 0 0-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 0 0 2.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 0 0 2.455 2.456L21.75 6l-1.036.259a3.375 3.375 0 0 0-2.455 2.456ZM16.894 20.567 16.5 21.75l-.394-1.183a2.25 2.25 0 0 0-1.423-1.423L13.5 18.75l1.183-.394a2.25 2.25 0 0 0 1.423-1.423l.394-1.183.394 1.183a2.25 2.25 0 0 0 1.423 1.423l1.183.394-1.183.394a2.25 2.25 0 0 0-1.423 1.423Z" /></svg>
                                  <span className="text-xs font-semibold text-primary tracking-wide uppercase">AI Modes</span>
                                </div>
                                {showModeSaving && isUpdatingModes && (
                                  <span className="text-[0.65rem] text-primary animate-pulse-soft">Saving…</span>
                                )}
                              </div>
                            </div>
                            <div className="p-4 space-y-3">
                              <div className="flex flex-wrap gap-3">
                                <label className="flex items-center gap-2 cursor-pointer group">
                                  <input
                                    type="checkbox"
                                    checked={activity.enableTeachMode}
                                    onChange={(e) => handleActivityModeChange(activity.id, 'teach', e.target.checked)}
                                    disabled={isUpdatingModes}
                                    className="rounded border-primary/50 text-primary focus:ring-primary"
                                  />
                                  <span className="text-sm text-foreground group-hover:text-primary transition-colors">Teach me</span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer group">
                                  <input
                                    type="checkbox"
                                    checked={activity.enableGuideMode}
                                    onChange={(e) => handleActivityModeChange(activity.id, 'guide', e.target.checked)}
                                    disabled={isUpdatingModes}
                                    className="rounded border-primary/50 text-primary focus:ring-primary"
                                  />
                                  <span className="text-sm text-foreground group-hover:text-primary transition-colors">Guide me</span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer group">
                                  <input
                                    type="checkbox"
                                    checked={activity.enableCustomMode}
                                    onChange={(e) =>
                                      handleActivityModeChange(activity.id, 'custom', e.target.checked)
                                    }
                                    disabled={isUpdatingModes}
                                    className="rounded border-primary/50 text-primary focus:ring-primary"
                                  />
                                  <span className="text-sm text-foreground group-hover:text-primary transition-colors">Custom prompt</span>
                                </label>
                              </div>

                              {isCustomEnabled && (
                                <div className="mt-2 pt-3 border-t border-border/50 space-y-3">
                                  <div>
                                    <label className="text-xs font-semibold text-primary block mb-1.5">
                                      Button title
                                      <span className="text-muted-foreground font-normal ml-1">(shown to students, max 20 chars)</span>
                                    </label>
                                    <input
                                      type="text"
                                      value={titleDrafts[activity.id] ?? activity.customPromptTitle ?? ''}
                                      onChange={(event) => {
                                        const value = event.target.value.slice(0, 20);
                                        setTitleDrafts((prev) => ({ ...prev, [activity.id]: value }));
                                        setPromptSaved((saved) => ({ ...saved, [activity.id]: false }));
                                      }}
                                      placeholder="e.g., Explain simply"
                                      maxLength={20}
                                      className="input-field text-sm"
                                      disabled={isSavingPrompt}
                                    />
                                    <div className="text-[0.65rem] text-muted-foreground mt-1 font-mono">
                                      {(titleDrafts[activity.id] ?? activity.customPromptTitle ?? '').length}/20
                                    </div>
                                  </div>
                                  <div>
                                    <label className="text-xs font-semibold text-primary block mb-1.5">
                                      Custom AI prompt
                                    </label>
                                    <textarea
                                      value={promptDraft}
                                      onChange={(event) =>
                                        setPromptDrafts((prev) => {
                                          setPromptSaved((saved) => ({ ...saved, [activity.id]: false }));
                                          return {
                                            ...prev,
                                            [activity.id]: event.target.value,
                                          };
                                        })
                                      }
                                      placeholder="Write a custom prompt the AI should follow for this activity…"
                                      rows={3}
                                      className="input-field text-sm"
                                      disabled={isSavingPrompt}
                                    />
                                    <p className="text-[0.65rem] text-muted-foreground mt-1">
                                      Tip: Use <code className="font-mono bg-secondary px-1.5 py-0.5 rounded text-foreground">[INSERT TOPIC HERE]</code> and <code className="font-mono bg-secondary px-1.5 py-0.5 rounded text-foreground">[ENTER KNOWLEDGE LEVEL]</code> as placeholders.
                                    </p>
                                  </div>
                                  <div className="flex items-center gap-3">
                                    <button
                                      type="button"
                                      onClick={() => handleCustomPromptSave(activity)}
                                      disabled={isSavingPrompt}
                                      className="btn-primary text-xs py-2"
                                    >
                                      {isSavingPrompt ? 'Saving…' : isPromptSaved ? 'Saved' : 'Save prompt'}
                                    </button>
                                    {promptError && (
                                      <span className="text-[0.75rem] text-destructive">
                                        {promptError}
                                      </span>
                                    )}
                                    {!promptError && isSavingPrompt && (
                                      <span className="text-[0.75rem] text-primary animate-pulse-soft">
                                        Saving prompt…
                                      </span>
                                    )}
                                  </div>
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      </article>
                    );
                  })}
                </div>
              )}
            </div>

            {/* Right column: Topics sidebar */}
            <aside className="lg:sticky lg:top-6 space-y-4 animate-slide-in-right">
              <div className="card-editorial overflow-hidden">
                <div className="px-5 py-4 border-b border-border/60 bg-card">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <svg className="w-4 h-4 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M9.568 3H5.25A2.25 2.25 0 0 0 3 5.25v4.318c0 .597.237 1.17.659 1.591l9.581 9.581c.699.699 1.78.872 2.607.33a18.095 18.095 0 0 0 5.223-5.223c.542-.827.369-1.908-.33-2.607L11.16 3.66A2.25 2.25 0 0 0 9.568 3Z" /><path strokeLinecap="round" strokeLinejoin="round" d="M6 6h.008v.008H6V6Z" /></svg>
                      <h2 className="font-display text-base font-semibold text-foreground">Course Topics</h2>
                    </div>
                    {lesson?.courseOfferingId && (
                      <span className="font-mono text-[0.65rem] text-muted-foreground">#{lesson.courseOfferingId}</span>
                    )}
                  </div>
                </div>

                <div className="p-5 space-y-4">
                  {topicsError && <p className="text-xs text-destructive">{topicsError}</p>}

                  <div className="flex items-center gap-2">
                    {!!course?.externalId || course?.externalSource === 'EDUAI' ? (
                      // EduAI course: Show only sync button
                      lesson?.courseOfferingId && (
                        <SyncTopicsButton
                          courseId={lesson.courseOfferingId}
                          syncing={syncingTopics}
                          onSync={async () => {
                            if (!lesson?.courseOfferingId) return;
                            setSyncingTopics(true);
                            try {
                              const result = await api.syncCourseTopics(lesson.courseOfferingId);
                              // Refresh topics first so the dialog options reflect latest topics
                              await courseTopics.refresh();
                              if (result && Array.isArray(result.missingTopics) && result.missingTopics.length > 0) {
                                setMissingTopics(result.missingTopics.map((t: any) => ({ id: t.id, name: t.name })));
                                setShowMapping(true);
                              }
                            } catch (e) {
                              console.error('Failed to sync topics', e);
                              alert('Failed to sync topics from EduAI. Please try again.');
                            } finally {
                              setSyncingTopics(false);
                            }
                          }}
                        />
                      )
                    ) : (
                      // Regular course: Show add topics button
                      <AddCourseTopicsButton
                        disabled={!lesson?.courseOfferingId}
                      />
                    )}
                  </div>

                  <div className="space-y-1.5 max-h-56 overflow-y-auto">
                    {topics.length === 0 ? (
                      <p className="text-xs text-muted-foreground py-2">No topics defined yet.</p>
                    ) : (
                      <div className="flex flex-wrap gap-1.5">
                        {topics.map((topic) => (
                          <span key={topic.id} className="tag tag-primary">
                            {topic.name}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </aside>
          </div>
        </div>
      </div>
      <TopicSyncMappingDialog
        open={showMapping}
        onClose={() => setShowMapping(false)}
        topics={topics}
        missing={missingTopics}
        busy={syncingTopics}
        onApply={async (mappings) => {
          if (!lesson?.courseOfferingId) return;
          await api.remapCourseTopics(lesson.courseOfferingId, mappings);
          await Promise.all([courseTopics.refresh(), refreshActivities()]);
        }}
      />
    </CourseTopicsProvider>
  );
}

