                  }`}>
                    <div className={`w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 ${
                      wasCorrect ? 'bg-sage-200/60 dark:bg-sage-800/40' : 'bg-terracotta-200/40 dark:bg-terracotta-800/30'
                    }`}>
                      {wasCorrect ? (
                        <svg className="w-4 h-4 text-sage-700 dark:text-sage-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75L11.25 15 15 9.75M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                        </svg>
                      ) : (
                        <svg className="w-4 h-4 text-terracotta-600 dark:text-terracotta-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
                        </svg>
                      )}
                    </div>
                    <div>
                      <span className="font-display font-bold text-base">{result}</span>
                      {wasCorrect && canNext && (
                        <p className="text-xs text-muted-foreground mt-1">Press Next to continue to the next question.</p>
                      )}
                    </div>
                  </div>
                )}

                {/* Feedback card */}
                {activity &&
                  currentFeedback.promptShown &&
                  !currentFeedback.dismissed &&
                  (currentFeedback.promptVisible || currentFeedback.submitted) && (
                  <StudentActivityFeedbackCard
                    rating={currentFeedback.rating}
                    note={currentFeedback.note}
                    saving={currentFeedback.saving}
                    submitted={currentFeedback.submitted}
                    error={currentFeedback.error}
                    onSelectRating={handleFeedbackRating}
                    onNoteChange={handleFeedbackNote}
                    onSubmit={handleSubmitFeedback}
                    onDismiss={handleDismissFeedback}
                  />
                )}
              </div>
            </div>
          </div>

          {/* AI Chat sidebar */}
          <div className="animate-slide-in-right lg:sticky lg:top-6" style={{ animationDelay: '200ms' }}>
            <StudentAiChat
              key={activity?.id ?? 'none'}
              ref={chatRef}
              activity={activity}
              isUserReady={isUserReady}
              knowledgeLevel={currentKnowledgeLevel}
              onRequestKnowledgeLevel={handleRequestKnowledgeLevel}
              onAdjustKnowledgeLevel={handleAdjustKnowledgeLevel}
              topicOptions={topicOptions}
              currentTopicId={currentTopicId}
              onSelectTopic={handleTopicSelect}
              studentAnswer={studentAnswer}
            />
          </div>
        </div>

        {/* Pre-Chat Knowledge Level Modal */}
        {showKnowledgeModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-foreground/20 backdrop-blur-sm p-4 animate-fade-in">
            <div className="max-w-lg w-full card-editorial p-8 lg:p-10 space-y-7 animate-scale-in noise relative">
              {/* Decorative accent */}
              <div className="absolute top-0 inset-x-0 h-1 bg-gradient-to-r from-primary/0 via-primary to-primary/0" />

              <div>
                <div className="w-14 h-14 rounded-2xl bg-primary/10 flex items-center justify-center text-primary mb-5">
                  <svg className="w-7 h-7" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
                  </svg>
                </div>
                <h2 className="font-display text-2xl lg:text-3xl font-bold text-foreground tracking-tight">
                  Before we start...
                </h2>
                <p className="text-muted-foreground mt-2 leading-relaxed">
                  Help me personalize your learning experience!
                </p>
              </div>

              {/* Knowledge Level Selection */}
              <div className="space-y-4">
                <label className="block text-sm font-semibold text-foreground">
                  What's your knowledge level on this topic?
                </label>
                <div className="grid grid-cols-3 gap-3">
                  {[
                    { value: 'beginner', label: 'Beginner', desc: "I'm new to this", icon: '1' },
                    { value: 'intermediate', label: 'Intermediate', desc: 'Some experience', icon: '2' },
                    { value: 'advanced', label: 'Advanced', desc: 'Quite experienced', icon: '3' },
                  ].map((level) => (
                    <button
                      key={level.value}
                      type="button"
                      onClick={() => setTempKnowledgeLevel(level.value)}
                      className={`p-4 lg:p-5 rounded-2xl border-2 text-left transition-all duration-200 group ${
                        tempKnowledgeLevel === level.value
                          ? 'border-primary bg-primary/5 shadow-md shadow-primary/10'
                          : 'border-border hover:border-primary/30 hover:shadow-sm'
                      }`}
                    >
                      <div className={`w-7 h-7 rounded-lg flex items-center justify-center font-mono text-xs font-bold mb-2.5 transition-colors ${
                        tempKnowledgeLevel === level.value
                          ? 'bg-primary text-primary-foreground'
                          : 'bg-secondary text-muted-foreground group-hover:bg-primary/10 group-hover:text-primary'
                      }`}>
                        {level.icon}
                      </div>
                      <div className="font-semibold text-foreground text-sm">{level.label}</div>
                      <div className="text-xs text-muted-foreground mt-0.5">{level.desc}</div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Action Buttons */}
              <div className="flex gap-3 pt-3">
                <button
                  onClick={handleCancelKnowledge}
                  className="btn-secondary flex-1"
                >
                  Cancel
                </button>
                <button
                  onClick={handleConfirmKnowledge}
                  disabled={!tempKnowledgeLevel}
                  className="btn-primary flex-1"
                >
                  Start Guidance
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

