type StudentActivityFeedbackCardProps = {
  rating: number | null;
  note: string;
  saving: boolean;
  submitted: boolean;
  error: string | null;
  onSelectRating: (value: number) => void;
  onNoteChange: (value: string) => void;
  onSubmit: () => void;
  onDismiss: () => void;
};

const DIFFICULTY_LABELS = ['Very easy', 'Easy', 'Moderate', 'Hard', 'Very hard'];

export default function StudentActivityFeedbackCard({
  rating,
  note,
  saving,
  submitted,
  error,
  onSelectRating,
  onNoteChange,
  onSubmit,
  onDismiss,
}: StudentActivityFeedbackCardProps) {
  if (submitted) {
    return (
      <div className="rounded-2xl border border-sage-300/40 dark:border-sage-700/40 bg-sage-50/60 dark:bg-sage-950/30 p-5 animate-scale-in">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-xl bg-sage-200/60 dark:bg-sage-800/40 flex items-center justify-center flex-shrink-0">
            <svg className="w-4 h-4 text-sage-700 dark:text-sage-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 12.75l6 6 9-13.5" />
            </svg>
          </div>
          <p className="text-sm text-foreground font-medium">
            Thanks for the feedback. We use it to improve future activities.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="rounded-2xl border border-border bg-card p-6 shadow-sm animate-scale-in noise relative overflow-hidden">
      {/* Decorative accent */}
      <div className="absolute top-0 inset-x-0 h-0.5 bg-gradient-to-r from-primary/0 via-terracotta-300/60 to-primary/0" />

      <div className="space-y-1.5">
        <div className="flex items-center justify-between gap-3">
          <div>
            <h3 className="font-display text-lg font-bold text-foreground tracking-tight">Quick feedback</h3>
            <p className="text-sm text-muted-foreground">
              How did this activity feel after your first attempt?
            </p>
          </div>
          <button
            type="button"
            onClick={onDismiss}
            className="text-xs font-medium text-muted-foreground hover:text-foreground transition-colors px-2 py-1 rounded-lg hover:bg-secondary"
          >
            Maybe later
          </button>
        </div>
      </div>

      <div className="mt-5 space-y-5">
        {/* Rating section */}
        <div className="space-y-3">
          <div className="text-sm font-semibold text-foreground">Rate the difficulty</div>
          <div className="grid grid-cols-5 gap-2">
            {[1, 2, 3, 4, 5].map((value) => (
              <button
                key={value}
                type="button"
                onClick={() => onSelectRating(value)}
                className={`rounded-xl border-2 px-3 py-3.5 text-center transition-all duration-200 group ${
                  rating === value
                    ? 'border-primary bg-primary text-primary-foreground shadow-md shadow-primary/15'
                    : 'border-border bg-background text-foreground hover:border-primary/30 hover:bg-primary/5 hover:shadow-sm'
                }`}
                aria-pressed={rating === value}
              >
                <div className="font-mono text-sm font-bold">{value}</div>
                <div className={`text-[10px] mt-0.5 leading-tight ${
                  rating === value ? 'text-primary-foreground/80' : 'text-muted-foreground'
                }`}>
                  {DIFFICULTY_LABELS[value - 1]}
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Optional note */}
        <div className="space-y-2">
          <label className="block text-sm font-semibold text-foreground" htmlFor="activity-feedback-note">
            Optional note
          </label>
          <textarea
            id="activity-feedback-note"
            value={note}
            onChange={(event) => onNoteChange(event.target.value)}
            placeholder="What made this question easy or difficult?"
            className="input-field min-h-24 resize-y text-sm"
          />
        </div>

        {/* Error display */}
        {error && (
          <div className="rounded-xl border border-destructive/20 bg-destructive/10 px-4 py-3 text-sm text-destructive flex items-center gap-2">
            <svg className="w-4 h-4 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
            </svg>
            {error}
          </div>
        )}

        {/* Submit row */}
        <div className="flex items-center gap-3 pt-1">
          <button
            type="button"
            onClick={onSubmit}
            disabled={!rating || saving}
            className="btn-primary"
          >
            {saving ? 'Saving...' : 'Send feedback'}
          </button>
          <p className="text-xs text-muted-foreground">Your response stays internal and helps us tune the course.</p>
        </div>
      </div>
    </div>
  );
}

