import type { FormEvent } from 'react';
import { useOptimistic, useRef, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router';
import Nav from '../components/Nav';
import {
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
} from '../components/ui/breadcrumb';
import { PublishStatusButton } from '../components/PublishStatusButton';
import api from '../lib/api';
import type { Course, Lesson, Module, ModuleDetail } from '../lib/types';
import type { Route } from './+types/instructor.topic';
import { requireClientUser } from '~/lib/client-auth';

export async function clientLoader({ params }: Route.ClientLoaderArgs) {
  await requireClientUser('PROFESSOR');
  const moduleId = Number(params.moduleId);
  if (!Number.isFinite(moduleId)) {
    throw new Response('Invalid module id', { status: 400 });
  }

  const [module, lessons] = await Promise.all([
    api.moduleById(moduleId) as Promise<ModuleDetail>,
    api.lessonsForModule(moduleId) as Promise<Lesson[]>,
  ]);

  const course = (await api.courseById(module.courseOfferingId)) as Course;

  return { course, module, lessons };
}

export default function InstructorModuleLessons({ loaderData }: Route.ComponentProps) {
  const navigate = useNavigate();
  const { moduleId } = useParams();
  const numericModuleId = moduleId ? Number(moduleId) : null;
  const { course, module, lessons: initialLessons } = loaderData;
  const [lessons, setLessons] = useState<Lesson[]>(initialLessons);
  const [title, setTitle] = useState('');
  const [creating, setCreating] = useState(false);
  const [showImport, setShowImport] = useState(false);
  const [availableCourses, setAvailableCourses] = useState<Course[]>([]);
  const [selectedSourceCourseId, setSelectedSourceCourseId] = useState<number | null>(null);
  const [sourceModules, setSourceModules] = useState<Module[]>([]);
  const [selectedSourceModuleId, setSelectedSourceModuleId] = useState<number | null>(null);
  const [sourceLessons, setSourceLessons] = useState<Lesson[]>([]);
  const [loadingSourceCourses, setLoadingSourceCourses] = useState(false);
  const [loadingSourceModules, setLoadingSourceModules] = useState(false);
  const [loadingSourceLessons, setLoadingSourceLessons] = useState(false);
  const [selectedLessonIds, setSelectedLessonIds] = useState<Set<number>>(new Set());
  const [importing, setImporting] = useState(false);
  const [publishingId, setPublishingId] = useState<number | null>(null);
  const sourceModulesRequestIdRef = useRef(0);
  const sourceLessonsRequestIdRef = useRef(0);

  const [oLessons, addLessonOpt] = useOptimistic(
    lessons,
    (state, patch: (items: Lesson[]) => Lesson[]) => patch(state),
  );

  // Adjust state during render when loader data changes
  const [prevInitialLessons, setPrevInitialLessons] = useState(initialLessons);
  if (initialLessons !== prevInitialLessons) {
    setPrevInitialLessons(initialLessons);
    setLessons(initialLessons);
  }

  const refreshLessons = async () => {
    if (!numericModuleId) return;
    try {
      const lessonData = await api.lessonsForModule(numericModuleId);
      setLessons(lessonData);
    } catch (error) {
      console.error('Failed to refresh lessons', error);
    }
  };

  const ensureSourceCoursesLoaded = () => {
    if (availableCourses.length > 0) return;
    setLoadingSourceCourses(true);
    api
      .listCourses()
      .then((data: Course[]) => {
        const nextCourses = module?.courseOfferingId
          ? data.filter((course: Course) => course.id !== module.courseOfferingId)
          : data;
        setAvailableCourses(nextCourses);
      })
      .catch((error) => console.error('Failed to load courses', error))
      .finally(() => setLoadingSourceCourses(false));
  };

  const handleSourceCourseSelection = async (nextCourseId: number | null) => {
    const courseRequestId = ++sourceModulesRequestIdRef.current;
    ++sourceLessonsRequestIdRef.current;

    setSelectedSourceCourseId(nextCourseId);
    setSourceModules([]);
    setSelectedSourceModuleId(null);
    setSourceLessons([]);
    setSelectedLessonIds(new Set());

    if (nextCourseId == null) {
      setLoadingSourceModules(false);
      setLoadingSourceLessons(false);
      return;
    }

    setLoadingSourceModules(true);
    try {
      const modulesData = await api.modulesForCourse(nextCourseId);
      if (sourceModulesRequestIdRef.current === courseRequestId) {
        setSourceModules(modulesData);
      }
    } catch (error) {
      if (sourceModulesRequestIdRef.current === courseRequestId) {
        console.error('Failed to load modules for course', error);
        setSourceModules([]);
      }
    } finally {
      if (sourceModulesRequestIdRef.current === courseRequestId) {
        setLoadingSourceModules(false);
      }
    }
  };

  const handleSourceModuleSelection = async (nextModuleId: number | null) => {
    const lessonRequestId = ++sourceLessonsRequestIdRef.current;

    setSelectedSourceModuleId(nextModuleId);
    setSourceLessons([]);
    setSelectedLessonIds(new Set());

    if (nextModuleId == null) {
      setLoadingSourceLessons(false);
      return;
    }

    setLoadingSourceLessons(true);
    try {
      const lessonData = await api.lessonsForModule(nextModuleId);
      if (sourceLessonsRequestIdRef.current === lessonRequestId) {
        setSourceLessons(lessonData);
      }
    } catch (error) {
      if (sourceLessonsRequestIdRef.current === lessonRequestId) {
        console.error('Failed to load lessons for module', error);
        setSourceLessons([]);
      }
    } finally {
      if (sourceLessonsRequestIdRef.current === lessonRequestId) {
        setLoadingSourceLessons(false);
      }
    }
  };

  const onCreateLesson = async (event: FormEvent) => {
    event.preventDefault();
    if (!numericModuleId || !title.trim()) return;
    setCreating(true);
    try {
      await api.createLesson(numericModuleId, { title: title.trim() });
      setTitle('');
      refreshLessons();
    } catch (error) {
      console.error('Failed to create lesson', error);
    } finally {
      setCreating(false);
    }
  };

  const toggleLesson = (lessonId: number) => {
    setSelectedLessonIds((prev) => {
      const next = new Set(prev);
      if (next.has(lessonId)) next.delete(lessonId);
      else next.add(lessonId);
      return next;
    });
  };

  const onImportLessons = async () => {
    if (!module || !numericModuleId || selectedSourceModuleId == null || selectedLessonIds.size === 0)
      return;
    setImporting(true);
    try {
      await api.importIntoCourse(module.courseOfferingId, {
        lessonIds: Array.from(selectedLessonIds),
        targetModuleId: numericModuleId,
      });
      setShowImport(false);
      await handleSourceCourseSelection(null);
      refreshLessons();
    } catch (error) {
      console.error('Import lessons failed', error);
    } finally {
      setImporting(false);
    }
  };

  const togglePublish = async (lessonId: number, currentlyPublished: boolean) => {
    // Optimistic update via useOptimistic
    addLessonOpt((items) =>
      items.map((l) => (l.id === lessonId ? { ...l, isPublished: !currentlyPublished } : l)),
    );
    setPublishingId(lessonId);

    try {
      const updated = currentlyPublished
        ? await api.unpublishLesson(lessonId)
        : await api.publishLesson(lessonId);
      // Confirm with server response
      setLessons((prev) => prev.map((l) => (l.id === lessonId ? updated : l)));
    } catch (error) {
      console.error('Failed to toggle publish status', error);
      // Rollback on error to clear optimistic change
      setLessons((prev) =>
        prev.map((l) => (l.id === lessonId ? { ...l, isPublished: currentlyPublished } : l)),
      );
    } finally {
      setPublishingId((current) => (current === lessonId ? null : current));
    }
  };

  return (
    <div className="min-h-dvh bg-background relative">
      {/* Subtle atmosphere */}
      <div className="fixed inset-0 dots-pattern opacity-30 pointer-events-none" />
      <div className="fixed bottom-0 left-0 w-[500px] h-[500px] bg-accent/[0.03] rounded-full blur-3xl pointer-events-none translate-y-1/2 -translate-x-1/3" />

      <Nav />

      <div className="relative container mx-auto max-w-5xl px-4 py-10 space-y-8">
        {/* Breadcrumb */}
        <Breadcrumb className="animate-fade-down">
          <BreadcrumbList>
            <BreadcrumbItem>
              <BreadcrumbLink asChild>
                <Link to="/instructor" className="text-muted-foreground hover:text-primary transition-colors">
                  Teaching
                </Link>
              </BreadcrumbLink>
            </BreadcrumbItem>
            <BreadcrumbSeparator>/</BreadcrumbSeparator>
            <BreadcrumbItem>
              {course && module ? (
                <BreadcrumbLink asChild>
                  <Link
                    to={`/instructor/courses/${module.courseOfferingId}`}
                    className="text-muted-foreground hover:text-primary transition-colors"
                  >
                    {course.title}
                  </Link>
                </BreadcrumbLink>
              ) : (
                <BreadcrumbPage>Course</BreadcrumbPage>
              )}
            </BreadcrumbItem>
            <BreadcrumbSeparator>/</BreadcrumbSeparator>
            <BreadcrumbItem>
              <BreadcrumbPage className="font-medium text-foreground">
                {module?.title || 'Module'}
              </BreadcrumbPage>
            </BreadcrumbItem>
          </BreadcrumbList>
        </Breadcrumb>

        {/* Page header */}
        <div className="flex items-end justify-between gap-4 animate-fade-up">
          <div className="space-y-1">
            <h1 className="font-display text-3xl font-bold tracking-tight text-foreground">
              Lessons
            </h1>
            <p className="text-sm text-muted-foreground">
              {oLessons.length === 0
                ? 'Get started by adding your first lesson'
                : `${oLessons.length} lesson${oLessons.length !== 1 ? 's' : ''} in this module`}
            </p>
          </div>
          <button
            onClick={() => {
              if (!showImport) {
                ensureSourceCoursesLoaded();
              } else {
                void handleSourceCourseSelection(null);
              }
              setShowImport((prev) => !prev);
            }}
            className="btn-ghost text-sm"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
              {showImport ? (
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              ) : (
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
              )}
            </svg>
            {showImport ? 'Close' : 'Import Lessons'}
          </button>
        </div>

        {/* Import panel */}
        {showImport && (
          <div className="card-editorial p-6 space-y-5 animate-scale-in">
            <div className="flex items-center gap-3 mb-1">
              <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
                <svg className="w-4 h-4 text-primary" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" />
                </svg>
              </div>
              <div>
                <h3 className="font-display text-base font-semibold text-foreground">Import Lessons</h3>
                <p className="text-xs text-muted-foreground">Copy lessons and their activities from another course module.</p>
              </div>
            </div>

            {/* Step 1: Select course */}
            <div>
              <label className="block text-sm font-medium text-foreground mb-2">
                <span className="font-mono text-xs text-muted-foreground mr-2">01</span>
                Source course
              </label>
              <select
                value={selectedSourceCourseId ?? ''}
                onChange={(e) => {
                  const nextValue = e.target.value ? Number(e.target.value) : null;
                  void handleSourceCourseSelection(nextValue);
                }}
                className="input-field"
              >
                <option value="">Select course...</option>
                {availableCourses.map((course) => (
                  <option key={course.id} value={course.id}>
                    {course.title}
                  </option>
                ))}
              </select>
              {loadingSourceCourses && (
                <p className="mt-2 text-xs text-muted-foreground animate-pulse-soft">Loading courses...</p>
              )}
              {!loadingSourceCourses && availableCourses.length === 0 && (
                <p className="mt-2 text-xs text-muted-foreground">
                  No other courses available to copy from.
                </p>
              )}
            </div>

            {/* Step 2: Select module */}
            {selectedSourceCourseId != null && (
              <div className="animate-fade-up">
                <label className="block text-sm font-medium text-foreground mb-2">
                  <span className="font-mono text-xs text-muted-foreground mr-2">02</span>
                  Source module
                </label>
                <select
                  value={selectedSourceModuleId ?? ''}
                  onChange={(e) => {
                    const nextValue = e.target.value ? Number(e.target.value) : null;
                    void handleSourceModuleSelection(nextValue);
                  }}
                  className="input-field"
                >
                  <option value="">Select module...</option>
                  {sourceModules.map((sourceModule) => (
                    <option key={sourceModule.id} value={sourceModule.id}>
                      {sourceModule.title}
                    </option>
                  ))}
                </select>
                {loadingSourceModules && (
                  <p className="mt-2 text-xs text-muted-foreground animate-pulse-soft">Loading modules...</p>
                )}
                {!loadingSourceModules && sourceModules.length === 0 && (
                  <p className="mt-2 text-xs text-muted-foreground">Selected course has no modules yet.</p>
                )}
              </div>
            )}

            {/* Step 3: Select lessons */}
            {selectedSourceCourseId == null ? (
              <p className="text-sm text-muted-foreground italic">Select a course to begin.</p>
            ) : selectedSourceModuleId == null ? (
              <p className="text-sm text-muted-foreground italic">Select a module to preview lessons.</p>
            ) : loadingSourceLessons ? (
              <p className="text-sm text-muted-foreground animate-pulse-soft">Loading lessons...</p>
            ) : sourceLessons.length === 0 ? (
              <p className="text-sm text-muted-foreground">Selected module has no lessons yet.</p>
            ) : (
              <div className="space-y-4 animate-fade-up">
                <label className="block text-sm font-medium text-foreground">
                  <span className="font-mono text-xs text-muted-foreground mr-2">03</span>
                  Select lessons
                </label>

                <div className="rounded-xl border border-border overflow-hidden">
                  <div className="px-4 py-2.5 text-xs font-semibold tracking-wide uppercase text-muted-foreground bg-secondary/50 border-b border-border">
                    Available Lessons
                  </div>
                  <div className="p-2 space-y-1.5 bg-card/50">
                    {sourceLessons.map((lesson, idx) => {
                      const isSelected = selectedLessonIds.has(lesson.id);
                      return (
                        <label
                          key={lesson.id}
                          className={`flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-all duration-200 ${
                            isSelected
                              ? 'border-primary ring-1 ring-primary/20 bg-primary/5'
                              : 'border-transparent hover:border-border hover:bg-background/60'
                          }`}
                        >
                          <input
                            type="checkbox"
                            className="sr-only"
                            checked={isSelected}
                            onChange={() => toggleLesson(lesson.id)}
                          />
                          <span className={`flex-shrink-0 w-5 h-5 rounded border-2 flex items-center justify-center transition-all ${
                            isSelected
                              ? 'border-primary bg-primary text-primary-foreground'
                              : 'border-border'
                          }`}>
                            {isSelected && (
                              <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                              </svg>
                            )}
                          </span>
                          <span className="font-mono text-xs text-muted-foreground/60 tabular-nums">
                            {String(idx + 1).padStart(2, '0')}
                          </span>
                          <span className="text-sm text-foreground">{lesson.title}</span>
                        </label>
                      );
                    })}
                  </div>
                </div>

                <div className="flex items-center justify-between pt-2 border-t border-border">
                  <span className="text-xs text-muted-foreground">
                    {selectedLessonIds.size} of {sourceLessons.length} selected
                  </span>
                  <button
                    onClick={onImportLessons}
                    disabled={importing || selectedLessonIds.size === 0}
                    className="btn-primary text-sm"
                  >
                    {importing ? 'Importing...' : `Import selected lesson${selectedLessonIds.size !== 1 ? 's' : ''}`}
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {/* Create form */}
        <form onSubmit={onCreateLesson} className="flex gap-3 animate-fade-up" style={{ animationDelay: '100ms' }}>
          <input
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="New lesson title..."
            className="input-field flex-1"
          />
          <button
            disabled={creating || !title.trim()}
            className="btn-primary whitespace-nowrap"
          >
            {creating ? 'Adding...' : 'Add Lesson'}
          </button>
        </form>

        {/* Lesson list */}
        {oLessons.length === 0 ? (
          <div className="card-editorial p-12 text-center animate-fade-up" style={{ animationDelay: '150ms' }}>
            <div className="mx-auto w-12 h-12 rounded-2xl bg-accent/30 flex items-center justify-center mb-4">
              <svg className="w-6 h-6 text-accent-foreground/50" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m0 12.75h7.5m-7.5 3H12M10.5 2.25H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
              </svg>
            </div>
            <p className="text-muted-foreground font-medium">No lessons yet</p>
            <p className="text-sm text-muted-foreground/70 mt-1">Add your first lesson to begin structuring this module.</p>
          </div>
        ) : (
          <div className="space-y-3">
            {oLessons.map((lesson, idx) => {
              const canPublish = course?.isPublished && module?.isPublished;
              const blocked = !lesson.isPublished && !canPublish;
              const parentName = !course?.isPublished
                ? course?.title || 'the parent course'
                : !module?.isPublished
                ? module?.title || 'the parent module'
                : null;
              const tooltipMessage = blocked && parentName
                ? `${parentName} is unpublished, so you can't publish ${lesson.title}.`
                : null;
              const busy = publishingId === lesson.id;
              return (
                <div
                  key={lesson.id}
                  className="card-editorial group cursor-pointer transition-all duration-300 hover:shadow-lg hover:-translate-y-px animate-fade-up"
                  style={{ animationDelay: `${idx * 60}ms` }}
                  onClick={() => navigate(`/instructor/lesson/${lesson.id}`)}
                  role="button"
                  tabIndex={0}
                  onKeyDown={(event) => {
                    if (event.key === 'Enter' || event.key === ' ') {
                      event.preventDefault();
                      navigate(`/instructor/lesson/${lesson.id}`);
                    }
                  }}
                >
                  <div className="flex items-center gap-5 p-5">
                    {/* Editorial number */}
                    <span className="flex-shrink-0 font-mono text-lg tabular-nums text-accent-foreground/30 group-hover:text-primary transition-colors duration-300 w-8 text-right">
                      {String(idx + 1).padStart(2, '0')}
                    </span>

                    {/* Divider line */}
                    <div className="w-px h-10 bg-border group-hover:bg-primary/30 transition-colors duration-300" />

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <h3 className="font-display text-base font-semibold text-foreground group-hover:text-primary transition-colors duration-300 truncate">
                        {lesson.title}
                      </h3>
                    </div>

                    {/* Status + arrow */}
                    <div className="flex items-center gap-3 flex-shrink-0">
                      <div onClick={(e) => e.stopPropagation()} onKeyDown={(e) => e.stopPropagation()}>
                        <PublishStatusButton
                          isPublished={lesson.isPublished}
                          pending={busy}
                          blockedReason={tooltipMessage}
                          onClick={() => {
                            if (busy || blocked) return;
                            togglePublish(lesson.id, lesson.isPublished);
                          }}
                        />
                      </div>
                      <svg
                        className="w-4 h-4 text-muted-foreground/40 group-hover:text-primary group-hover:translate-x-0.5 transition-all duration-300"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                        strokeWidth={1.5}
                      >
                        <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
                      </svg>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

import type { FormEvent } from 'react';
import { useMemo, useState } from 'react';
import api from '../lib/api';
import { useCourseTopicsContext } from '../hooks/useCourseTopics';
interface AddActivityPanelProps {
  lessonId: number;
  onActivityCreated: () => void;
}

export default function AddActivityPanel({
  lessonId,
  onActivityCreated,
}: AddActivityPanelProps) {
  const { topics, loading: loadingTopics, error: topicsError } = useCourseTopicsContext();
  const [type, setType] = useState<'MCQ' | 'SHORT_TEXT'>('MCQ');
  const [question, setQuestion] = useState('');
  const [choices, setChoices] = useState<string[]>(['', '', '', '']);
  const [correct, setCorrect] = useState(0);
  const [hasSelectedCorrect, setHasSelectedCorrect] = useState(false);
  const [textAnswer, setTextAnswer] = useState('');
  const [hint, setHint] = useState('');
  const [busy, setBusy] = useState(false);

  const [selectedMainTopicId, setSelectedMainTopicId] = useState<number | ''>('');
  const [selectedSecondaryTopicIds, setSelectedSecondaryTopicIds] = useState<number[]>([]);
  const [topicSelectionError, setTopicSelectionError] = useState<string | null>(null);

  const [enableTeachMode, setEnableTeachMode] = useState(true);
  const [enableGuideMode, setEnableGuideMode] = useState(true);

  // Adjust main topic selection during render when topics change
  const [prevTopics, setPrevTopics] = useState(topics);
  if (topics !== prevTopics) {
    setPrevTopics(topics);

    if (topics.length === 0) {
      if (selectedMainTopicId !== '') setSelectedMainTopicId('');
      if (selectedSecondaryTopicIds.length > 0) setSelectedSecondaryTopicIds([]);
    } else {
      // If current selection is invalid, default to first topic
      if (selectedMainTopicId === '' || !topics.some((topic) => topic.id === selectedMainTopicId)) {
        setSelectedMainTopicId(topics[0].id);
      }
    }
  }

  const availableSecondaryTopics = useMemo(
    () =>
      topics.filter(
        (topic) => topic.id !== (typeof selectedMainTopicId === 'number' ? selectedMainTopicId : -1),
      ),
    [topics, selectedMainTopicId],
  );



  const toggleSecondaryForNew = (topicId: number) => {
    setSelectedSecondaryTopicIds((prev) => {
      if (prev.includes(topicId)) {
        return prev.filter((id) => id !== topicId);
      }
      return [...prev, topicId];
    });
  };

  const handleAddActivity = async (event: FormEvent) => {
    event.preventDefault();
    if (!question.trim()) return;
    if (selectedMainTopicId === '') {
      setTopicSelectionError('Select a main topic to continue.');
      return;
    }

    if (!enableTeachMode && !enableGuideMode) {
      alert('At least one AI mode must be enabled');
      return;
    }

    setBusy(true);
    setTopicSelectionError(null);

    const mainTopicId = Number(selectedMainTopicId);
    const secondaryIds = selectedSecondaryTopicIds.filter((id) => id !== mainTopicId);

    try {
      if (type === 'MCQ') {
        await api.createActivity(lessonId, {
          question: question.trim(),
          type,
          options: { choices },
          answer: { correctIndex: correct },
          hints: hint.trim() ? [hint.trim()] : [],
          mainTopicId,
          secondaryTopicIds: secondaryIds,
          enableTeachMode,
          enableGuideMode,
        });
      } else {
        await api.createActivity(lessonId, {
          question: question.trim(),
          type,
          answer: { text: textAnswer.trim() },
          hints: hint.trim() ? [hint.trim()] : [],
          mainTopicId,
          secondaryTopicIds: secondaryIds,
          enableTeachMode,
          enableGuideMode,
        });
      }

      setQuestion('');
      setChoices(['', '', '', '']);
      setCorrect(0);
      setHasSelectedCorrect(false);
      setTextAnswer('');
      setHint('');
      setSelectedSecondaryTopicIds([]);
      setEnableTeachMode(true);
      setEnableGuideMode(true);
      onActivityCreated();
    } catch (error) {
      console.error('Failed to add activity', error);
    } finally {
      setBusy(false);
    }
  };

  return (
    <form
      onSubmit={handleAddActivity}
      className="card-editorial overflow-hidden"
    >
      {/* Panel header */}
      <div className="px-5 py-4 border-b border-border/60 bg-primary/[0.04]">
        <div className="flex items-center gap-2">
          <svg className="w-4 h-4 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" /></svg>
          <h3 className="font-display text-base font-semibold text-foreground">New Activity</h3>
        </div>
      </div>

      <div className="p-5 space-y-5">
        {/* Type selector */}
        <div>
          <span className="text-xs font-semibold text-muted-foreground tracking-wide uppercase block mb-2">Type</span>
          <div className="flex gap-2">
            <label
              className={`px-4 py-2 rounded-xl cursor-pointer transition-all duration-200 text-sm font-medium ${
                type === 'MCQ'
                  ? 'bg-primary text-primary-foreground shadow-md shadow-primary/20'
                  : 'bg-secondary text-secondary-foreground hover:bg-muted border border-border'
              }`}
            >
              <input
                type="radio"
                name="type"
                className="sr-only"
                checked={type === 'MCQ'}
                onChange={() => setType('MCQ')}
              />
              Multiple Choice
            </label>
            <label
              className={`px-4 py-2 rounded-xl cursor-pointer transition-all duration-200 text-sm font-medium ${
                type === 'SHORT_TEXT'
                  ? 'bg-primary text-primary-foreground shadow-md shadow-primary/20'
                  : 'bg-secondary text-secondary-foreground hover:bg-muted border border-border'
              }`}
            >
              <input
                type="radio"
                name="type"
                className="sr-only"
                checked={type === 'SHORT_TEXT'}
                onChange={() => setType('SHORT_TEXT')}
              />
              Short Answer
            </label>
          </div>
        </div>

        {/* Question prompt */}
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
            Question prompt
          </label>
          <textarea
            value={question}
            onChange={(event) => setQuestion(event.target.value)}
            placeholder="Write the question learners should answer…"
            rows={4}
            className="input-field"
          />
        </div>

        {/* MCQ choices or short answer */}
        {type === 'MCQ' ? (
          <div className="space-y-3">
            <span className="text-xs font-semibold text-muted-foreground tracking-wide uppercase block">Choices</span>
            <div className="space-y-2">
              {choices.map((choice, index) => {
                const isSelected = correct === index && hasSelectedCorrect;
                return (
                  <label
                    key={index}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border cursor-pointer transition-all duration-200 focus-within:outline-none bg-card ${
                      isSelected
                        ? 'border-primary ring-2 ring-primary/20 bg-primary/5'
                        : 'border-border hover:border-primary/40'
                    }`}
                  >
                    <input
                      type="radio"
                      name="correct"
                      className="sr-only"
                      checked={correct === index}
                      onChange={() => {
                        setCorrect(index);
                        setHasSelectedCorrect(true);
                      }}
                    />
                    <span className={`flex-shrink-0 w-7 h-7 rounded-lg flex items-center justify-center text-xs font-bold font-mono ${
                      isSelected
                        ? 'bg-primary text-primary-foreground'
                        : 'bg-secondary text-muted-foreground'
                    }`}>
                      {String.fromCharCode(65 + index)}
                    </span>
                    <input
                      value={choice}
                      onChange={(event) =>
                        setChoices((prev) => {
                          const next = [...prev];
                          next[index] = event.target.value;
                          return next;
                        })
                      }
                      placeholder="Option text"
                      className="flex-1 min-w-0 border-none bg-transparent focus:outline-none text-foreground placeholder:text-muted-foreground"
                    />
                    {isSelected && (
                      <svg className="w-4 h-4 text-primary flex-shrink-0" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" /></svg>
                    )}
                  </label>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="space-y-1.5">
            <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
              Expected answer
            </label>
            <input
              value={textAnswer}
              onChange={(event) => setTextAnswer(event.target.value)}
              placeholder="Ideal short response…"
              className="input-field"
            />
          </div>
        )}

        {/* Topic selection */}
        <div className="rounded-xl border border-border bg-accent/5 overflow-hidden">
          <div className="px-4 py-2.5 border-b border-border/60 bg-accent/10">
            <div className="flex items-center gap-2">
              <svg className="w-3.5 h-3.5 text-accent-foreground" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M9.568 3H5.25A2.25 2.25 0 0 0 3 5.25v4.318c0 .597.237 1.17.659 1.591l9.581 9.581c.699.699 1.78.872 2.607.33a18.095 18.095 0 0 0 5.223-5.223c.542-.827.369-1.908-.33-2.607L11.16 3.66A2.25 2.25 0 0 0 9.568 3Z" /><path strokeLinecap="round" strokeLinejoin="round" d="M6 6h.008v.008H6V6Z" /></svg>
              <span className="text-xs font-semibold text-accent-foreground tracking-wide uppercase">Topic Classification</span>
            </div>
          </div>
          <div className="p-4 space-y-3">
            <div className="space-y-1.5">
              <label className="text-xs font-semibold text-muted-foreground">Main topic</label>
              <select
                value={selectedMainTopicId === '' ? '' : selectedMainTopicId}
                onChange={(event) => {
                  const newMainTopicId = event.target.value ? Number(event.target.value) : '';
                  setSelectedMainTopicId(newMainTopicId);
                  // Remove new main topic from secondary topics if it was selected there
                  if (typeof newMainTopicId === 'number') {
                    setSelectedSecondaryTopicIds((prev) => prev.filter((id) => id !== newMainTopicId));
                  }
                }}
                disabled={loadingTopics || topics.length === 0}
                className="input-field text-sm"
              >
                <option value="">Select a topic…</option>
                {topics.map((topic) => (
                  <option key={topic.id} value={topic.id}>
                    {topic.name}
                  </option>
                ))}
              </select>
              {topicSelectionError && (
                <p className="text-xs text-destructive">{topicSelectionError}</p>
              )}
            </div>

            <div className="space-y-1.5">
              <span className="text-xs font-semibold text-muted-foreground block">
                Secondary topics
                <span className="font-normal text-muted-foreground ml-1">(optional)</span>
              </span>
              <div className="flex flex-wrap gap-1.5">
                {availableSecondaryTopics.length === 0 ? (
                  <span className="text-xs text-muted-foreground">No other topics available.</span>
                ) : (
                  availableSecondaryTopics.map((topic) => {
                    const checked = selectedSecondaryTopicIds.includes(topic.id);
                    return (
                      <label
                        key={topic.id}
                        className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs cursor-pointer transition-all duration-200 ${
                          checked
                            ? 'tag-accent shadow-sm font-semibold'
                            : 'bg-secondary text-secondary-foreground hover:bg-muted border border-border'
                        }`}
                      >
                        <input
                          type="checkbox"
                          className="sr-only"
                          checked={checked}
                          onChange={() => toggleSecondaryForNew(topic.id)}
                        />
                        {checked && (
                          <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" /></svg>
                        )}
                        {topic.name}
                      </label>
                    );
                  })
                )}
              </div>
            </div>
          </div>
        </div>

        {/* AI modes */}
        <div className="rounded-xl border border-border bg-primary/[0.03] overflow-hidden">
          <div className="px-4 py-2.5 border-b border-border/60 bg-primary/[0.06]">
            <div className="flex items-center gap-2">
              <svg className="w-3.5 h-3.5 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M9.813 15.904 9 18.75l-.813-2.846a4.5 4.5 0 0 0-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 0 0 3.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 0 0 3.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 0 0-3.09 3.09ZM18.259 8.715 18 9.75l-.259-1.035a3.375 3.375 0 0 0-2.455-2.456L14.25 6l1.036-.259a3.375 3.375 0 0 0 2.455-2.456L18 2.25l.259 1.035a3.375 3.375 0 0 0 2.455 2.456L21.75 6l-1.036.259a3.375 3.375 0 0 0-2.455 2.456ZM16.894 20.567 16.5 21.75l-.394-1.183a2.25 2.25 0 0 0-1.423-1.423L13.5 18.75l1.183-.394a2.25 2.25 0 0 0 1.423-1.423l.394-1.183.394 1.183a2.25 2.25 0 0 0 1.423 1.423l1.183.394-1.183.394a2.25 2.25 0 0 0-1.423 1.423Z" /></svg>
              <span className="text-xs font-semibold text-primary tracking-wide uppercase">AI Study Buddy Modes</span>
            </div>
          </div>
          <div className="p-4 space-y-2">
            <p className="text-xs text-muted-foreground mb-2">
              Choose which AI assistance modes students can use for this activity.
            </p>
            <label className="flex items-center gap-2.5 cursor-pointer group">
              <input
                type="checkbox"
                checked={enableTeachMode}
                onChange={(e) => {
                  if (!e.target.checked && !enableGuideMode) {
                    alert('At least one AI mode must be enabled');
                    return;
                  }
                  setEnableTeachMode(e.target.checked);
                }}
                className="rounded border-primary/50 text-primary focus:ring-primary"
              />
              <div>
                <span className="text-sm font-medium text-foreground group-hover:text-primary transition-colors">Teach me</span>
                <span className="text-xs text-muted-foreground ml-2">Conceptual learning</span>
              </div>
            </label>
            <label className="flex items-center gap-2.5 cursor-pointer group">
              <input
                type="checkbox"
                checked={enableGuideMode}
                onChange={(e) => {
                  if (!e.target.checked && !enableTeachMode) {
                    alert('At least one AI mode must be enabled');
                    return;
                  }
                  setEnableGuideMode(e.target.checked);
                }}
                className="rounded border-primary/50 text-primary focus:ring-primary"
              />
              <div>
                <span className="text-sm font-medium text-foreground group-hover:text-primary transition-colors">Guide me</span>
                <span className="text-xs text-muted-foreground ml-2">Step-by-step guidance</span>
              </div>
            </label>
          </div>
        </div>

        {/* Hint */}
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
            Hint
            <span className="font-normal ml-1">(optional)</span>
          </label>
          <input
            value={hint}
            onChange={(event) => setHint(event.target.value)}
            placeholder="Give learners a nudge in the right direction…"
            className="input-field"
          />
        </div>

        {/* Submit */}
        <button
          type="submit"
          disabled={busy || !question.trim()}
          className="w-full btn-primary text-sm"
        >
          {busy ? 'Adding…' : 'Create Activity'}
        </button>

        {topicsError && <p className="text-xs text-destructive">{topicsError}</p>}
      </div>
    </form>
  );
}

import { useEffect, useMemo, useState } from 'react';
import Nav from '~/components/Nav';
import api from '~/lib/api';
import type { AdminEnrollmentData, AdminUser, Course, EduAiApiKeyStatus } from '~/lib/types';
import type { Route } from './+types/admin';
import { requireClientUser } from '~/lib/client-auth';
import { Tooltip, TooltipContent, TooltipTrigger } from '~/components/ui/tooltip';

type CostTier = 'LOW' | 'MEDIUM' | 'HIGH';

type AdminAiModelPolicy = {
  allowedTutorModelIds: string[];
  defaultTutorModelId: string | null;
  defaultSupervisorModelId: string | null;
  dualLoopEnabled: boolean;
  maxSupervisorIterations: number;
};

type AdminAiModelOption = {
  id: string;
  modelId: string;
  modelName: string;
  provider?: string | null;
  summary?: string | null;
  costTier?: CostTier | null;
};

type AdminLoaderData = {
  status: EduAiApiKeyStatus;
  users: AdminUser[];
  courses: Course[];
  aiPolicy: AdminAiModelPolicy | null;
  aiModels: AdminAiModelOption[];
  aiPolicyAvailable: boolean;
  aiPolicyError: string | null;
};

type AdminSettingsApi = {
  getAdminAiModelPolicy?: () => Promise<unknown>;
  setAdminAiModelPolicy?: (payload: AdminAiModelPolicy) => Promise<unknown>;
  listAiModels?: () => Promise<unknown>;
};

const DEFAULT_POLICY: AdminAiModelPolicy = {
  allowedTutorModelIds: [],
  defaultTutorModelId: null,
  defaultSupervisorModelId: null,
  dualLoopEnabled: true,
  maxSupervisorIterations: 3,
};

function getAdminSettingsApi(): AdminSettingsApi {
  return api as typeof api & AdminSettingsApi;
}

export async function clientLoader(_: Route.ClientLoaderArgs) {
  await requireClientUser('ADMIN');
  const settingsApi = getAdminSettingsApi();
  const aiPolicyAvailable =
    typeof settingsApi.getAdminAiModelPolicy === 'function' &&
    typeof settingsApi.setAdminAiModelPolicy === 'function';

  const [status, users, courses, aiModelsResult, aiPolicyResult] = await Promise.all([
    api.getEduAiApiKeyStatus(),
    api.listAdminUsers(),
    api.listAdminCourses(),
    loadAdminAiModels(settingsApi),
    loadAdminAiPolicy(settingsApi),
  ]);

  return {
    status,
    users,
    courses,
    aiModels: aiModelsResult.models,
    aiPolicy: aiPolicyResult.policy,
    aiPolicyError: aiPolicyResult.error,
    aiPolicyAvailable,
  } satisfies AdminLoaderData;
}

function formatTime(value: string | null) {
  if (!value) return null;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return date.toLocaleString();
}

export default function AdminHome({ loaderData }: Route.ComponentProps) {
  const settingsApi = getAdminSettingsApi();
  const [activeTab, setActiveTab] = useState<'users' | 'enrollments' | 'settings'>('users');
  const [status, setStatus] = useState<EduAiApiKeyStatus>(loaderData.status);
  const [users, setUsers] = useState<AdminUser[]>(loaderData.users);
  const [courses] = useState<Course[]>(loaderData.courses);
  const [aiPolicy, setAiPolicy] = useState<AdminAiModelPolicy>(
    normalizePolicy(loaderData.aiPolicy ?? DEFAULT_POLICY, loaderData.aiModels),
  );
  const [initialAiPolicy, setInitialAiPolicy] = useState<AdminAiModelPolicy>(
    normalizePolicy(loaderData.aiPolicy ?? DEFAULT_POLICY, loaderData.aiModels),
  );
  const [aiModels] = useState<AdminAiModelOption[]>(loaderData.aiModels);
  const [selectedCourseId, setSelectedCourseId] = useState<number | null>(
    loaderData.courses[0]?.id ?? null,
  );
  const [courseEnrollments, setCourseEnrollments] = useState<AdminEnrollmentData | null>(null);
  const [loadingEnrollments, setLoadingEnrollments] = useState(false);
  const [updatingEnrollmentUserId, setUpdatingEnrollmentUserId] = useState<string | null>(null);
  const [selectedStudentId, setSelectedStudentId] = useState<string | ''>('');
  const [apiKey, setApiKey] = useState('');
  const [showKey, setShowKey] = useState(false);
  const [saving, setSaving] = useState(false);
  const [clearing, setClearing] = useState(false);
  const [savingAiPolicy, setSavingAiPolicy] = useState(false);
  const [message, setMessage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(loaderData.aiPolicyError);

  const updatedLabel = useMemo(() => formatTime(status.updatedAt), [status.updatedAt]);
  const aiPolicyAvailable = loaderData.aiPolicyAvailable;
  const hasAllowedTutorModels = aiPolicy.allowedTutorModelIds.length > 0;
  const aiPolicyDirty = useMemo(() => {
    return JSON.stringify(initialAiPolicy) !== JSON.stringify(aiPolicy);
  }, [aiPolicy, initialAiPolicy]);

  const sourceTag = (() => {
    if (!status.configured) return { label: 'Not configured', className: 'tag' };
    if (status.source === 'ADMIN') return { label: 'Admin override', className: 'tag tag-primary' };
    if (status.source === 'ENV') return { label: 'From .env', className: 'tag tag-accent' };
    return { label: 'Configured', className: 'tag' };
  })();

  useEffect(() => {
    if (activeTab !== 'enrollments' || !selectedCourseId) {
      return;
    }

    let cancelled = false;
    setLoadingEnrollments(true);
    api
      .getAdminCourseEnrollments(selectedCourseId)
      .then((data) => {
        if (!cancelled) {
          setCourseEnrollments(data);
          setSelectedStudentId(data.availableStudents[0]?.id ?? '');
        }
      })
      .catch(() => {
        if (!cancelled) {
          setError('Could not load course enrollments.');
          setCourseEnrollments(null);
        }
      })
      .finally(() => {
        if (!cancelled) {
          setLoadingEnrollments(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [activeTab, selectedCourseId]);

  const refreshSelectedCourseEnrollments = async (courseId: number) => {
    setLoadingEnrollments(true);
    try {
      const data = await api.getAdminCourseEnrollments(courseId);
      setCourseEnrollments(data);
      setSelectedStudentId((current) => {
        if (typeof current === 'string' && data.availableStudents.some((student) => student.id === current)) {
          return current;
        }
        return data.availableStudents[0]?.id ?? '';
      });
    } catch {
      setError('Could not load course enrollments.');
      setCourseEnrollments(null);
    } finally {
      setLoadingEnrollments(false);
    }
  };

  const enrollStudent = async () => {
    if (!selectedCourseId || typeof selectedStudentId !== 'string' || !selectedStudentId) {
      return;
    }

    setUpdatingEnrollmentUserId(selectedStudentId);
    setError(null);
    setMessage(null);
    try {
      await api.enrollStudentInCourse(selectedCourseId, selectedStudentId);
      await refreshSelectedCourseEnrollments(selectedCourseId);
      setMessage('Student enrolled successfully.');
    } catch {
      setError('Could not enroll student. Please try again.');
    } finally {
      setUpdatingEnrollmentUserId(null);
    }
  };

  const removeEnrollment = async (userId: string) => {
    if (!selectedCourseId) {
      return;
    }

    setUpdatingEnrollmentUserId(userId);
    setError(null);
    setMessage(null);
    try {
      await api.removeStudentFromCourse(selectedCourseId, userId);
      await refreshSelectedCourseEnrollments(selectedCourseId);
      setMessage('Student removed from course.');
    } catch {
      setError('Could not remove enrollment. Please try again.');
    } finally {
      setUpdatingEnrollmentUserId(null);
    }
  };

  const save = async () => {
    setSaving(true);
    setError(null);
    setMessage(null);
    try {
      const next = await api.setEduAiApiKey(apiKey);
      setStatus(next);
      setApiKey('');
      setMessage('Saved. This overrides EDUAI_API_KEY from the environment.');
    } catch (e) {
      setError('Could not save key. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  const clear = async () => {
    setClearing(true);
    setError(null);
    setMessage(null);
    try {
      const next = await api.clearEduAiApiKey();
      setStatus(next);
      setMessage('Cleared admin override. The server will fall back to EDUAI_API_KEY from the environment.');
    } catch {
      setError('Could not clear override. Please try again.');
    } finally {
      setClearing(false);
    }
  };

  const toggleTutorModel = (modelId: string) => {
    setAiPolicy((current) => {
      const nextAllowed = current.allowedTutorModelIds.includes(modelId)
        ? current.allowedTutorModelIds.filter((id) => id !== modelId)
        : [...current.allowedTutorModelIds, modelId];

      const fallbackTutor =
        current.defaultTutorModelId && nextAllowed.includes(current.defaultTutorModelId)
          ? current.defaultTutorModelId
          : nextAllowed[0] ?? null;

      return {
        ...current,
        allowedTutorModelIds: nextAllowed,
        defaultTutorModelId: fallbackTutor,
      };
    });
  };

  const saveAiPolicy = async () => {
