                      <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M8.625 9.75a.375.375 0 11-.75 0 .375.375 0 01.75 0zm0 0H8.25m4.125 0a.375.375 0 11-.75 0 .375.375 0 01.75 0zm0 0H12m4.125 0a.375.375 0 11-.75 0 .375.375 0 01.75 0zm0 0h-.375m-13.5 3.01c0 1.6 1.123 2.994 2.707 3.227 1.087.16 2.185.283 3.293.369V21l4.184-4.183a1.14 1.14 0 01.778-.332 48.294 48.294 0 005.83-.498c1.585-.233 2.708-1.626 2.708-3.228V6.741c0-1.602-1.123-2.995-2.707-3.228A48.394 48.394 0 0012 3c-2.392 0-4.744.175-7.043.513C3.373 3.746 2.25 5.14 2.25 6.741v6.018z" />
                      </svg>
                    }
                    title="Tutor"
                    badge={<InfoBadge copy="The tutor is the student-facing assistant. It should be fast, clear, and Socratic rather than answer-revealing." />}
                    description="Students may override this model, but only within the tutor allowlist below."
                  />
                  <ExplainerCard
                    icon={
                      <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75L11.25 15 15 9.75m-3-7.036A11.959 11.959 0 013.598 6 11.99 11.99 0 003 9.749c0 5.592 3.824 10.29 9 11.623 5.176-1.332 9-6.03 9-11.622 0-1.31-.21-2.571-.598-3.751h-.152c-3.196 0-6.1-1.248-8.25-3.285z" />
                      </svg>
                    }
                    title="Supervisor"
                    badge={<InfoBadge copy="The supervisor is an internal reviewer. It sees hidden answer-aware context, rejects risky drafts, and proposes revisions or a safe fallback." />}
                    description="Keep this stable and safety-oriented. Students cannot change it."
                  />
                  <ExplainerCard
                    icon={
                      <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 18.75a60.07 60.07 0 0115.797 2.101c.727.198 1.453-.342 1.453-1.096V18.75M3.75 4.5v.75A.75.75 0 013 6h-.75m0 0v-.375c0-.621.504-1.125 1.125-1.125H20.25M2.25 6v9m18-10.5v.75c0 .414.336.75.75.75h.75m-1.5-1.5h.375c.621 0 1.125.504 1.125 1.125v9.75c0 .621-.504 1.125-1.125 1.125h-.375m1.5-1.5H21a.75.75 0 00-.75.75v.75m0 0H3.75m0 0h-.375a1.125 1.125 0 01-1.125-1.125V15m1.5 1.5v-.75A.75.75 0 003 15h-.75M15 10.5a3 3 0 11-6 0 3 3 0 016 0zm3 0h.008v.008H18V10.5zm-12 0h.008v.008H6V10.5z" />
                      </svg>
                    }
                    title="Cost guidance"
                    badge={<InfoBadge copy="Costs are qualitative here on purpose. Use these labels to weigh speed and quality without depending on fragile exact vendor pricing." />}
                    description="Low-cost models are best for routine hints. Higher-cost models are better when you want more careful supervision."
                  />
                </div>

                {!aiPolicyAvailable ? (
                  <div className="rounded-xl border border-dashed border-border px-5 py-5 text-sm text-muted-foreground">
                    AI model policy endpoints are not wired into the client API yet. This UI is ready for the
                    contract, but saving is temporarily disabled until the shared client layer lands.
                  </div>
                ) : null}

                <div className="grid gap-6 lg:grid-cols-[minmax(0,1.4fr)_minmax(320px,0.8fr)]">
                  {/* Allowed tutor models list */}
                  <div className="space-y-4 rounded-2xl border border-border/60 bg-card/60 p-5">
                    <div className="space-y-1">
                      <h3 className="font-semibold text-foreground">Allowed tutor models</h3>
                      <p className="text-sm text-muted-foreground">
                        Students can only choose from the models you allow here.
                      </p>
                    </div>

                    {aiModels.length === 0 ? (
                      <div className="rounded-xl border border-dashed border-border px-4 py-8 text-center text-sm text-muted-foreground">
                        No AI models are available yet.
                      </div>
                    ) : (
                      <div className="space-y-2">
                        {aiModels.map((model) => {
                          const isAllowed = aiPolicy.allowedTutorModelIds.includes(model.modelId);
                          const isTutorDefault = aiPolicy.defaultTutorModelId === model.modelId;
                          const isSupervisorDefault = aiPolicy.defaultSupervisorModelId === model.modelId;

                          return (
                            <label
                              key={model.id}
                              className={`group flex flex-col gap-3 rounded-xl border px-4 py-3.5 transition-all duration-200 cursor-pointer sm:flex-row sm:items-start sm:justify-between ${
                                isAllowed
                                  ? 'border-primary/30 bg-primary/[0.04] shadow-sm'
                                  : 'border-border/50 bg-background/40 hover:border-primary/20 hover:bg-muted/20'
                              }`}
                            >
                              <div className="flex gap-3">
                                <input
                                  type="checkbox"
                                  checked={isAllowed}
                                  onChange={() => toggleTutorModel(model.modelId)}
                                  className="mt-1 h-4 w-4 rounded border-border text-primary focus:ring-primary"
                                />
                                <div className="space-y-1.5">
                                  <div className="flex flex-wrap items-center gap-2">
                                    <span className="font-semibold text-foreground">{model.modelName}</span>
                                    <span className="tag">{model.provider ?? inferProvider(model.modelId)}</span>
                                    <span className={costTierClassName(model.costTier)}>
                                      {formatCostTier(model.costTier)}
                                    </span>
                                    {isTutorDefault ? <span className="tag tag-primary">Tutor default</span> : null}
                                    {isSupervisorDefault ? (
                                      <span className="tag tag-accent">Supervisor default</span>
                                    ) : null}
                                  </div>
                                  <p className="text-sm text-muted-foreground leading-relaxed">
                                    {model.summary ?? buildFallbackSummary(model)}
                                  </p>
                                  <p className="text-xs text-muted-foreground font-mono opacity-70">{model.modelId}</p>
                                </div>
                              </div>
                            </label>
                          );
                        })}
                      </div>
                    )}
                  </div>

                  {/* Loop defaults panel */}
                  <div className="space-y-4 rounded-2xl border border-border/60 bg-card/60 p-5">
                    <div className="space-y-1">
                      <h3 className="font-semibold text-foreground">Loop defaults</h3>
                      <p className="text-sm text-muted-foreground">
                        These defaults apply across teach, guide, and custom activity modes in this phase.
                      </p>
                    </div>

                    {/* Dual loop toggle */}
                    <div className="rounded-xl border border-border/50 bg-background/50 p-4 space-y-3">
                      <div className="flex items-center justify-between gap-4">
                        <div className="space-y-1">
                          <div className="flex items-center gap-2">
                            <span className="font-medium text-foreground text-sm">Enable dual loop</span>
                            <InfoBadge copy="When enabled, the tutor drafts a reply and the supervisor reviews it before the student sees it." />
                          </div>
                          <p className="text-xs text-muted-foreground">
                            Turning this off falls back to a single tutor pass.
                          </p>
                        </div>
                        <button
                          type="button"
                          onClick={() =>
                            setAiPolicy((current) => ({
                              ...current,
                              dualLoopEnabled: !current.dualLoopEnabled,
                            }))
                          }
                          className={`relative inline-flex h-7 w-14 shrink-0 items-center rounded-full transition-colors duration-200 ${
                            aiPolicy.dualLoopEnabled ? 'bg-primary' : 'bg-secondary'
                          }`}
                          aria-pressed={aiPolicy.dualLoopEnabled}
                        >
                          <span
                            className={`inline-block h-5 w-5 rounded-full bg-white shadow-sm transition-transform duration-200 ${
                              aiPolicy.dualLoopEnabled ? 'translate-x-7' : 'translate-x-1'
                            }`}
                          />
                        </button>
                      </div>
                    </div>

                    {/* Default tutor model */}
                    <div className="space-y-1.5">
                      <label className="block text-sm font-medium text-foreground">Default tutor model</label>
                      <select
                        value={aiPolicy.defaultTutorModelId ?? ''}
                        onChange={(e) =>
                          setAiPolicy((current) => ({
                            ...current,
                            defaultTutorModelId: e.target.value || null,
                          }))
                        }
                        className="input-field"
                        disabled={!hasAllowedTutorModels}
                      >
                        {!hasAllowedTutorModels ? (
                          <option value="">Choose allowed tutor models first</option>
                        ) : (
