                      </p>
                    </div>

                    {/* Pre-save guidance */}
                    <div className="rounded-xl border border-border/50 bg-background/50 p-4 text-sm text-muted-foreground space-y-1.5">
                      <p className="font-medium text-foreground text-xs uppercase tracking-wide">Before you save</p>
                      <p className="text-xs leading-relaxed">
                        Choose at least one tutor model, then set a tutor default and a supervisor default.
                        Tutor defaults shape the student experience. Supervisor defaults shape safety.
                      </p>
                    </div>

                    {/* Action buttons */}
                    <div className="flex flex-col sm:flex-row gap-2 pt-1">
                      <button
                        type="button"
                        onClick={saveAiPolicy}
                        disabled={
                          savingAiPolicy ||
                          !aiPolicyAvailable ||
                          !aiPolicyDirty ||
                          !hasAllowedTutorModels ||
                          !aiPolicy.defaultTutorModelId ||
                          !aiPolicy.defaultSupervisorModelId
                        }
                        className="btn-primary"
                      >
                        {savingAiPolicy ? 'Saving...' : 'Save loop settings'}
                      </button>
                      <button
                        type="button"
                        onClick={() => setAiPolicy(initialAiPolicy)}
                        disabled={savingAiPolicy || !aiPolicyDirty}
                        className="btn-secondary"
                      >
                        Reset changes
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </section>

            {/* EduAI API Key card */}
            <section className="card-editorial overflow-hidden">
              <div className="border-b border-border/60 px-6 py-5 sm:px-8 sm:py-6">
                <h2 className="font-display text-xl font-bold text-foreground">EduAI API Key</h2>
                <p className="mt-1 text-sm text-muted-foreground max-w-2xl">
                  {status.envConfigured ? (
                    <>
                      <span className="font-mono text-xs bg-muted/50 px-1.5 py-0.5 rounded">EDUAI_API_KEY</span> is already configured in your server environment
                      (for example via <span className="font-mono text-xs bg-muted/50 px-1.5 py-0.5 rounded">.env</span>). Saving a key here will override it.
                      Clear the override to fall back to the environment value.
                    </>
                  ) : (
                    <>
                      No <span className="font-mono text-xs bg-muted/50 px-1.5 py-0.5 rounded">EDUAI_API_KEY</span> is configured in your server environment (for
                      example via <span className="font-mono text-xs bg-muted/50 px-1.5 py-0.5 rounded">.env</span>). You can set one here.
                    </>
                  )}
                </p>
                {updatedLabel && status.hasAdminOverride && (
                  <p className="mt-2 text-xs text-muted-foreground">
                    Last updated: <span className="font-mono text-primary/80">{updatedLabel}</span>
                  </p>
                )}
              </div>

              <div className="px-6 py-6 sm:px-8 space-y-4">
                <div className="space-y-2">
                  <label className="block text-sm font-medium text-foreground">New key</label>
                  <div className="flex flex-col sm:flex-row gap-2">
                    <input
                      value={apiKey}
                      onChange={(e) => setApiKey(e.target.value)}
                      type={showKey ? 'text' : 'password'}
                      className="input-field flex-1"
                      placeholder="Paste EDUAI API key"
                      autoComplete="off"
                    />
                    <button
                      type="button"
                      onClick={() => setShowKey((v) => !v)}
                      className="btn-ghost border border-border text-sm"
                    >
                      {showKey ? 'Hide' : 'Show'}
                    </button>
                  </div>
                </div>

                <div className="flex flex-col sm:flex-row gap-2">
                  <button
                    type="button"
                    onClick={save}
                    disabled={saving || !apiKey.trim()}
                    className="btn-primary"
                  >
                    {saving ? 'Saving...' : 'Save key'}
                  </button>
                  <button
                    type="button"
                    onClick={clear}
                    disabled={clearing || !status.hasAdminOverride}
                    className="btn-secondary"
                    title={!status.hasAdminOverride ? 'No admin override to clear' : undefined}
                  >
                    {clearing ? 'Clearing...' : 'Clear override'}
                  </button>
                </div>
              </div>
            </section>
          </div>
        )}
      </div>
    </div>
  );
}

