function RoleTag({ role }: { role: string }) {
  const base = 'tag';
  if (role === 'ADMIN') return <span className={`${base} tag-primary`}>{role}</span>;
  if (role === 'PROFESSOR' || role === 'INSTRUCTOR') return <span className={`${base} tag-accent`}>{role}</span>;
  return <span className={base}>{role}</span>;
}

