/* ════════════════════════════════════════════════════════════
   Helper utilities (pure functions)
   ════════════════════════════════════════════════════════════ */

function normalizePolicy(raw: unknown, models: AdminAiModelOption[]): AdminAiModelPolicy {
  const fallbackTutor = models[0]?.modelId ?? null;
  const allowedTutorModelIds = Array.isArray((raw as { allowedTutorModelIds?: unknown })?.allowedTutorModelIds)
    ? (raw as { allowedTutorModelIds: unknown[] }).allowedTutorModelIds.filter(
        (value): value is string => typeof value === 'string',
      )
    : fallbackTutor
      ? [fallbackTutor]
      : [];

  const defaultTutorModelId =
    typeof (raw as { defaultTutorModelId?: unknown })?.defaultTutorModelId === 'string'
      ? (raw as { defaultTutorModelId: string }).defaultTutorModelId
      : allowedTutorModelIds[0] ?? null;

  return {
    allowedTutorModelIds,
    defaultTutorModelId:
      defaultTutorModelId && allowedTutorModelIds.includes(defaultTutorModelId)
        ? defaultTutorModelId
        : allowedTutorModelIds[0] ?? null,
    defaultSupervisorModelId:
      typeof (raw as { defaultSupervisorModelId?: unknown })?.defaultSupervisorModelId === 'string'
        ? (raw as { defaultSupervisorModelId: string }).defaultSupervisorModelId
        : models[0]?.modelId ?? null,
    dualLoopEnabled:
      typeof (raw as { dualLoopEnabled?: unknown })?.dualLoopEnabled === 'boolean'
        ? (raw as { dualLoopEnabled: boolean }).dualLoopEnabled
        : true,
    maxSupervisorIterations:
      typeof (raw as { maxSupervisorIterations?: unknown })?.maxSupervisorIterations === 'number'
        ? Math.max(1, Math.min(5, (raw as { maxSupervisorIterations: number }).maxSupervisorIterations))
        : DEFAULT_POLICY.maxSupervisorIterations,
  };
}

async function loadAdminAiPolicy(settingsApi: AdminSettingsApi) {
  if (typeof settingsApi.getAdminAiModelPolicy !== 'function') {
    return { policy: null, error: null };
  }

  try {
    const policy = await settingsApi.getAdminAiModelPolicy();
    return { policy: policy as AdminAiModelPolicy, error: null };
  } catch {
    return {
      policy: null,
      error: 'AI model settings could not be loaded. The rest of the admin tools are still available.',
    };
  }
}

async function loadAdminAiModels(settingsApi: AdminSettingsApi) {
  if (typeof settingsApi.listAiModels !== 'function') {
    return { models: [] as AdminAiModelOption[] };
  }

  try {
    const models = await settingsApi.listAiModels();
    const normalized = Array.isArray(models)
      ? models
          .map((model, index) => normalizeModelOption(model, index))
          .filter((model): model is AdminAiModelOption => model !== null)
      : [];

    return { models: normalized };
  } catch {
    return { models: [] as AdminAiModelOption[] };
  }
}

function normalizeModelOption(raw: unknown, index: number): AdminAiModelOption | null {
  if (!raw || typeof raw !== 'object') return null;

  const record = raw as Record<string, unknown>;
  const modelId =
    typeof record.modelId === 'string'
      ? record.modelId
      : typeof record.id === 'string'
        ? record.id
        : null;

  if (!modelId) {
    return null;
  }

  const provider =
    typeof record.provider === 'string' ? record.provider : inferProvider(modelId);
  const costTier =
    record.costTier === 'LOW' || record.costTier === 'MEDIUM' || record.costTier === 'HIGH'
      ? record.costTier
      : inferCostTier(modelId, String(record.modelName ?? modelId));

  return {
    id: typeof record.id === 'string' ? record.id : `${modelId}-${index}`,
    modelId,
    modelName:
      typeof record.modelName === 'string'
        ? record.modelName
        : typeof record.name === 'string'
          ? record.name
          : modelId,
    provider,
    summary: typeof record.summary === 'string' ? record.summary : null,
    costTier,
  };
}

function buildFallbackSummary(model: AdminAiModelOption) {
  const provider = model.provider ?? inferProvider(model.modelId);
  const costLabel = formatCostTier(model.costTier).toLowerCase();
  return `${model.modelName} is a ${provider} option suited for ${costLabel} usage with this admin policy.`;
}

function inferProvider(modelId: string) {
  const [provider] = modelId.split(':');
  return provider || 'provider';
}

function inferCostTier(modelId: string, modelName: string): CostTier {
  const haystack = `${modelId} ${modelName}`.toLowerCase();
  if (haystack.includes('flash') || haystack.includes('mini') || haystack.includes('nano')) return 'LOW';
  if (haystack.includes('pro') || haystack.includes('4.1') || haystack.includes('ultra')) return 'HIGH';
  return 'MEDIUM';
}

function formatCostTier(costTier: CostTier | null | undefined) {
  if (costTier === 'LOW') return 'Low cost';
  if (costTier === 'HIGH') return 'Higher cost';
  return 'Balanced cost';
}

function costTierClassName(costTier: CostTier | null | undefined) {
  if (costTier === 'LOW') return 'tag tag-accent';
  if (costTier === 'HIGH') return 'tag tag-primary';
  return 'tag';
}

function clampIterations(value: string) {
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) return DEFAULT_POLICY.maxSupervisorIterations;
  return Math.max(1, Math.min(5, Math.round(parsed)));
}

function InfoBadge({ copy }: { copy: string }) {
  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <button
          type="button"
          className="inline-flex h-5 w-5 items-center justify-center rounded-full border border-border text-[11px] font-bold text-muted-foreground transition-colors hover:border-primary/40 hover:text-foreground"
          aria-label="More information"
        >
          i
        </button>
      </TooltipTrigger>
      <TooltipContent side="top" className="max-w-[260px]">
        <p>{copy}</p>
      </TooltipContent>
    </Tooltip>
  );
}

import type { FormEvent } from 'react';
import { useMemo, useState } from 'react';
import type { Activity } from '../lib/types';
import {
  activityToFormValues,
  buildUpdatePayload,
  ensureChoiceSlots,
  type ActivityFormValues,
} from '../lib/activityForm';

type EditActivityPanelProps = {
  activity: Activity;
  busy?: boolean;
  error?: string | null;
  onSubmit: (payload: {
    title: string | null;
    instructionsMd: string;
    question: string;
    type: 'MCQ' | 'SHORT_TEXT';
    options: string[] | null;
    answer: any;
    hints: string[];
  }) => Promise<void> | void;
  onCancel: () => void;
};

export default function EditActivityPanel({ activity, busy, error, onSubmit, onCancel }: EditActivityPanelProps) {
  const [values, setValues] = useState<ActivityFormValues>(() => activityToFormValues(activity));
  const [formError, setFormError] = useState<string | null>(null);
  const [prevActivity, setPrevActivity] = useState(activity);

  if (prevActivity !== activity) {
    setPrevActivity(activity);
    setValues(activityToFormValues(activity));
    setFormError(null);
  }

  const paddedChoices = useMemo(() => ensureChoiceSlots(values.choices), [values.choices]);
  const choiceLabels = useMemo(
    () => paddedChoices.map((_, index) => String.fromCharCode(65 + index)),
    [paddedChoices],
  );

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const { payload, error: buildError } = buildUpdatePayload(values);
    if (buildError || !payload) {
      setFormError(buildError ?? 'Invalid activity data.');
      return;
    }
    setFormError(null);
    await onSubmit(payload);
  };

  return (
    <form
      onSubmit={handleSubmit}
      className="rounded-xl border border-primary/30 bg-primary/[0.04] overflow-hidden animate-scale-in"
    >
      {/* Edit panel header */}
      <div className="px-4 py-2.5 border-b border-primary/20 bg-primary/[0.06]">
        <div className="flex items-center gap-2">
          <svg className="w-3.5 h-3.5 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m16.862 4.487 1.687-1.688a1.875 1.875 0 1 1 2.652 2.652L10.582 16.07a4.5 4.5 0 0 1-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 0 1 1.13-1.897l8.932-8.931Zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0 1 15.75 21H5.25A2.25 2.25 0 0 1 3 18.75V8.25A2.25 2.25 0 0 1 5.25 6H10" /></svg>
          <span className="text-xs font-semibold text-primary tracking-wide uppercase">Edit Activity</span>
        </div>
      </div>

      <div className="p-4 space-y-4">
        {/* Internal title */}
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
            Internal title
            <span className="font-normal ml-1">(optional)</span>
          </label>
          <input
            value={values.title}
            onChange={(event) => setValues((prev) => ({ ...prev, title: event.target.value }))}
            placeholder="Optional internal label"
            className="input-field text-sm"
          />
        </div>

        {/* Question prompt */}
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
            Question prompt
          </label>
          <textarea
            value={values.question}
            onChange={(event) => setValues((prev) => ({ ...prev, question: event.target.value }))}
            rows={4}
            className="input-field text-sm"
          />
        </div>

        {/* Type selector */}
        <div>
          <span className="text-xs font-semibold text-muted-foreground tracking-wide uppercase block mb-2">Type</span>
          <div className="flex gap-2">
            <label
              className={`px-4 py-2 rounded-xl cursor-pointer transition-all duration-200 text-sm font-medium ${
                values.type === 'MCQ'
                  ? 'bg-primary text-primary-foreground shadow-md shadow-primary/20'
                  : 'bg-secondary text-secondary-foreground hover:bg-muted border border-border'
              }`}
            >
              <input
                type="radio"
                name="edit-type"
                className="sr-only"
                checked={values.type === 'MCQ'}
                onChange={() =>
                  setValues((prev) => ({
                    ...prev,
                    type: 'MCQ',
                    choices: ensureChoiceSlots(prev.choices),
                    correctIndex: 0,
                  }))
                }
              />
              Multiple Choice
            </label>
            <label
              className={`px-4 py-2 rounded-xl cursor-pointer transition-all duration-200 text-sm font-medium ${
                values.type === 'SHORT_TEXT'
                  ? 'bg-primary text-primary-foreground shadow-md shadow-primary/20'
                  : 'bg-secondary text-secondary-foreground hover:bg-muted border border-border'
              }`}
            >
              <input
                type="radio"
                name="edit-type"
                className="sr-only"
                checked={values.type === 'SHORT_TEXT'}
                onChange={() =>
                  setValues((prev) => ({
                    ...prev,
                    type: 'SHORT_TEXT',
                  }))
                }
              />
              Short Answer
            </label>
          </div>
        </div>

        {/* MCQ choices or short answer input */}
        {values.type === 'MCQ' ? (
          <div className="space-y-3">
            <span className="text-xs font-semibold text-muted-foreground tracking-wide uppercase block">Choices</span>
            <div className="space-y-2">
              {paddedChoices.map((choice, index) => {
                const isSelected = values.correctIndex === index;
                return (
                  <label
                    key={index}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border cursor-pointer transition-all duration-200 focus-within:outline-none bg-card ${
                      isSelected
                        ? 'border-primary ring-2 ring-primary/20 bg-primary/5'
                        : 'border-border hover:border-primary/40'
                    }`}
                  >
                    <input
                      type="radio"
                      name="correct-choice"
                      className="sr-only"
                      checked={isSelected}
                      onChange={() =>
                        setValues((prev) => ({
                          ...prev,
                          correctIndex: index,
                        }))
                      }
                    />
                    <span className={`flex-shrink-0 w-7 h-7 rounded-lg flex items-center justify-center text-xs font-bold font-mono ${
                      isSelected
                        ? 'bg-primary text-primary-foreground'
                        : 'bg-secondary text-muted-foreground'
                    }`}>
                      {choiceLabels[index] ?? String.fromCharCode(65 + index)}
                    </span>
                    <input
                      value={choice}
                      onChange={(event) =>
                        setValues((prev) => {
                          const nextChoices = ensureChoiceSlots(prev.choices);
                          nextChoices[index] = event.target.value;
                          return { ...prev, choices: nextChoices };
                        })
                      }
                      placeholder="Option text"
                      className="flex-1 min-w-0 border-none bg-transparent text-foreground focus:outline-none placeholder:text-muted-foreground"
                    />
                    {isSelected && (
                      <svg className="w-4 h-4 text-primary flex-shrink-0" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" /></svg>
                    )}
                    {paddedChoices.length > 2 && (
                      <button
                        type="button"
                        onClick={() =>
                          setValues((prev) => {
                            if (prev.choices.length <= 2) return prev;
                            const nextChoices = ensureChoiceSlots(prev.choices).filter(
                              (_, idx) => idx !== index,
                            );
                            let nextCorrect = prev.correctIndex;
                            if (index === prev.correctIndex) {
                              nextCorrect = Math.max(0, nextCorrect - 1);
                            } else if (index < prev.correctIndex) {
                              nextCorrect = Math.max(0, nextCorrect - 1);
                            }
                            nextCorrect = Math.min(nextCorrect, nextChoices.length - 1);
                            return {
                              ...prev,
                              choices: ensureChoiceSlots(nextChoices),
                              correctIndex: nextCorrect,
                            };
                          })
                        }
                        className="text-xs text-destructive hover:text-destructive/80 font-medium transition-colors"
                      >
                        Remove
                      </button>
                    )}
                  </label>
                );
              })}
            </div>
            <button
              type="button"
              onClick={() =>
                setValues((prev) => ({
                  ...prev,
                  choices: [...ensureChoiceSlots(prev.choices), ''],
                }))
              }
              className="btn-ghost text-xs text-primary hover:text-primary/80"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" /></svg>
              Add choice
            </button>
          </div>
        ) : (
          <div className="space-y-1.5">
            <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
              Expected answer
            </label>
            <input
              value={values.textAnswer}
              onChange={(event) => setValues((prev) => ({ ...prev, textAnswer: event.target.value }))}
              placeholder="Ideal short response"
              className="input-field text-sm"
            />
          </div>
        )}

        {/* Instructions */}
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
            Instructions
            <span className="font-normal ml-1">(optional)</span>
          </label>
          <textarea
            value={values.instructionsMd}
            onChange={(event) => setValues((prev) => ({ ...prev, instructionsMd: event.target.value }))}
            rows={3}
            className="input-field text-sm"
          />
        </div>

        {/* Hints */}
        <div className="space-y-1.5">
          <label className="text-xs font-semibold text-muted-foreground tracking-wide uppercase">
            Hints
            <span className="font-normal ml-1">(one per line)</span>
          </label>
          <textarea
            value={values.hintsText}
            onChange={(event) => setValues((prev) => ({ ...prev, hintsText: event.target.value }))}
            rows={3}
            className="input-field text-sm"
          />
        </div>

        {/* Errors */}
        {(formError || error) && (
          <div className="flex items-start gap-2 p-3 rounded-xl bg-destructive/10 border border-destructive/20">
            <svg className="w-4 h-4 text-destructive flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 1 1-18 0 9 9 0 0 1 18 0Zm-9 3.75h.008v.008H12v-.008Z" /></svg>
            <p className="text-xs text-destructive">{formError || error}</p>
          </div>
        )}

        {/* Actions */}
        <div className="flex justify-end gap-2 pt-1">
          <button
            type="button"
            className="btn-secondary text-sm"
            onClick={() => {
              setValues(activityToFormValues(activity));
              setFormError(null);
              onCancel();
            }}
            disabled={busy}
          >
            Cancel
          </button>
          <button
            type="submit"
            className="btn-primary text-sm"
            disabled={busy}
          >
            {busy ? 'Saving…' : 'Save changes'}
          </button>
        </div>
      </div>
    </form>
  );
}

