import { useEffect } from 'react';
import { useNavigate } from 'react-router';
import { useLocalUser } from '../hooks/useLocalUser';

function routeForRole(role: string) {
  if (role === 'STUDENT') return '/student';
  if (role === 'PROFESSOR') return '/instructor';
  if (role === 'ADMIN') return '/admin';
  return '/';
}

export default function UnsupportedRolePage() {
  const navigate = useNavigate();
  const { user, logout } = useLocalUser();

  useEffect(() => {
    if (!user) {
      navigate('/', { replace: true });
      return;
    }

    if (user.role !== 'TA') {
      navigate(routeForRole(user.role), { replace: true });
    }
  }, [navigate, user]);

  const handleLogout = async () => {
    await logout();
    navigate('/', { replace: true });
  };

  return (
    <main className="relative min-h-dvh overflow-hidden bg-background">
      {/* Background atmosphere */}
      <div className="absolute inset-0 noise" />
      <div className="absolute inset-0 dots-pattern opacity-40" />
      <div className="absolute top-1/3 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[400px] rounded-full bg-primary/[0.05] blur-[100px] pointer-events-none" />

      {/* Content */}
      <div className="relative z-10 flex min-h-dvh flex-col items-center justify-center px-6 py-16">

        {/* Logo mark */}
        <div className="animate-fade-down mb-10 flex items-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl border border-primary/20 bg-primary/5">
            <div className="flex flex-col items-center gap-[3px]">
              <div className="h-[3px] w-[18px] rounded-full bg-primary" />
              <div className="h-[3px] w-3 rounded-full bg-primary/60" />
              <div className="h-[3px] w-[7px] rounded-full bg-primary/30" />
            </div>
          </div>
          <span className="text-sm font-semibold tracking-[0.12em] uppercase text-muted-foreground">
            AI Tutor
          </span>
        </div>

        {/* Card */}
        <div className="animate-fade-up card-editorial w-full max-w-lg p-8 sm:p-10 text-center">

          {/* Warm illustration */}
          <div className="mx-auto mb-6 flex h-16 w-16 items-center justify-center rounded-2xl bg-accent/15">
            <svg
              className="h-8 w-8 text-accent-foreground"
              fill="none"
              viewBox="0 0 24 24"
              stroke="currentColor"
              strokeWidth={1.5}
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M18 18.72a9.094 9.094 0 003.741-.479 3 3 0 00-4.682-2.72m.94 3.198l.001.031c0 .225-.012.447-.037.666A11.944 11.944 0 0112 21c-2.17 0-4.207-.576-5.963-1.584A6.062 6.062 0 016 18.719m12 0a5.971 5.971 0 00-.941-3.197m0 0A5.995 5.995 0 0012 12.75a5.995 5.995 0 00-5.058 2.772m0 0a3 3 0 00-4.681 2.72 8.986 8.986 0 003.74.477m.94-3.197a5.971 5.971 0 00-.94 3.197M15 6.75a3 3 0 11-6 0 3 3 0 016 0zm6 3a2.25 2.25 0 11-4.5 0 2.25 2.25 0 014.5 0zm-13.5 0a2.25 2.25 0 11-4.5 0 2.25 2.25 0 014.5 0z"
              />
            </svg>
          </div>

          {/* Message */}
          <h1 className="mb-3 font-display text-2xl sm:text-3xl font-bold tracking-tight text-foreground">
            TA access is not available yet
          </h1>
          <p className="mb-3 text-base text-muted-foreground leading-relaxed max-w-sm mx-auto">
            Your EduAI account was authenticated successfully, but AI Tutor does not support TA
            access in this first release.
          </p>
          <p className="mb-8 text-sm text-muted-foreground leading-relaxed max-w-sm mx-auto">
            If you expected a different role, update it in EduAI and sign in again. Otherwise,
            please contact the EduAI team for access guidance.
          </p>

          {/* Divider */}
          <div className="mb-8 border-t border-border/60" />

          {/* Actions */}
          <div className="flex flex-col items-center gap-3 sm:flex-row sm:justify-center">
            <button type="button" onClick={handleLogout} className="btn-primary w-full sm:w-auto">
              <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 9V5.25A2.25 2.25 0 0013.5 3h-6a2.25 2.25 0 00-2.25 2.25v13.5A2.25 2.25 0 007.5 21h6a2.25 2.25 0 002.25-2.25V15m3 0l3-3m0 0l-3-3m3 3H9" />
              </svg>
              Sign out
            </button>
            <button
              type="button"
              onClick={() => navigate('/', { replace: true })}
              className="btn-ghost w-full sm:w-auto"
            >
              Back to home
            </button>
          </div>
        </div>

        {/* Subtle footer note */}
        <p className="animate-fade-up delay-300 mt-8 text-xs text-muted-foreground/60">
          Support for teaching assistants is on the roadmap.
        </p>
      </div>
    </main>
  );
}

