        onClick={() => setOpen((prev) => !prev)}
        aria-expanded={open}
        aria-controls={`activity-${activity.id}-details`}
        className="w-full px-4 py-2.5 flex items-center justify-between gap-3 text-sm font-semibold text-foreground hover:bg-secondary/50 focus:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 focus-visible:ring-offset-background transition-colors"
      >
        <div className="flex items-center gap-2">
          <svg className="w-3.5 h-3.5 text-muted-foreground" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 0 0-3.375-3.375h-1.5A1.125 1.125 0 0 1 13.5 7.125v-1.5a3.375 3.375 0 0 0-3.375-3.375H8.25m5.231 13.481L15 17.25m-4.5-15H5.625c-.621 0-1.125.504-1.125 1.125v16.5c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 0 0-9-9Zm3.75 11.625a2.625 2.625 0 1 1-5.25 0 2.625 2.625 0 0 1 5.25 0Z" /></svg>
          <span>Question details</span>
        </div>
        <svg
          className={`h-4 w-4 text-muted-foreground transition-transform duration-200 ${open ? 'rotate-180' : ''}`}
          viewBox="0 0 20 20"
          fill="currentColor"
          aria-hidden="true"
        >
          <path
            fillRule="evenodd"
            d="M5.23 7.21a.75.75 0 0 1 1.06.02L10 10.94l3.71-3.71a.75.75 0 1 1 1.06 1.06l-4.24 4.25a.75.75 0 0 1-1.06 0L5.21 8.29a.75.75 0 0 1 .02-1.08Z"
            clipRule="evenodd"
          />
        </svg>
      </button>
      {open && (
        <div
          id={`activity-${activity.id}-details`}
          className="px-4 pb-4 pt-1 space-y-4 text-sm text-foreground border-t border-border/60 animate-fade-up"
          style={{ animationDuration: '0.3s' }}
        >
          {activity.title && (
            <div>
              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">
                Internal title
              </div>
              <p className="whitespace-pre-wrap">{activity.title}</p>
            </div>
          )}

          {activity.instructionsMd && (
            <div>
              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">
                Instructions
              </div>
              <p className="whitespace-pre-wrap text-muted-foreground">{activity.instructionsMd}</p>
            </div>
          )}

          {details.choices.length > 0 && (
            <div>
              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-2">
                Choices
              </div>
              <ul className="space-y-1.5">
                {details.choices.map((choice, index) => {
                  const isCorrect = details.correctChoiceIndex === index;
                  return (
                    <li
                      key={index}
                      className={`flex items-start gap-2.5 px-3 py-2 rounded-lg transition-colors ${
                        isCorrect ? 'bg-accent/20 border border-accent/30' : 'bg-secondary/50'
                      }`}
                    >
                      <span className={`flex-shrink-0 w-6 h-6 rounded-md flex items-center justify-center text-xs font-bold font-mono ${
                        isCorrect
                          ? 'bg-accent text-accent-foreground'
                          : 'bg-muted text-muted-foreground'
                      }`}>
                        {String.fromCharCode(65 + index)}
                      </span>
                      <span className="flex-1 whitespace-pre-wrap">{choice}</span>
                      {isCorrect && (
                        <svg className="w-4 h-4 text-accent-foreground flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="m4.5 12.75 6 6 9-13.5" /></svg>
                      )}
                    </li>
                  );
                })}
              </ul>
            </div>
          )}

          {activity.type === 'MCQ' && details.correctChoiceIndex !== null && details.choices.length === 0 && (
            <div>
              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">
                Correct answer
              </div>
              <p className="whitespace-pre-wrap font-medium">
                {`${String.fromCharCode(65 + details.correctChoiceIndex)}. ${
                  details.choices[details.correctChoiceIndex] ?? 'Option not found'
                }`}
              </p>
            </div>
          )}

          {activity.type === 'SHORT_TEXT' && details.shortAnswerText && (
            <div>
              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">
                Expected answer
              </div>
              <p className="whitespace-pre-wrap px-3 py-2 rounded-lg bg-accent/10 border border-accent/20 font-medium">{details.shortAnswerText}</p>
            </div>
          )}

          {activity.hints.length > 0 && (
            <div>
              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-2">
                Hints
              </div>
              <ol className="space-y-1.5">
                {activity.hints.map((hint, index) => (
                  <li key={index} className="flex items-start gap-2.5 px-3 py-2 rounded-lg bg-primary/5 border border-primary/10">
                    <span className="flex-shrink-0 w-5 h-5 rounded-md bg-primary/10 text-primary flex items-center justify-center font-mono text-[0.65rem] font-bold">
                      {index + 1}
                    </span>
                    <span className="whitespace-pre-wrap text-muted-foreground">{hint}</span>
                  </li>
                ))}
              </ol>
            </div>
          )}

          {!details.hasContent && (
            <p className="text-xs text-muted-foreground py-2">No additional details captured yet.</p>
          )}
        </div>
      )}
    </div>
  );
}

export default memo(ActivityDetailsCard);

import type { FormEvent } from 'react';
import { useState } from 'react';
import { useCourseTopicsContext } from '../hooks/useCourseTopics';

type AddCourseTopicsButtonProps = {
  disabled?: boolean;
};

export default function AddCourseTopicsButton({ disabled = false }: AddCourseTopicsButtonProps) {
  const { createTopic } = useCourseTopicsContext();
  const [open, setOpen] = useState(false);
  const [name, setName] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [busy, setBusy] = useState(false);

  const toggle = () => {
    if (disabled || busy) return;
    setError(null);
    setOpen((current) => {
      if (current) {
        setName('');
      }
      return !current;
    });
  };

  const handleSubmit = async (event: FormEvent) => {
    event.preventDefault();
    const trimmed = name.trim();
    if (!trimmed) {
      setError('Topic name is required.');
      return;
    }

    setBusy(true);
    setError(null);
    try {
      await createTopic(trimmed);
      setName('');
      setOpen(false);
    } catch (err) {
      console.error('Failed to create topic', err);
      setError('Could not create topic. Try a different name.');
    } finally {
      setBusy(false);
    }
  };

  const buttonDisabled = disabled || busy;

  return (
    <div className="w-full space-y-3">
      <button
        type="button"
        onClick={toggle}
        disabled={buttonDisabled}
        className="w-full btn-primary text-sm"
      >
        {open ? (
          <>
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
            Cancel
          </>
        ) : (
          <>
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4.5v15m7.5-7.5h-15" /></svg>
            Add Topic
          </>
        )}
      </button>
      {open && (
        <form onSubmit={handleSubmit} className="space-y-2 animate-fade-up" style={{ animationDuration: '0.25s' }}>
          <input
            value={name}
            onChange={(event) => setName(event.target.value)}
            placeholder="New topic name…"
            className="input-field text-sm"
            autoFocus
          />
          {error && (
            <p className="text-xs text-destructive">{error}</p>
          )}
          <div className="flex justify-end">
            <button
              type="submit"
              disabled={busy || !name.trim()}
              className="btn-primary text-xs py-2"
            >
              {busy ? 'Adding…' : 'Save Topic'}
            </button>
          </div>
        </form>
      )}
    </div>
  );
}

