import { useMemo, useState } from 'react';
import type { Topic } from '~/lib/types';

type MissingTopic = { id: number; name: string };

type Mapping = { fromTopicId: number; toTopicId: string; };

export default function TopicSyncMappingDialog({
  open,
  onClose,
  topics,
  missing,
  onApply,
  busy = false,
}: {
  open: boolean;
  onClose: () => void;
  topics: Topic[];
  missing: MissingTopic[];
  onApply: (mappings: { fromTopicId: number; toTopicId: number }[]) => Promise<void>;
  busy?: boolean;
}) {
  const [submitting, setSubmitting] = useState(false);
  const [mappings, setMappings] = useState<Mapping[]>(() =>
    missing.map((m) => ({ fromTopicId: m.id, toTopicId: '' })),
  );

  // Reset mapping rows when missing list changes or dialog reopens
  const prevOpen = useMemo(() => open, [open]);
  if (prevOpen && mappings.length !== missing.length) {
    // Ensure we have one mapping per missing topic
    const byFrom = new Map(mappings.map((m) => [m.fromTopicId, m.toTopicId]));
    setMappings(missing.map((m) => ({ fromTopicId: m.id, toTopicId: byFrom.get(m.id) ?? '' })));
  }

  // Keep mappings in sync when missing changes
  const missingIds = useMemo(() => new Set(missing.map((m) => m.id)), [missing]);
  const mappingByFrom = useMemo(() => {
    const map = new Map<number, string>();
    for (const m of mappings) map.set(m.fromTopicId, m.toTopicId);
    return map;
  }, [mappings]);

  const options = useMemo(() => topics, [topics]);

  const allSelected = mappings.length > 0 && mappings.every((m) => m.toTopicId !== '');

  const handleChange = (fromTopicId: number, value: string) => {
    const toTopicId = value || '';
    setMappings((prev) =>
      prev.map((m) => (m.fromTopicId === fromTopicId ? { ...m, toTopicId } : m)),
    );
  };

  const onSubmit = async () => {
    if (!allSelected || submitting || busy) return;
    setSubmitting(true);
    try {
      const payload = mappings
        .filter((m) => m.toTopicId !== '')
        .map((m) => ({ fromTopicId: m.fromTopicId, toTopicId: Number(m.toTopicId) }));
      await onApply(payload);
      onClose();
    } finally {
      setSubmitting(false);
    }
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-foreground/40 backdrop-blur-sm animate-fade-in" style={{ animationDuration: '0.2s' }}>
      <div className="w-[min(720px,95vw)] card-editorial p-0 shadow-2xl animate-scale-in overflow-hidden">
        {/* Dialog header */}
        <div className="px-6 py-5 border-b border-border/60 bg-card">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center flex-shrink-0">
              <svg className="w-5 h-5 text-primary" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" d="M7.5 21 3 16.5m0 0L7.5 12M3 16.5h13.5m0-13.5L21 7.5m0 0L16.5 12M21 7.5H7.5" /></svg>
            </div>
            <div>
              <h2 className="font-display text-lg font-semibold text-foreground">Review topic changes</h2>
              <p className="text-sm text-muted-foreground mt-0.5">
                Some topics are no longer present in EduAI. Map them to existing topics so activities remain correctly tagged.
              </p>
            </div>
          </div>
        </div>

        {/* Mapping rows */}
        <div className="px-6 py-4 space-y-3 max-h-[50vh] overflow-y-auto">
          {missing.map((m) => (
            <div key={m.id} className="rounded-xl border border-border bg-secondary/30 p-4">
              <div className="text-sm mb-2.5">
                <span className="tag tag-primary mr-2">{m.name}</span>
                <span className="text-muted-foreground">no longer exists. Choose a replacement:</span>
              </div>
              <select
                className="input-field text-sm"
                value={mappingByFrom.get(m.id) ?? ''}
                onChange={(e) => handleChange(m.id, e.target.value)}
              >
                <option value="">Select replacement…</option>
                {options
                  .filter((t) => t.id !== m.id)
                  .map((t) => (
                    <option key={t.id} value={t.id}>
                      {t.name}
                    </option>
                  ))}
              </select>
            </div>
          ))}
        </div>

        {/* Dialog footer */}
        <div className="px-6 py-4 border-t border-border/60 bg-card flex justify-end gap-2">
          <button
            type="button"
            onClick={onClose}
            className="btn-secondary text-sm"
            disabled={submitting || busy}
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={onSubmit}
            disabled={!allSelected || submitting || busy}
            className="btn-primary text-sm"
          >
            {submitting ? 'Applying…' : 'Apply mappings'}
          </button>
        </div>
      </div>
    </div>
  );
}

